import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthProvider';
import api from '../../lib/api';
import BIHeader from './BIHeader';
import BITabBar from './BITabBar';
import OverviewTab from './tabs/OverviewTab';
import DeliveriesTab from './tabs/DeliveriesTab';
import SuppliesTab from './tabs/SuppliesTab';
import EquipmentTab from './tabs/EquipmentTab';
import StockTab from './tabs/StockTab';
import OperationalTab from './tabs/OperationalTab';

const TABS = [
  { label: 'Visão Geral', component: OverviewTab },
  { label: 'Entregas', component: DeliveriesTab },
  { label: 'Insumos', component: SuppliesTab },
  { label: 'Equipamentos', component: EquipmentTab },
  { label: 'Estoque', component: StockTab },
  { label: 'Operacional', component: OperationalTab },
];

export default function BIDashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const activeContract = user?.activeContract;
  const contractId = typeof activeContract === 'string'
    ? activeContract
    : activeContract?.contract_id || activeContract?.id;

  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState(0);
  const [dateFilter, setDateFilter] = useState({ start: null, end: null });

  const fetchDashboard = useCallback(async () => {
    if (!contractId) return;
    setLoading(true);
    setError(null);
    try {
      const params = { contract_id: contractId };
      if (dateFilter.start) params.start_date = dateFilter.start;
      if (dateFilter.end) params.end_date = dateFilter.end;
      const res = await api.get('/bi/dashboard', { params });
      setData(res.data);
    } catch (err) {
      setError(err?.response?.data?.detail || 'Erro ao carregar dashboard');
    } finally {
      setLoading(false);
    }
  }, [contractId, dateFilter]);

  useEffect(() => {
    fetchDashboard();
  }, [fetchDashboard]);

  const handleClose = () => navigate('/equipment');

  // Full-page loading (first load)
  if (loading && !data) {
    return (
      <div className="fixed inset-0 z-50 bg-slate-50 dark:bg-slate-950 flex items-center justify-center">
        <div className="flex flex-col items-center gap-4 text-slate-400">
          <div className="w-10 h-10 border-4 border-slate-200 dark:border-slate-700 border-t-primary rounded-full animate-spin" />
          <p className="text-sm font-bold uppercase tracking-widest">Carregando BI Dashboard...</p>
        </div>
      </div>
    );
  }

  // Full-page error (no data at all)
  if (error && !data) {
    return (
      <div className="fixed inset-0 z-50 bg-slate-50 dark:bg-slate-950 flex items-center justify-center">
        <div className="flex flex-col items-center gap-4 text-center max-w-sm">
          <div className="w-14 h-14 rounded-2xl bg-red-100 dark:bg-red-900/30 flex items-center justify-center">
            <span className="text-2xl">⚠️</span>
          </div>
          <p className="text-slate-700 dark:text-slate-300 font-medium">{error}</p>
          <button
            onClick={fetchDashboard}
            className="px-6 py-2 rounded-xl text-sm font-bold text-white"
            style={{ backgroundColor: 'rgb(var(--color-primary))' }}
          >
            Tentar novamente
          </button>
          <button onClick={handleClose} className="text-sm text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
            Voltar
          </button>
        </div>
      </div>
    );
  }

  const ActiveTabComponent = TABS[activeTab]?.component;

  return (
    <div className="fixed inset-0 z-50 bg-slate-50 dark:bg-slate-950 flex flex-col overflow-hidden">
      <BIHeader
        contractId={contractId}
        dateFilter={dateFilter}
        onFilterChange={setDateFilter}
        onClose={handleClose}
      />
      <BITabBar activeTab={activeTab} onTabChange={setActiveTab} />

      <div className="flex-1 overflow-auto custom-scrollbar p-4 md:p-6">
        {loading && data && (
          <div className="flex items-center gap-2 mb-4 px-1 text-xs text-slate-400">
            <div className="w-3 h-3 border-2 border-slate-300 border-t-primary rounded-full animate-spin" />
            Atualizando dados...
          </div>
        )}
        {ActiveTabComponent && data && (
          <ActiveTabComponent data={data} contractId={contractId} />
        )}
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { X, Calendar } from 'lucide-react';

const PRESETS = [
  { label: 'Últimos 30 dias', days: 30 },
  { label: 'Últimos 90 dias', days: 90 },
  { label: 'Este ano', year: true },
  { label: 'Tudo', all: true },
];

function toISODate(d) {
  return d.toISOString().split('T')[0];
}

export default function BIHeader({ contractId, dateFilter, onFilterChange, onClose }) {
  const [localStart, setLocalStart] = useState(dateFilter.start || '');
  const [localEnd, setLocalEnd] = useState(dateFilter.end || '');
  const [dateError, setDateError] = useState('');

  const applyFilter = (start, end) => {
    if (start && end && start > end) {
      setDateError('A data inicial não pode ser posterior à data final.');
      return;
    }
    setDateError('');
    onFilterChange({ start: start || null, end: end || null });
  };

  const handleStartChange = (val) => {
    setLocalStart(val);
    setDateError('');
  };

  const handleEndChange = (val) => {
    setLocalEnd(val);
    setDateError('');
  };

  const handleApply = () => applyFilter(localStart, localEnd);

  const handlePreset = (preset) => {
    if (preset.all) {
      setLocalStart('');
      setLocalEnd('');
      setDateError('');
      onFilterChange({ start: null, end: null });
      return;
    }
    const end = new Date();
    let start;
    if (preset.year) {
      start = new Date(end.getFullYear(), 0, 1);
    } else {
      start = new Date();
      start.setDate(start.getDate() - preset.days);
    }
    const s = toISODate(start);
    const e = toISODate(end);
    setLocalStart(s);
    setLocalEnd(e);
    setDateError('');
    onFilterChange({ start: s, end: e });
  };

  return (
    <header className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 md:px-6 py-3 flex flex-col gap-2 shrink-0 shadow-sm">
      <div className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="p-2 rounded-xl bg-primary/10">
            <Calendar className="w-4 h-4 text-primary" />
          </div>
          <div>
            <h1 className="text-base font-bold text-slate-800 dark:text-white leading-none">BI Dashboard</h1>
            {contractId && (
              <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest mt-0.5">
                Contrato: {contractId}
              </p>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2 flex-wrap">
          {/* Preset buttons */}
          {PRESETS.map((p) => (
            <button
              key={p.label}
              onClick={() => handlePreset(p)}
              className="px-3 py-1.5 rounded-lg text-[11px] font-bold bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700 transition-all"
            >
              {p.label}
            </button>
          ))}

          {/* Date inputs */}
          <div className="flex items-center gap-1.5">
            <input
              type="date"
              value={localStart}
              onChange={(e) => handleStartChange(e.target.value)}
              className="px-2 py-1.5 rounded-lg text-xs bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 focus:ring-2 focus:ring-primary/20 outline-none"
            />
            <span className="text-slate-400 text-xs">→</span>
            <input
              type="date"
              value={localEnd}
              onChange={(e) => handleEndChange(e.target.value)}
              className="px-2 py-1.5 rounded-lg text-xs bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 focus:ring-2 focus:ring-primary/20 outline-none"
            />
            <button
              onClick={handleApply}
              className="px-3 py-1.5 rounded-lg text-[11px] font-bold text-white transition-all"
              style={{ backgroundColor: 'rgb(var(--color-primary))' }}
            >
              Aplicar
            </button>
          </div>

          <button
            onClick={onClose}
            className="p-2 rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all"
            title="Fechar"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      </div>

      {dateError && (
        <p className="text-xs text-red-500 font-medium px-1">{dateError}</p>
      )}
    </header>
  );
}

import React from 'react';
import { cn } from '../../lib/utils';

const TABS = [
  'Visão Geral',
  'Entregas',
  'Insumos',
  'Equipamentos',
  'Estoque',
  'Operacional',
];

export default function BITabBar({ activeTab, onTabChange }) {
  return (
    <nav className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 md:px-6 shrink-0">
      <div className="flex gap-0 overflow-x-auto custom-scrollbar">
        {TABS.map((tab, i) => (
          <button
            key={tab}
            onClick={() => onTabChange(i)}
            className={cn(
              'px-4 py-3 text-xs font-bold uppercase tracking-widest whitespace-nowrap border-b-2 transition-all',
              activeTab === i
                ? 'border-primary text-primary'
                : 'border-transparent text-slate-400 dark:text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 hover:border-slate-300 dark:hover:border-slate-600'
