}

import React, { useState } from 'react';
import {
  BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from 'recharts';
import KPICard from '../widgets/KPICard';
import ChartCard from '../widgets/ChartCard';

const COLORS = ['rgb(var(--color-primary))', '#22c55e', '#f59e0b', '#ef4444', '#06b6d4', '#a855f7'];

export default function DeliveriesTab({ data }) {
  const delivery = data?.delivery || {};
  const [timeView, setTimeView] = useState('month');

  const timeData = (timeView === 'month' ? delivery.by_month : delivery.by_week) || [];
  const chartData = timeData.map(d => ({ name: d.period, value: d.count }));

  const pvd = delivery.pending_vs_delivered || {};
  const pvdData = [
    { name: 'Entregues', value: pvd.delivered || 0 },
    { name: 'Pendentes', value: pvd.pending || 0 },
    { name: 'Cancelados', value: pvd.cancelled || 0 },
  ].filter(d => d.value > 0);

  const toBarData = (arr) => (arr || []).map(d => ({ name: d.name, value: d.value }));

  return (
    <div className="space-y-6">
      {/* KPIs */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <KPICard label="Total Entregas" value={delivery.total_entregas ?? 0} />
        <KPICard label="Taxa Cancelamento" value={`${delivery.cancellation_rate ?? 0}%`} />
        <KPICard label="Média Dias Entrega" value={delivery.avg_delivery_days ?? 0} />
        <KPICard label="Pendentes" value={delivery.pending_count ?? 0} />
      </div>

      {/* Volume toggle */}
      <ChartCard
        title={
          <div className="flex items-center gap-3">
            <span>Volume por {timeView === 'month' ? 'Mês' : 'Semana'}</span>
            <div className="flex gap-1">
              {['month', 'week'].map(v => (
                <button
                  key={v}
                  onClick={() => setTimeView(v)}
                  className={`px-2 py-0.5 rounded text-[10px] font-bold transition-all ${timeView === v ? 'text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-500'}`}
                  style={timeView === v ? { backgroundColor: 'rgb(var(--color-primary))' } : {}}
                >
                  {v === 'month' ? 'Mês' : 'Semana'}
                </button>
              ))}
            </div>
          </div>
        }
      >
        <ResponsiveContainer width="100%" height={280}>
          <BarChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
            <XAxis dataKey="name" tick={{ fontSize: 10 }} />
            <YAxis tick={{ fontSize: 10 }} />
            <Tooltip />
            <Bar dataKey="value" fill="rgb(var(--color-primary))" name="Entregas" radius={[4, 4, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </ChartCard>

      {/* Row: channel + pending vs delivered */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <ChartCard title="Por Canal de Solicitação">
          <ResponsiveContainer width="100%" height={280}>
            <PieChart>
              <Pie data={toBarData(delivery.by_channel)} cx="50%" cy="50%" outerRadius={100} dataKey="value" nameKey="name" label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`} labelLine={false}>
                {(delivery.by_channel || []).map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="Pendentes vs Entregues vs Cancelados">
          <ResponsiveContainer width="100%" height={280}>
            <PieChart>
              <Pie data={pvdData} cx="50%" cy="50%" outerRadius={100} dataKey="value" nameKey="name" label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`} labelLine={false}>
                {pvdData.map((_, i) => <Cell key={i} fill={['#22c55e', '#f59e0b', '#ef4444'][i]} />)}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      {/* By city */}
      <ChartCard title="Por Cidade">
        <ResponsiveContainer width="100%" height={280}>
          <BarChart data={toBarData(delivery.by_city)} layout="vertical">
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
            <XAxis type="number" tick={{ fontSize: 10 }} />
            <YAxis type="category" dataKey="name" tick={{ fontSize: 10 }} width={120} />
            <Tooltip />
            <Bar dataKey="value" fill="#22c55e" name="Entregas" radius={[0, 4, 4, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </ChartCard>

      {/* Grid of breakdowns */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {[
          { key: 'by_empresa', title: 'Por Empresa (Top 10)' },
          { key: 'by_model', title: 'Por Modelo (Top 10)' },
          { key: 'by_solicitante', title: 'Por Solicitante (Top 10)' },
          { key: 'by_area', title: 'Por Área (Top 10)' },
          { key: 'by_competencia', title: 'Por Competência' },
          { key: 'by_contrato', title: 'Por Contrato' },
        ].map(({ key, title }) => {
          const d = toBarData(delivery[key]);
          if (!d.length) return null;
          return (
            <ChartCard key={key} title={title}>
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={d}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
                  <XAxis dataKey="name" tick={{ fontSize: 9 }} angle={-30} textAnchor="end" height={50} />
                  <YAxis tick={{ fontSize: 10 }} />
                  <Tooltip />
                  <Bar dataKey="value" fill="rgb(var(--color-primary))" name="Entregas" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </ChartCard>
          );
        })}
      </div>
    </div>
  );
}

import React from 'react';
import {
  BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from 'recharts';
import ChartCard from '../widgets/ChartCard';
import DataTable from '../widgets/DataTable';

const COLORS = ['rgb(var(--color-primary))', '#22c55e', '#f59e0b', '#ef4444', '#06b6d4', '#a855f7'];
const TONER_COLORS = { bk: '#334155', cy: '#06b6d4', mg: '#ec4899', yw: '#eab308' };

export default function EquipmentTab({ data }) {
  const equipment = data?.equipment || {};

  const statusData = (equipment.status_distribution || []).map(d => ({ name: d.name, value: d.value }));
  const modelData = (equipment.model_distribution || []).map(d => ({ name: d.name, value: d.value }));

  const cvmData = [
    { name: 'Colorido', value: equipment.color_vs_mono?.color || 0 },
    { name: 'Mono', value: equipment.color_vs_mono?.mono || 0 },
  ].filter(d => d.value > 0);

  // Toner distribution grouped bar
  const tonerDist = equipment.toner_level_distribution || {};
  const ranges = ['0-20', '21-50', '51-80', '81-100'];
  const tonerBarData = ranges.map(range => {
    const entry = { range };
    ['bk', 'cy', 'mg', 'yw'].forEach(color => {
      const bucket = (tonerDist[color] || []).find(b => b.range === range);
      entry[color.toUpperCase()] = bucket?.count || 0;
    });
    return entry;
  });

  return (
    <div className="space-y-6">
      {/* Fleet health + color vs mono */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <ChartCard title="Status da Frota">
          <ResponsiveContainer width="100%" height={280}>
            <PieChart>
              <Pie data={statusData} cx="50%" cy="50%" innerRadius={50} outerRadius={90} dataKey="value" nameKey="name" label={({ name, percent }) => `${(percent * 100).toFixed(0)}%`} labelLine={false}>
                {statusData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
              </Pie>
              <Tooltip />
              <Legend />
            </PieChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="Colorido vs Mono">
          <ResponsiveContainer width="100%" height={280}>
            <PieChart>
              <Pie data={cvmData} cx="50%" cy="50%" outerRadius={90} dataKey="value" nameKey="name" label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`} labelLine={false}>
                <Cell fill="rgb(var(--color-primary))" />
                <Cell fill="#94a3b8" />
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="Distribuição por Modelo (Top 10)">
          <ResponsiveContainer width="100%" height={280}>
            <BarChart data={modelData} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis type="number" tick={{ fontSize: 10 }} />
              <YAxis type="category" dataKey="name" tick={{ fontSize: 9 }} width={100} />
              <Tooltip />
              <Bar dataKey="value" fill="rgb(var(--color-primary))" radius={[0, 4, 4, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      {/* Toner level distribution */}
      <ChartCard title="Distribuição de Nível de Toner por Faixa">
        <ResponsiveContainer width="100%" height={280}>
          <BarChart data={tonerBarData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
            <XAxis dataKey="range" tick={{ fontSize: 10 }} />
            <YAxis tick={{ fontSize: 10 }} />
            <Tooltip />
            <Legend />
            {['BK', 'CY', 'MG', 'YW'].map(c => (
              <Bar key={c} dataKey={c} fill={TONER_COLORS[c.toLowerCase()]} radius={[2, 2, 0, 0]} />
            ))}
          </BarChart>
        </ResponsiveContainer>
      </ChartCard>

      {/* Rankings */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <ChartCard title="Top 10 por Entregas">
          <DataTable
            columns={[{ key: 'serie', label: 'Série' }, { key: 'fila', label: 'Fila' }, { key: 'modelo', label: 'Modelo' }, { key: 'count', label: 'Entregas' }]}
            rows={equipment.top_by_deliveries || []}
          />
        </ChartCard>
        <ChartCard title="Top 10 por A4">
          <DataTable
            columns={[{ key: 'serie', label: 'Série' }, { key: 'fila', label: 'Fila' }, { key: 'total_a4', label: 'A4' }]}
            rows={equipment.top_by_a4 || []}
          />
        </ChartCard>
        <ChartCard title="Top 10 por Incidentes">
          <DataTable
            columns={[{ key: 'serie', label: 'Série' }, { key: 'fila', label: 'Fila' }, { key: 'count', label: 'Incidentes' }]}
            rows={equipment.top_by_incidents || []}
          />
        </ChartCard>
        <ChartCard title="Top 10 por Recolhas">
          <DataTable
            columns={[{ key: 'serie', label: 'Série' }, { key: 'fila', label: 'Fila' }, { key: 'count', label: 'Recolhas' }]}
            rows={equipment.top_by_recolhas || []}
          />
        </ChartCard>
      </div>

      {/* Days since delivery + counter production */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <ChartCard title="Dias desde Última Entrega (desc)">
          <DataTable
            columns={[{ key: 'serie', label: 'Série' }, { key: 'modelo', label: 'Modelo' }, { key: 'last_delivery', label: 'Última Entrega' }, { key: 'days', label: 'Dias' }]}
            rows={equipment.days_since_delivery || []}
          />
        </ChartCard>
        <ChartCard title="Produção de Contador por Equipamento">
          <DataTable
            columns={[{ key: 'serie', label: 'Série' }, { key: 'total_production', label: 'Produção Total' }]}
            rows={equipment.counter_production || []}
          />
        </ChartCard>
      </div>
    </div>
  );
}

import React from 'react';
import {
  LineChart, Line, BarChart, Bar, ScatterChart, Scatter,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, ZAxis
} from 'recharts';
import KPICard from '../widgets/KPICard';
import ChartCard from '../widgets/ChartCard';

export default function OperationalTab({ data }) {
  const op = data?.operational || {};

  const slaByMonth = (op.sla_by_month || []).map(d => ({ name: d.period, SLA: d.rate }));
  const byFunc = (op.by_funcionario || []).map(d => ({ name: d.name, value: d.count }));
  const byAlm = (op.by_almoxarifado || []).map(d => ({ name: d.name, value: d.count }));
  const paperVsCounter = (op.paper_vs_counter || []).map(d => ({
    x: d.a4_total,
    y: d.counter_production,
    z: 1,
    name: d.serie,
  }));
  const tonerVsCounter = (op.toner_vs_counter || []).map(d => ({
    name: d.model,
    toner: d.toner_total,
    counter: d.avg_counter,
  }));

  return (
    <div className="space-y-6">
      {/* KPIs */}
      <div className="grid grid-cols-2 md:grid-cols-2 gap-4">
        <KPICard label="SLA Compliance" value={`${op.sla_compliance_rate ?? 0}%`} />
        <KPICard label="Média Produção Contador" value={op.avg_counter_production ?? 0} />
      </div>

      {/* SLA trend */}
      <ChartCard title="SLA por Mês (%)">
        <ResponsiveContainer width="100%" height={280}>
          <LineChart data={slaByMonth}>
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
            <XAxis dataKey="name" tick={{ fontSize: 10 }} />
            <YAxis domain={[0, 100]} tick={{ fontSize: 10 }} unit="%" />
            <Tooltip formatter={(v) => `${v}%`} />
            <Line type="monotone" dataKey="SLA" stroke="rgb(var(--color-primary))" strokeWidth={2} dot={{ r: 3 }} name="SLA %" />
          </LineChart>
        </ResponsiveContainer>
      </ChartCard>

      {/* Scatter: paper vs counter */}
      <ChartCard title="Correlação: A4 vs Produção de Contador">
        <ResponsiveContainer width="100%" height={280}>
          <ScatterChart>
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
            <XAxis dataKey="x" name="A4 (resmas)" tick={{ fontSize: 10 }} label={{ value: 'A4', position: 'insideBottom', offset: -5, fontSize: 10 }} />
            <YAxis dataKey="y" name="Produção Contador" tick={{ fontSize: 10 }} />
            <ZAxis dataKey="z" range={[40, 40]} />
            <Tooltip cursor={{ strokeDasharray: '3 3' }} content={({ payload }) => {
              if (!payload?.length) return null;
              const d = payload[0]?.payload;
              return (
                <div className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg p-2 text-xs shadow">
                  <p className="font-bold">{d?.name}</p>
                  <p>A4: {d?.x}</p>
                  <p>Contador: {d?.y}</p>
                </div>
              );
            }} />
            <Scatter data={paperVsCounter} fill="rgb(var(--color-primary))" />
          </ScatterChart>
        </ResponsiveContainer>
      </ChartCard>

      {/* Toner vs counter by model */}
      {tonerVsCounter.length > 0 && (
        <ChartCard title="Toner vs Contador por Modelo">
          <ResponsiveContainer width="100%" height={280}>
            <BarChart data={tonerVsCounter}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis dataKey="name" tick={{ fontSize: 9 }} angle={-30} textAnchor="end" height={50} />
              <YAxis tick={{ fontSize: 10 }} />
              <Tooltip />
              <Legend />
              <Bar dataKey="toner" fill="#f59e0b" name="Toner Total" radius={[4, 4, 0, 0]} />
              <Bar dataKey="counter" fill="rgb(var(--color-primary))" name="Média Contador" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      )}

      {/* By funcionario */}
      {byFunc.length > 0 && (
        <ChartCard title="Top 10 por Funcionário">
          <ResponsiveContainer width="100%" height={280}>
            <BarChart data={byFunc} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis type="number" tick={{ fontSize: 10 }} />
              <YAxis type="category" dataKey="name" tick={{ fontSize: 10 }} width={120} />
              <Tooltip />
              <Bar dataKey="value" fill="#22c55e" name="Entregas" radius={[0, 4, 4, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      )}

      {/* By almoxarifado */}
      {byAlm.length > 0 && (
        <ChartCard title="Por Almoxarifado">
          <ResponsiveContainer width="100%" height={280}>
            <BarChart data={byAlm}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis dataKey="name" tick={{ fontSize: 10 }} />
              <YAxis tick={{ fontSize: 10 }} />
              <Tooltip />
              <Bar dataKey="value" fill="#06b6d4" name="Entregas" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      )}
    </div>
  );
}

import React from 'react';
import {
  AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from 'recharts';
import KPICard from '../widgets/KPICard';
import ChartCard from '../widgets/ChartCard';
import AlertPanel from '../widgets/AlertPanel';
import { Package, Truck, Printer, AlertTriangle } from 'lucide-react';

const COLORS = ['rgb(var(--color-primary))', '#22c55e', '#f59e0b', '#ef4444', '#06b6d4', '#a855f7'];

export default function OverviewTab({ data }) {
  const delivery = data?.delivery || {};
  const supply = data?.supply || {};
  const equipment = data?.equipment || {};
  const stock = data?.stock || {};
  const predictive = data?.predictive || {};

  const totalToners = (supply.total_toner_bk || 0) + (supply.total_toner_cy || 0) +
    (supply.total_toner_mg || 0) + (supply.total_toner_yw || 0);

  const byMonthData = (delivery.by_month || []).map(d => ({ name: d.period, value: d.count }));
  const statusData = (equipment.status_distribution || []).map(d => ({ name: d.name, value: d.value }));
  const top5 = (equipment.top_by_deliveries || []).slice(0, 5).map(d => ({
    name: d.serie || d.fila || '',
    value: d.count,
  }));

  return (
    <div className="space-y-6">
      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
        <KPICard label="Total Entregas" value={delivery.total_entregas ?? 0} icon={<Truck className="w-4 h-4" />} />
        <KPICard label="Total A4 (resmas)" value={supply.total_a4 ?? 0} icon={<Package className="w-4 h-4" />} />
        <KPICard label="Total Toners" value={totalToners} icon={<Package className="w-4 h-4" />} />
        <KPICard label="Frota Total" value={equipment.fleet_size ?? 0} icon={<Printer className="w-4 h-4" />} />
        <KPICard label="Alertas Toner" value={(predictive.toner_alerts || []).length} icon={<AlertTriangle className="w-4 h-4" />} />
        <KPICard label="Estoque Zerado" value={(stock.zero_stock_items || []).length} icon={<AlertTriangle className="w-4 h-4" />} />
      </div>

      {/* Charts row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <ChartCard title="Volume de Entregas por Mês">
          <ResponsiveContainer width="100%" height={280}>
            <AreaChart data={byMonthData}>
              <defs>
                <linearGradient id="colorPrimary" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="rgb(var(--color-primary))" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="rgb(var(--color-primary))" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis dataKey="name" tick={{ fontSize: 10 }} />
              <YAxis tick={{ fontSize: 10 }} />
              <Tooltip />
              <Area type="monotone" dataKey="value" stroke="rgb(var(--color-primary))" fill="url(#colorPrimary)" name="Entregas" />
            </AreaChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="Status da Frota">
          <ResponsiveContainer width="100%" height={280}>
            <PieChart>
              <Pie data={statusData} cx="50%" cy="50%" innerRadius={60} outerRadius={100} dataKey="value" nameKey="name" label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`} labelLine={false}>
                {statusData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      {/* Top 5 equipment */}
      <ChartCard title="Top 5 Equipamentos por Entregas">
        <ResponsiveContainer width="100%" height={280}>
          <BarChart data={top5} layout="vertical">
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
            <XAxis type="number" tick={{ fontSize: 10 }} />
            <YAxis type="category" dataKey="name" tick={{ fontSize: 10 }} width={100} />
            <Tooltip />
            <Bar dataKey="value" fill="rgb(var(--color-primary))" name="Entregas" radius={[0, 4, 4, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </ChartCard>

      {/* Alerts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <ChartCard title="Alertas de Toner">
          <AlertPanel alerts={predictive.toner_alerts || []} type="toner" />
        </ChartCard>
        <ChartCard title="Alertas de Papel">
          <AlertPanel alerts={predictive.paper_alerts || []} type="paper" />
        </ChartCard>
      </div>
    </div>
  );
}

import React from 'react';
import {
  AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from 'recharts';
import ChartCard from '../widgets/ChartCard';
import DataTable from '../widgets/DataTable';
import AlertPanel from '../widgets/AlertPanel';

const COLORS = ['rgb(var(--color-primary))', '#22c55e', '#f59e0b', '#ef4444', '#06b6d4', '#a855f7'];

export default function StockTab({ data }) {
  const stock = data?.stock || {};

  const catData = (stock.by_category || []).map(d => ({ name: d.name, value: d.value }));
  const movData = (stock.movements_by_month || []).map(d => ({ name: d.period, Entrada: d.entrada, Saída: d.saida }));
  const typeData = (stock.movements_by_type || []).map(d => ({ name: d.name, value: d.value }));

  const zeroAlerts = (stock.zero_stock_items || []).map(item => ({
    serie: item.tipo_modelo,
    fila: item.categoria,
    estoque_atual: item.estoque_atual,
  }));

  return (
    <div className="space-y-6">
      {/* Zero stock alerts */}
      {zeroAlerts.length > 0 && (
        <ChartCard title={`⚠️ Itens com Estoque Zerado (${zeroAlerts.length})`}>
          <AlertPanel alerts={zeroAlerts} type="stock" />
        </ChartCard>
      )}

      {/* Stock items table */}
      <ChartCard title="Posição Atual do Estoque">
        <DataTable
          columns={[
            { key: 'tipo_modelo', label: 'Item' },
            { key: 'categoria', label: 'Categoria' },
            { key: 'estoque_atual', label: 'Estoque Atual' },
            { key: 'ultima_alteracao', label: 'Última Alteração' },
          ]}
          rows={stock.items || []}
          maxRows={20}
        />
      </ChartCard>

      {/* By category */}
      <ChartCard title="Estoque por Categoria">
        <ResponsiveContainer width="100%" height={280}>
          <BarChart data={catData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
            <XAxis dataKey="name" tick={{ fontSize: 10 }} />
            <YAxis tick={{ fontSize: 10 }} />
            <Tooltip />
            <Bar dataKey="value" fill="rgb(var(--color-primary))" name="Estoque" radius={[4, 4, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </ChartCard>

      {/* Movements */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <ChartCard title="Movimentações por Mês">
          <ResponsiveContainer width="100%" height={280}>
            <AreaChart data={movData}>
              <defs>
                <linearGradient id="colorEntrada" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#22c55e" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#22c55e" stopOpacity={0} />
                </linearGradient>
                <linearGradient id="colorSaida" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis dataKey="name" tick={{ fontSize: 10 }} />
              <YAxis tick={{ fontSize: 10 }} />
              <Tooltip />
              <Legend />
              <Area type="monotone" dataKey="Entrada" stroke="#22c55e" fill="url(#colorEntrada)" />
              <Area type="monotone" dataKey="Saída" stroke="#ef4444" fill="url(#colorSaida)" />
            </AreaChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="Por Tipo de Lançamento">
          <ResponsiveContainer width="100%" height={280}>
            <PieChart>
              <Pie data={typeData} cx="50%" cy="50%" outerRadius={100} dataKey="value" nameKey="name" label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`} labelLine={false}>
                {typeData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>
    </div>
  );
}

import React from 'react';
import {
  AreaChart, Area, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from 'recharts';
import KPICard from '../widgets/KPICard';
import ChartCard from '../widgets/ChartCard';
import DataTable from '../widgets/DataTable';

const COLORS = ['rgb(var(--color-primary))', '#22c55e', '#f59e0b', '#ef4444', '#06b6d4', '#a855f7'];

export default function SuppliesTab({ data }) {
  const supply = data?.supply || {};

  const consumptionData = (supply.consumption_by_month || []).map(d => ({
    name: d.period,
    A4: d.a4,
    Toner: d.toner,
  }));

  const mix = supply.paper_vs_toner_mix || {};
  const mixData = [
    { name: 'Só Papel', value: mix.paper_only || 0 },
    { name: 'Só Toner', value: mix.toner_only || 0 },
    { name: 'Ambos', value: mix.both || 0 },
    { name: 'Nenhum', value: mix.neither || 0 },
  ].filter(d => d.value > 0);

  return (
    <div className="space-y-6">
      {/* KPIs */}
      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-4">
        <KPICard label="Total A4" value={supply.total_a4 ?? 0} />
        <KPICard label="Total A3" value={supply.total_a3 ?? 0} />
        <KPICard label="Toner BK" value={supply.total_toner_bk ?? 0} />
        <KPICard label="Toner CY" value={supply.total_toner_cy ?? 0} />
        <KPICard label="Toner MG" value={supply.total_toner_mg ?? 0} />
        <KPICard label="Toner YW" value={supply.total_toner_yw ?? 0} />
        <KPICard label="Média A4/Entrega" value={supply.avg_a4_per_delivery ?? 0} />
      </div>

      {/* Consumption trend */}
      <ChartCard title="Consumo por Mês (A4 e Toner)">
        <ResponsiveContainer width="100%" height={280}>
          <AreaChart data={consumptionData}>
            <defs>
              <linearGradient id="colorA4" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="rgb(var(--color-primary))" stopOpacity={0.3} />
                <stop offset="95%" stopColor="rgb(var(--color-primary))" stopOpacity={0} />
              </linearGradient>
              <linearGradient id="colorToner" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3} />
                <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
            <XAxis dataKey="name" tick={{ fontSize: 10 }} />
            <YAxis tick={{ fontSize: 10 }} />
            <Tooltip />
