                        />
                    </div>
                    <div className="h-6 w-[1px] bg-slate-200 mx-2 hidden sm:block"></div>
                    <button
                        onClick={() => setShowFilters(!showFilters)}
                        className={cn(
                            "flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all",
