                            </button>
                        )}
                        <div className="relative flex-1 md:flex-none md:w-64">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 dark:text-slate-500" />
                            <input
                                type="text"
                                placeholder="Série, Fila, Modelo..."
                                className="w-full pl-10 pr-4 py-2 bg-slate-100 dark:bg-slate-800 border-none rounded-xl text-sm text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 focus:ring-2 focus:ring-primary/20 outline-none transition-all"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>

                        <select
                            className="bg-slate-100 dark:bg-slate-800 border-none rounded-xl px-4 py-2 text-xs font-bold text-slate-700 dark:text-slate-300 focus:ring-2 focus:ring-primary/20 outline-none transition-all"
                            value={statusFilter}
                            onChange={(e) => setStatusFilter(e.target.value)}
                        >
                            <option value="all" className="dark:bg-slate-900">Status: Todos</option>
                            {availableStatuses.map(s => <option key={s} value={s} className="dark:bg-slate-900">{s}</option>)}
                        </select>

                        <select
                            className="bg-slate-100 dark:bg-slate-800 border-none rounded-xl px-4 py-2 text-xs font-bold text-slate-700 dark:text-slate-300 focus:ring-2 focus:ring-primary/20 outline-none transition-all"
                            value={cityFilter}
                            onChange={(e) => setCityFilter(e.target.value)}
                        >
                            <option value="all" className="dark:bg-slate-900">Unidade: Todas</option>
                            {availableCities.map(c => <option key={c} value={c} className="dark:bg-slate-900">{c}</option>)}
                        </select>

                        <ColumnManager columns={columns} onChange={setColumns} />
                        <ExportButton
                            tableId="equipment"
                            data={sortedData}
                            visibleColumns={visibleColumns}
                            backendEndpoint="/export/inventory"
                            backendParams={{ contract_id: contractId }}
                            backendFilename={`inventario_${contractId}.csv`}
                        />
                    </div>
                </div>

                <div className="overflow-auto flex-1 custom-scrollbar">
                    <table className="w-full text-left text-xs border-separate border-spacing-0 min-w-[1000px]">
                        <thead className="bg-slate-50 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-0 z-10 transition-colors">
                            <tr>
                                {visibleColumns.map((col) => (
                                    <ResizableHeader
                                        key={col.key}
                                        columnKey={col.key}
                                        width={widths[col.key]}
                                        onResize={(k, w) => setColumnWidth(k, w)}
                                        onResizeEnd={(k, w) => setColumnWidth(k, w)}
                                        className="px-4 py-4 font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest text-[9px] cursor-pointer select-none hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors border-b border-slate-200 dark:border-slate-800"
                                        style={{ minWidth: widths[col.key] ? `${widths[col.key]}px` : col.minW }}
                                        onClick={() => requestSort(col.key)}
                                    >
                                        <div className="flex items-center gap-2">
                                            {col.label}
                                            <div className="flex flex-col opacity-20">
                                                <ArrowUp className={cn("w-2 h-2", sortConfig?.key === col.key && sortConfig.direction === 'ascending' && "text-primary opacity-100")} />
                                                <ArrowDown className={cn("w-2 h-2", sortConfig?.key === col.key && sortConfig.direction === 'descending' && "text-primary opacity-100")} />
                                            </div>
                                        </div>
                                    </ResizableHeader>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                            {paginatedItems.map((item, i) => (
                                <tr
                                    key={i}
                                    onClick={() => setSelectedEquipment(item.Serie)}
                                    className="group hover:bg-slate-50/80 dark:hover:bg-slate-800/50 cursor-pointer transition-all border-b border-slate-50 dark:border-slate-800"
                                >
                                    {visibleColumns.map(col => {
                                        switch (col.key) {
                                            case 'Serie':
                                                return <td key={col.key} className="px-4 py-4 font-mono font-bold text-primary group-hover:text-primary/80 transition-colors">{item.Serie}</td>;
                                            case 'Fila':
                                                return <td key={col.key} className="px-4 py-4 text-slate-600 dark:text-slate-400 font-medium">{item.Fila}</td>;
                                            case 'ModeloSimpress':
                                                return <td key={col.key} className="px-4 py-4 text-slate-800 dark:text-white font-bold">{item.ModeloSimpress || item.Modelo || '—'}</td>;
                                            case 'STATUS':
                                                return (
                                                    <td key={col.key} className="px-4 py-4">
                                                        {(() => {
                                                            const status = item.STATUS || item.Status || '';
                                                            return (
                                                                <span className={cn(
                                                                    "px-2.5 py-1 rounded-full text-[10px] uppercase font-bold border",
                                                                    status.toLowerCase().includes('produ')
                                                                        ? 'border-emerald-200 dark:border-emerald-800 text-emerald-700 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-950/30'
                                                                        : status.toLowerCase().includes('backup')
                                                                            ? 'border-amber-200 dark:border-amber-800 text-amber-700 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/30'
                                                                            : status
                                                                                ? 'border-slate-200 dark:border-slate-800 text-slate-500 dark:text-slate-400 bg-slate-50 dark:bg-slate-900/50'
                                                                                : 'border-transparent text-slate-300 dark:text-slate-600'
                                                                )}>
                                                                    {status || '—'}
                                                                </span>
                                                            );
                                                        })()}
                                                    </td>
                                                );
                                            case '_toner':
                                                return (
                                                    <td key={col.key} className="px-4 py-3">
                                                        <TonerBars bk={item.toner_bk} cy={item.toner_cy} mg={item.toner_mg} yw={item.toner_yw} />
                                                    </td>
                                                );
                                            case 'Empresa':
                                                return (
                                                    <td key={col.key} className="px-4 py-4">
                                                        <div className="text-slate-700 dark:text-slate-300 font-medium">{item.Empresa}</div>
                                                        <div className="text-[9px] text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider mt-0.5">{item.Cidade}</div>
                                                    </td>
                                                );
                                            case 'LocalInstalacao':
                                                return (
                                                    <td key={col.key} className="px-4 py-4 text-slate-600 dark:text-slate-400 text-xs" title={[item.LocalInstalacao, item.RuaRef].filter(Boolean).join(' · ') || item.ENDERECO}>
                                                        <div>{item.LocalInstalacao || item.ENDERECO || '—'}</div>
                                                        {item.RuaRef && item.RuaRef !== item.LocalInstalacao && (
                                                            <div className="text-[10px] text-slate-400 dark:text-slate-500 mt-0.5">{item.RuaRef}</div>
                                                        )}
                                                    </td>
                                                );
                                            default:
                                                return <td key={col.key} className="px-4 py-4 text-slate-600 dark:text-slate-400">{item[col.key]}</td>;
                                        }
                                    })}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-800 flex justify-between items-center bg-slate-50 dark:bg-slate-900 shrink-0 transition-colors">
                    <button
                        disabled={page === 1}
                        onClick={() => setPage(p => p - 1)}
                        className="px-5 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 font-bold text-xs hover:bg-slate-50 dark:hover:bg-slate-700 disabled:opacity-30 transition-all active:scale-95 shadow-sm"
                    >
                        Anterior
                    </button>
                    <span className="text-slate-400 dark:text-slate-500 font-medium text-xs">
                        Página <strong className="text-slate-800 dark:text-white">{page}</strong> de <strong className="text-slate-800 dark:text-white">{totalPages}</strong>
                        <span className="mx-2 text-slate-200 dark:text-slate-800">|</span>
                        <strong className="text-primary">{filteredData.length}</strong> dispositivos
                    </span>
                    <button
                        disabled={page === totalPages}
                        onClick={() => setPage(p => p + 1)}
                        className="px-5 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 font-bold text-xs hover:bg-slate-50 dark:hover:bg-slate-700 disabled:opacity-30 transition-all active:scale-95 shadow-sm"
                    >
                        Próxima
                    </button>
                </div>
            </div>

            {/* Modal */}
            {selectedEquipment && (
                <EquipmentModal
                    serie={selectedEquipment}
                    activeContract={activeContract}
                    onClose={() => setSelectedEquipment(null)}
                />
            )}
        </div>
    );
}

function Card({ title, value, icon, color, sub }) {
    const colorMap = {
        indigo: { icon: 'text-primary bg-primary/10', border: 'border-primary/20' },
        emerald: { icon: 'text-emerald-600 bg-emerald-100', border: 'border-emerald-100' },
        blue: { icon: 'text-blue-600 bg-blue-100', border: 'border-blue-100' },
        amber: { icon: 'text-amber-600 bg-amber-100', border: 'border-amber-100' }
    };

    const c = colorMap[color] || colorMap.indigo;

    return (
        <div className={cn("bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm p-5 flex items-center gap-4 hover:shadow-md transition-all")}>
            <div className={cn("p-3 rounded-2xl", c.icon)}>
                {icon}
            </div>
            <div className="flex-1">
                <p className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">{title}</p>
                <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-0.5">{value}</h3>
                {sub && (
                    <p className="text-[9px] text-slate-500 dark:text-slate-400 font-medium mt-1">{sub}</p>
                )}
            </div>
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { X, Printer, MapPin, Activity, Calendar, FileText, Search } from 'lucide-react';
import api from '../../lib/api';
import { cn } from '../../lib/utils';

export default function EquipmentModal({ serie, onClose, activeContract }) {
    const [loading, setLoading] = useState(true);
    const [data, setData] = useState(null);
    const [error, setError] = useState(null);
    const [activeTab, setActiveTab] = useState('details');

    // History Pagination/Filter
    const [historySearch, setHistorySearch] = useState('');
    const [historyPage, setHistoryPage] = useState(1);
    const historyItemsPerPage = 5;

    // Helper for contract ID extraction
    const contractId = typeof activeContract === 'string'
        ? activeContract
        : activeContract?.contract_id || activeContract?.id || null;

    useEffect(() => {
        if (!serie) return;
        const fetchDetails = async () => {
            setLoading(true);
            try {
                const res = await api.get(`/data/assist/equipment/${encodeURIComponent(serie)}`, {
                    params: { contract_id: contractId }
                });
                if (res.data) {
                    setData(res.data);
                } else {
                    setError('Equipamento não encontrado.');
                }
            } catch (err) {


                setError('Erro ao carregar detalhes.');
            } finally {
                setLoading(false);
            }
        };
        fetchDetails();
    }, [serie, contractId]);

    if (!serie) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 dark:bg-black/80 backdrop-blur-md animate-in fade-in duration-300 transition-colors">
            <div className="glass-surface dark:bg-slate-900/90 w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col relative animate-in zoom-in duration-300 rounded-3xl border border-white/20 dark:border-slate-800 shadow-2xl bg-white transition-colors">

                {/* Header */}
                <div className="flex justify-between items-start p-6 border-b border-slate-200 dark:border-slate-800 shrink-0 bg-white dark:bg-slate-900 transition-colors">
                    <div className="flex-1">
                        <div className="flex items-center justify-between w-full">
                            <h2 className="text-2xl font-bold text-slate-800 dark:text-white flex items-center gap-3">
                                <div className="p-2 bg-primary/10 text-primary rounded-xl">
                                    <Printer className="h-6 w-6" />
                                </div>
                                {serie}
                                {data?.equipment?.Fila && (
                                    <span className="text-lg text-slate-400 dark:text-slate-500 font-normal">
                                        / {data.equipment.Fila}
                                    </span>
                                )}
                            </h2>
                            <button
                                onClick={onClose}
                                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-all text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300"
                            >
                                <X className="h-6 w-6" />
                            </button>
                        </div>

                        {/* Tabs */}
                        <div className="flex gap-8 mt-5">
                            <button
                                onClick={() => setActiveTab('details')}
                                className={cn(
                                    "pb-2 text-xs font-bold uppercase tracking-widest transition-all border-b-2",
                                    activeTab === 'details' ? 'border-primary text-primary' : 'border-transparent text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300'
                                )}
                            >
                                Detalhes do Equipamento
                            </button>
                            <button
                                onClick={() => setActiveTab('history')}
                                className={cn(
                                    "pb-2 text-xs font-bold uppercase tracking-widest transition-all border-b-2",
                                    activeTab === 'history' ? 'border-primary text-primary' : 'border-transparent text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300'
                                )}
                            >
                                Histórico ({data?.history?.length || 0})
                            </button>
                        </div>
                    </div>
                </div>

                {/* Content Area */}
                <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-slate-50/50 dark:bg-slate-900/50 transition-colors">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center py-20 space-y-4">
                            <div className="w-10 h-10 border-4 border-slate-200 dark:border-slate-800 border-t-primary rounded-full animate-spin" />
                            <p className="text-sm text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">Carregando dados...</p>
                        </div>
                    ) : error ? (
                        <div className="bg-red-50 dark:bg-red-950 border border-red-200 dark:border-red-900 text-red-600 p-6 rounded-xl flex items-center gap-4 justify-center">
                            <Activity className="h-6 w-6" />
                            <span className="font-bold text-sm">{error}</span>
                        </div>
                    ) : data && (
                        <div className="space-y-6 animate-in fade-in duration-300">
                            {activeTab === 'details' ? (
                                <>
                                    {/* Main Identity Card */}
                                    <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-6 rounded-xl grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 shadow-sm transition-colors">
                                        <div className="space-y-1">
                                            <label className="text-[9px] uppercase text-slate-400 dark:text-slate-500 font-bold tracking-widest">Modelo</label>
                                            <p className="text-sm font-bold text-slate-800 dark:text-white">{data.equipment.ModeloSimpress || '-'}</p>
                                        </div>
                                        <div className="space-y-1">
                                            <label className="text-[9px] uppercase text-slate-400 dark:text-slate-500 font-bold tracking-widest">Fila / Hostname</label>
                                            <p className="text-sm font-mono text-primary font-bold">{data.equipment.Fila || '-'}</p>
                                        </div>
                                        <div className="space-y-1">
                                            <label className="text-[9px] uppercase text-slate-400 dark:text-slate-500 font-bold tracking-widest">Status</label>
                                            <div>
                                                <span className={cn(
                                                    "inline-block px-2.5 py-1 rounded-full text-[10px] font-bold uppercase border",
                                                    (data.equipment.STATUS || '').toLowerCase().includes('produ')
                                                        ? 'bg-emerald-50 dark:bg-emerald-950/30 text-emerald-700 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800'
                                                        : 'bg-amber-50 dark:bg-amber-950/30 text-amber-700 dark:text-amber-400 border-amber-200 dark:border-amber-800'
                                                )}>
                                                    {data.equipment.STATUS || 'Desconhecido'}
                                                </span>
                                            </div>
                                        </div>
                                        <div className="space-y-1">
                                            <label className="text-[9px] uppercase text-slate-400 dark:text-slate-500 font-bold tracking-widest">IP</label>
                                            <p className="text-sm font-mono text-slate-500 dark:text-slate-400">{data.equipment.IP || '-'}</p>
                                        </div>
                                    </div>

                                    {/* Location Info */}
                                    <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-6 rounded-xl shadow-sm transition-colors">
                                        <h3 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-5 flex items-center gap-2">
                                            <MapPin className="h-3.5 w-3.5 text-primary" />
                                            Localização
                                        </h3>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-1 text-sm">
                                            <div className="flex justify-between py-3 border-b border-slate-100 dark:border-slate-800">
                                                <span className="text-slate-400 dark:text-slate-500 font-medium">Unidade</span>
                                                <span className="font-bold text-slate-800 dark:text-white text-right">{data.equipment.Empresa || '-'}</span>
                                            </div>
                                            <div className="flex justify-between py-3 border-b border-slate-100 dark:border-slate-800">
                                                <span className="text-slate-400 dark:text-slate-500 font-medium">Cidade / UF</span>
                                                <span className="font-bold text-slate-800 dark:text-white text-right">{data.equipment.Cidade} - {data.equipment.UF}</span>
                                            </div>
                                            <div className="flex justify-between py-3 border-b border-slate-100 dark:border-slate-800">
                                                <span className="text-slate-400 dark:text-slate-500 font-medium">Setor</span>
                                                <span className="font-bold text-slate-800 dark:text-white text-right">{data.equipment.Area || '-'}</span>
                                            </div>
                                            <div className="flex justify-between py-3 border-b border-slate-100 dark:border-slate-800">
                                                <span className="text-slate-400 dark:text-slate-500 font-medium">Local de Instalação</span>
                                                <span className="font-bold text-slate-800 dark:text-white text-right">{data.equipment.LocalInstalacao || '-'}</span>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Counters & Last Delivery */}
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                        <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-6 rounded-xl shadow-sm transition-colors">
                                            <h3 className="text-primary font-bold mb-5 flex items-center gap-2 uppercase tracking-widest text-[10px]">
                                                <Activity className="h-3.5 w-3.5" />
                                                Contadores e Toner
                                            </h3>
                                            <div className="space-y-4">
                                                <div className="flex justify-between items-end">
                                                    <span className="text-slate-400 dark:text-slate-500 text-sm font-medium">Total Acumulado</span>
                                                    <span className="font-bold text-slate-900 dark:text-white text-2xl">
                                                        {data.counters?.counter_total?.toLocaleString() || '0'}
                                                    </span>
                                                </div>
                                                <div className="h-px bg-slate-100 dark:bg-slate-800"></div>
                                                <div className="grid grid-cols-4 gap-2 text-center">
                                                    {['BK', 'CY', 'MG', 'YW'].map((c) => {
                                                        const pct = data.counters?.[`toner_${c.toLowerCase()}_pct`];
                                                        const colorClass = c === 'BK' ? 'bg-slate-100 dark:bg-slate-800 text-slate-800 dark:text-slate-200' :
                                                                         c === 'CY' ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400' :
                                                                         c === 'MG' ? 'bg-pink-50 dark:bg-pink-900/30 text-pink-700 dark:text-pink-400' :
                                                                         'bg-amber-50 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400';
                                                        return (
                                                            <div key={c} className={cn("py-2.5 rounded-xl border border-slate-100 dark:border-slate-800", colorClass)}>
                                                                <p className="text-[8px] font-bold opacity-60 uppercase">{c}</p>
                                                                <p className="text-sm font-bold">{pct || '0'}%</p>
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        </div>

                                        <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-6 rounded-xl shadow-sm transition-colors">
                                            <h3 className="text-primary font-bold mb-5 flex items-center gap-2 uppercase tracking-widest text-[10px]">
                                                <Calendar className="h-3.5 w-3.5" />
