                                            </h3>
                                            <div className="space-y-3">
                                                <div className="flex justify-between">
                                                    <span className="text-slate-400 dark:text-slate-500 text-sm font-medium">Data</span>
                                                    <span className="font-bold text-slate-800 dark:text-white">
                                                        {data.last_delivery?.date
                                                            ? (data.last_delivery.date instanceof Date
                                                                ? data.last_delivery.date.toLocaleDateString('pt-BR')
                                                                : String(data.last_delivery.date).split('T')[0])
                                                            : 'Sem registro'}
                                                    </span>
                                                </div>
                                                <div className="flex justify-between">
                                                    <span className="text-slate-400 dark:text-slate-500 text-sm font-medium">Contador Final</span>
                                                    <span className="font-mono text-slate-800 dark:text-slate-200 font-bold">
                                                        {data.last_delivery?.counter || '-'}
                                                    </span>
                                                </div>
                                                <div className="h-px bg-slate-100 dark:bg-slate-800"></div>
                                                <div>
                                                    <p className="text-[9px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest mb-2">Itens Entregues:</p>
                                                    <div className="flex flex-wrap gap-2">
                                                        {data.last_delivery?.qty > 0 && (
                                                            <span className="bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 px-2.5 py-1 rounded-full text-[10px] text-slate-700 dark:text-slate-300 font-bold">
                                                                A4: {data.last_delivery.qty} resma(s)
                                                            </span>
                                                        )}
                                                        {!data.last_delivery?.qty && (
                                                            <span className="text-slate-400 dark:text-slate-500 text-[10px] italic">Sem dados</span>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Suggestion */}
                                    {data.suggestion && (
                                        <div className="bg-amber-50/50 dark:bg-amber-950/20 p-6 rounded-xl border border-amber-200 dark:border-amber-900 flex items-start gap-4 transition-colors">
                                            <div className="w-10 h-10 bg-amber-100 dark:bg-amber-900/40 rounded-xl flex items-center justify-center shrink-0 border border-amber-200 dark:border-amber-800">
                                                <FileText className="h-5 w-5 text-amber-600 dark:text-amber-400" />
                                            </div>
                                            <div>
                                                <h4 className="text-sm font-bold text-amber-800 dark:text-amber-500">Sugestão de Atendimento</h4>
                                                <p className="text-xs text-amber-600 dark:text-amber-500 opacity-80 mt-1 leading-relaxed">
                                                    Baseado na análise de consumo e telemetrias, segue sugestão:
                                                </p>
                                                <div className="flex flex-wrap gap-3 mt-3">
                                                    <div className="bg-white dark:bg-slate-900 px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm transition-colors">
                                                        <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Resmas A4</p>
                                                        <p className="text-lg font-bold text-slate-900 dark:text-white">{data.suggestion.resmas || 0}</p>
                                                    </div>
                                                    <div className="bg-white dark:bg-slate-900 px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm transition-colors">
                                                        <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Toner BK</p>
                                                        <p className={cn("text-sm font-bold", data.suggestion.toner_bk ? 'text-red-600 dark:text-red-400' : 'text-slate-400 dark:text-slate-600')}>
                                                            {data.suggestion.toner_bk ? 'NECESSÁRIO' : 'ESTÁVEL'}
                                                        </p>
                                                    </div>
                                                    <div className="bg-white dark:bg-slate-900 px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm transition-colors">
                                                        <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Kit Color</p>
                                                        <p className={cn("text-sm font-bold", (data.suggestion.toner_cy || data.suggestion.toner_mg || data.suggestion.toner_yw) ? 'text-red-600 dark:text-red-400' : 'text-slate-400 dark:text-slate-600')}>
                                                            {(data.suggestion.toner_cy || data.suggestion.toner_mg || data.suggestion.toner_yw) ? 'NECESSÁRIO' : 'ESTÁVEL'}
                                                        </p>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </>
                            ) : (
                                <HistoryView
                                    history={data.history}
                                    search={historySearch}
                                    setSearch={setHistorySearch}
                                    page={historyPage}
                                    setPage={setHistoryPage}
                                    itemsPerPage={historyItemsPerPage}
                                />
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

function HistoryView({ history, search, setSearch, page, setPage, itemsPerPage }) {
    const filtered = (history || []).filter(item =>
        (item.Protocolo || '').toString().includes(search) ||
        (item.DataEntrega || item.Data || '').includes(search)
    );

    const totalPages = Math.ceil(filtered.length / itemsPerPage);
    const paginated = filtered.slice((page - 1) * itemsPerPage, page * itemsPerPage);

    return (
        <div className="space-y-4">
            <div className="flex justify-between items-center bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm transition-colors">
                <h4 className="text-sm font-bold text-slate-800 dark:text-white">Histórico de Entregas</h4>
                <div className="relative w-56">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-slate-400 dark:text-slate-500" />
                    <input
                        type="text"
                        placeholder="Buscar ID ou Data..."
                        className="w-full pl-9 pr-4 py-2 bg-slate-100 dark:bg-slate-800 border-none rounded-xl text-xs text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 focus:ring-2 focus:ring-primary/20 outline-none transition-all"
                        value={search}
                        onChange={(e) => { setSearch(e.target.value); setPage(1); }}
                    />
                </div>
            </div>

            <div className="overflow-hidden border border-slate-200 dark:border-slate-800 rounded-xl bg-white dark:bg-slate-900 shadow-sm transition-colors">
                <table className="w-full text-left text-xs">
                    <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 dark:text-slate-400 font-bold uppercase tracking-widest text-[9px] border-b border-slate-200 dark:border-slate-800 transition-colors">
                        <tr>
                            <th className="px-5 py-3.5">Protocolo</th>
                            <th className="px-5 py-3.5">Data</th>
                            <th className="px-5 py-3.5 text-center">Contador</th>
                            <th className="px-5 py-3.5">Itens</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                        {paginated.length > 0 ? paginated.map((item, i) => (
                            <tr key={i} className="hover:bg-slate-50/80 dark:hover:bg-slate-800/50 transition-colors">
                                <td className="px-5 py-4 font-bold text-primary">#{item.Protocolo}</td>
                                <td className="px-5 py-4 text-slate-500 dark:text-slate-400 font-medium">{item.DataEntrega || item.Data}</td>
                                <td className="px-5 py-4 font-mono text-center text-slate-800 dark:text-slate-200 font-bold">{item.ContadorFinal || item.ContFinal || '-'}</td>
                                <td className="px-5 py-4">
                                    <div className="flex flex-wrap gap-1.5">
                                        {item.A4 > 0 && <span className="bg-primary/10 text-primary px-2 py-0.5 rounded border border-primary/20 font-bold text-[10px]">A4: {item.A4}</span>}
                                        {(item.TonerPreto > 0 || item.TonerBk > 0) && <span className="bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 px-2 py-0.5 rounded border border-slate-200 dark:border-slate-700 font-bold text-[10px]">BK: {item.TonerPreto || item.TonerBk}</span>}
                                        {(item.TonerCiano > 0 || item.TonerCy > 0) && <span className="bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 px-2 py-0.5 rounded border border-blue-100 dark:border-blue-800 font-bold text-[10px]">CY: {item.TonerCiano || item.TonerCy}</span>}
                                        {(item.TonerMagenta > 0 || item.TonerMg > 0) && <span className="bg-pink-50 dark:bg-pink-900/30 text-pink-700 dark:text-pink-300 px-2 py-0.5 rounded border border-pink-100 dark:border-pink-800 font-bold text-[10px]">MG: {item.TonerMagenta || item.TonerMg}</span>}
                                        {(item.TonerAmarelo > 0 || item.TonerYw > 0) && <span className="bg-amber-50 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300 px-2 py-0.5 rounded border border-amber-100 dark:border-amber-800 font-bold text-[10px]">YW: {item.TonerAmarelo || item.TonerYw}</span>}
                                    </div>
                                </td>
                            </tr>
                        )) : (
                            <tr>
                                 <td colSpan="4" className="px-5 py-16 text-center text-slate-400 dark:text-slate-600 font-bold text-xs uppercase tracking-widest">Nenhum registro no histórico.</td>
                            </tr>
                        )}
                    </tbody>
                </table>
            </div>

            {totalPages > 1 && (
                <div className="flex justify-between items-center px-2 mt-4 shrink-0">
                     <button
                        disabled={page === 1}
                        onClick={() => setPage(p => p - 1)}
                        className="px-5 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 font-bold text-xs hover:bg-slate-50 dark:hover:bg-slate-700 disabled:opacity-30 transition-all active:scale-95 shadow-sm"
                    >
                        Anterior
                    </button>
                     <span className="text-slate-400 dark:text-slate-500 font-bold text-xs">
                        Página <span className="text-slate-800 dark:text-white">{page}</span> de <span className="text-slate-800 dark:text-white">{totalPages}</span>
                    </span>
                     <button
                        disabled={page === totalPages}
                        onClick={() => setPage(p => p + 1)}
                        className="px-5 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 font-bold text-xs hover:bg-slate-50 dark:hover:bg-slate-700 disabled:opacity-30 transition-all active:scale-95 shadow-sm"
                    >
                        Próxima
                    </button>
                </div>
            )}
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { useToast } from '../../context/ToastContext';
import { useAuth } from '../../context/AuthProvider';
import api from '../../lib/api';
import { Search, Filter, History as HistoryIcon, ArrowUp, ArrowDown } from 'lucide-react';
import Pagination from '../Shared/Pagination';
import { usePagination } from '../../hooks/usePagination';
import { useSortableData } from '../../hooks/useSortableData';
import { useColumns } from '../../hooks/useColumns';
import { useColumnWidths } from '../../hooks/useColumnWidths';
import { cn } from '../../lib/utils';
import ColumnManager from '../Shared/ColumnManager';
import ExportButton from '../Shared/ExportButton';
import ResizableHeader from '../Shared/ResizableHeader';
import HistoryDetailModal from './HistoryDetailModal';

const HISTORY_COLUMNS = [
    { key: 'Protocolo',   label: 'Nº Pedido',       w: '110px' },
    { key: 'Status',      label: 'Status',           w: '110px' },
    { key: 'Cidade',      label: 'Cidade',           w: '110px' },
    { key: 'Empresa',     label: 'Unidade',          w: '160px' },
    { key: 'Modelo',      label: 'Equipamento',      w: '150px' },
    { key: 'Serie',       label: 'Número Série',     w: '130px' },
    { key: 'Fila',        label: 'Fila / Canal',     w: '110px' },
    { key: 'Solicitacao', label: 'Solicitante',      w: '130px' },
    { key: 'A4',          label: 'Itens Entregues',  w: '130px' },
    { key: 'DataEntrega', label: 'Data de Entrega',  w: '130px' },
];

export default function History() {
    const { addToast } = useToast();
    const { user } = useAuth();
    const [protocols, setProtocols] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedProtocol, setSelectedProtocol] = useState(null);

    // Filters State
    const [showFilters, setShowFilters] = useState(false);
    const [filterOptions, setFilterOptions] = useState({ cidades: [], filas: [], empresas: [] });
    const [filters, setFilters] = useState({ city: '', fila: '', empresa: '' });
    const [dateRange, setDateRange] = useState({ start: '', end: '' });
    const [search, setSearch] = useState('');

    useEffect(() => {
        fetchFilterOptions();
    }, []);

    useEffect(() => {
        loadHistory();
    }, [filters, search, dateRange, user.activeContract]);

    const fetchFilterOptions = async () => {
        try {
            const res = await api.get('data/entregas/filter-options');
            if (res.data && typeof res.data === 'object') {
                setFilterOptions({
                    cidades: Array.isArray(res.data.cidades) ? res.data.cidades : [],
                    filas: Array.isArray(res.data.filas) ? res.data.filas : [],
                    empresas: Array.isArray(res.data.empresas) ? res.data.empresas : []
                });
            }
        } catch (_error) {
            console.warn("Failed to fetch filter options:", _error);
        }
    };

    const loadHistory = async () => {
        if (!user.activeContract) return;

        try {
            setLoading(true);
            const params = new URLSearchParams({
                limit: 500,
                status: 'all',
                contract_id: user.activeContract,
                city: filters.city,
                fila: filters.fila,
                empresa: filters.empresa,
                search: search,
                start_date: dateRange.start,
                end_date: dateRange.end
            });
            const response = await api.get(`/data/entregas?${params.toString()}`);
            if (Array.isArray(response.data)) {
                setProtocols(response.data);
            } else {
                setProtocols([]);
            }
        } catch (_error) {
            console.error("Failed to load history:", _error);
            setProtocols([]);
        } finally {
            setLoading(false);
        }
    };

    const handleRowClick = async (protocolId) => {
        try {
            const res = await api.get(`/data/entregas/${protocolId}`);
            setSelectedProtocol(res.data);
        } catch (_error) {
            console.error("Failed to fetch protocol details:", _error);
            addToast("Erro ao carregar detalhes do protocolo.", "error");
        }
    };

    const getStatusText = (status, date, cancelado) => {
        if (status === 'Cancelado' || cancelado === 'Sim') return 'Cancelado';
        if (status === 'Entregue' || date) return 'Entregue';
        return 'Pendente';
    };

    const { items: sortedProtocols, requestSort, sortConfig } = useSortableData(protocols);
    const { currentData: currentProtocols, paginationProps } = usePagination(sortedProtocols, 15);
    const { columns, setColumns, visibleColumns } = useColumns(`history-columns`, HISTORY_COLUMNS);
    const { widths, setColumnWidth } = useColumnWidths(`history-columns`);

    return (
        <div className="space-y-6 flex flex-col h-full animate-in fade-in duration-500">
            {/* Page Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 shrink-0">
                <div className="flex items-center gap-4">
                    <div className="p-3 bg-primary/10 text-primary rounded-2xl shadow-sm">
                        <HistoryIcon size={24} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-bold text-slate-800 dark:text-white tracking-tight">Histórico de Entregas</h1>
                        <p className="text-slate-500 dark:text-slate-400 text-sm">Todos os pedidos e entregas realizados.</p>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <ColumnManager columns={columns} onChange={setColumns} />
                    <ExportButton
                        tableId="history"
                        data={sortedProtocols}
                        visibleColumns={visibleColumns}
                        backendEndpoint="/export/deliveries"
                        backendParams={{
                            status: 'all',
                            contract_id: user.activeContract,
                            city: filters.city,
                            fila: filters.fila,
                            empresa: filters.empresa,
                            search,
                            start_date: dateRange.start,
                            end_date: dateRange.end,
                        }}
                        backendFilename={`historico_${user.activeContract}.csv`}
                    />
                </div>
            </div>

            {/* Filters */}
            <div className="bg-white dark:bg-slate-900 p-2 border border-slate-200 dark:border-slate-800 rounded-xl shadow-sm flex flex-col md:flex-row gap-2 items-center justify-between shrink-0 transition-colors">
                <div className="relative flex-1 w-full">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                    <input
                        type="text"
                        placeholder="Buscar por identificador ou número de série..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 text-sm border-none focus:ring-0 bg-transparent text-slate-800 dark:text-white placeholder-slate-400"
                    />
                </div>
                <button
                    onClick={() => setShowFilters(!showFilters)}
                    className={cn(
                        "flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all",
                        showFilters ? "bg-primary/10 text-primary" : "text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800"
                    )}
                >
                    <Filter className="h-4 w-4" /> Filtros
                </button>
            </div>

            {showFilters && (
                <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm grid grid-cols-1 md:grid-cols-3 gap-6 animate-in slide-in-from-top-2 duration-300">
                    <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Cidade</label>
                        <select className="w-full p-2.5 border border-slate-200 dark:border-slate-700 rounded-lg text-sm bg-slate-50 dark:bg-slate-800 dark:text-white outline-none" value={filters.city} onChange={(e) => setFilters(prev => ({ ...prev, city: e.target.value }))}>
                            <option value="" className="dark:bg-slate-900">TODAS</option>
                            {filterOptions.cidades.map(c => <option key={c} value={c} className="dark:bg-slate-900">{c.toUpperCase()}</option>)}
                        </select>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Unidade</label>
                        <select className="w-full p-2.5 border border-slate-200 dark:border-slate-700 rounded-lg text-sm bg-slate-50 dark:bg-slate-800 dark:text-white outline-none" value={filters.empresa} onChange={(e) => setFilters(prev => ({ ...prev, empresa: e.target.value }))}>
                            <option value="" className="dark:bg-slate-900">TODAS</option>
                            {filterOptions.empresas.map(c => <option key={c} value={c} className="dark:bg-slate-900">{c.toUpperCase()}</option>)}
                        </select>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Canal</label>
                        <select className="w-full p-2.5 border border-slate-200 dark:border-slate-700 rounded-lg text-sm bg-slate-50 dark:bg-slate-800 dark:text-white outline-none" value={filters.fila} onChange={(e) => setFilters(prev => ({ ...prev, fila: e.target.value }))}>
                            <option value="" className="dark:bg-slate-900">TODOS</option>
                            {filterOptions.filas.map(c => <option key={c} value={c} className="dark:bg-slate-900">{c.toUpperCase()}</option>)}
                        </select>
                    </div>
                    <div className="md:col-span-3 grid grid-cols-1 md:grid-cols-2 gap-6 border-t border-slate-100 dark:border-slate-800 pt-6">
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Início (Data Entrega)</label>
                            <input
                                type="date"
                                className="w-full p-2.5 border border-slate-200 dark:border-slate-700 rounded-lg text-sm bg-slate-50 dark:bg-slate-800 dark:text-white outline-none"
                                value={dateRange.start}
                                onChange={e => setDateRange({ ...dateRange, start: e.target.value })}
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Fim (Data Entrega)</label>
                            <input
                                type="date"
                                className="w-full p-2.5 border border-slate-200 dark:border-slate-700 rounded-lg text-sm bg-slate-50 dark:bg-slate-800 dark:text-white outline-none"
                                value={dateRange.end}
                                onChange={e => setDateRange({ ...dateRange, end: e.target.value })}
                            />
                        </div>
                    </div>
                </div>
            )}

            {/* Read-Only Legacy Table */}
            <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden flex-1 flex flex-col min-h-0 transition-colors">
                <div className="overflow-auto flex-1 custom-scrollbar">
                    <table className="w-full text-left text-xs border-separate border-spacing-0 min-w-[1100px]">
                        <thead className="bg-slate-50 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-0 z-10 transition-colors">
                            <tr>
                                {visibleColumns.map((col) => (
                                    <ResizableHeader
                                        key={col.key}
                                        columnKey={col.key}
                                        width={widths[col.key]}
                                        onResize={(k, w) => setColumnWidth(k, w)}
                                        onResizeEnd={(k, w) => setColumnWidth(k, w)}
                                        className="px-4 py-4 font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest text-[9px] cursor-pointer select-none hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors border-b border-slate-200 dark:border-slate-800"
                                        style={{ width: widths[col.key] ? `${widths[col.key]}px` : col.w, minWidth: col.w }}
                                        onClick={() => requestSort(col.key)}
                                    >
                                        <div className="flex items-center justify-between">
                                            {col.label}
                                            <div className="flex flex-col opacity-20">
                                                <ArrowUp className={cn("w-2 h-2", sortConfig?.key === col.key && sortConfig.direction === 'ascending' && "text-primary opacity-100")} />
                                                <ArrowDown className={cn("w-2 h-2", sortConfig?.key === col.key && sortConfig.direction === 'descending' && "text-primary opacity-100")} />
                                            </div>
                                        </div>
                                    </ResizableHeader>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {loading ? (
                                <tr>
                                    <td colSpan="10" className="px-6 py-24 text-center">
                                       <div className="flex flex-col items-center gap-4">
                                          <div className="w-10 h-10 border-4 border-primary/20 border-t-primary rounded-full animate-spin" />
                                          <p className="text-sm font-medium text-slate-400">Carregando histórico...</p>
                                       </div>
                                    </td>
                                </tr>
                            ) : protocols.length === 0 ? (
                                <tr>
                                    <td colSpan="10" className="px-6 py-24 text-center">
                                       <div className="flex flex-col items-center gap-2 opacity-30">
                                          <Search size={48} className="text-slate-400" />
                                          <p className="font-bold text-sm">Nenhum registro encontrado</p>
                                       </div>
                                    </td>
                                </tr>
                            ) : (
                                currentProtocols.map((p, idx) => (
                                    <tr
                                        key={idx}
                                        onClick={() => handleRowClick(p.Protocolo)}
                                        className="group hover:bg-slate-50/80 dark:hover:bg-slate-800/50 cursor-pointer transition-colors border-b border-slate-100 dark:border-slate-800"
                                    >
                                        {visibleColumns.map(col => {
                                            switch (col.key) {
                                                case 'Protocolo':
                                                    return <td key={col.key} className="px-4 py-4 font-bold text-primary border-r border-slate-50 dark:border-slate-800">{p.Protocolo}</td>;
                                                case 'Status':
                                                    return (
                                                        <td key={col.key} className="px-4 py-4">
                                                            <span className={cn(
                                                                "px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border",
                                                                (p.Status === 'Cancelado' || p.Cancelado === 'Sim')
                                                                    ? "bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400 border-red-100 dark:border-red-800"
                                                                    : (p.Status === 'Entregue' || p.DataEntrega)
                                                                        ? "bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 border-emerald-100 dark:border-emerald-800"
                                                                        : "bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 border-amber-100 dark:border-amber-800"
                                                            )}>
                                                                {getStatusText(p.Status, p.DataEntrega, p.Cancelado)}
                                                            </span>
                                                        </td>
                                                    );
                                                case 'Cidade':
                                                    return <td key={col.key} className="px-4 py-4 text-slate-600 dark:text-slate-400 truncate max-w-[110px]" title={p.Cidade}>{p.Cidade}</td>;
                                                case 'Empresa':
                                                    return <td key={col.key} className="px-4 py-4 text-slate-600 dark:text-slate-400 truncate max-w-[160px]" title={p.Empresa}>{p.Empresa}</td>;
                                                case 'Modelo':
                                                    return <td key={col.key} className="px-4 py-4 text-slate-700 dark:text-slate-300 font-medium truncate max-w-[150px]" title={p.Modelo}>{p.Modelo}</td>;
                                                case 'Serie':
                                                    return <td key={col.key} className="px-4 py-4 text-slate-600 dark:text-slate-400 font-mono text-[10px] truncate max-w-[130px]" title={p.Serie}>{p.Serie}</td>;
                                                case 'Fila':
                                                    return <td key={col.key} className="px-4 py-4 text-primary font-bold tracking-tight truncate max-w-[110px]" title={p.Fila}>{p.Fila}</td>;
                                                case 'Solicitacao':
                                                    return <td key={col.key} className="px-4 py-4 text-slate-500 dark:text-slate-400 font-medium truncate max-w-[130px]" title={p.Solicitacao}>{p.Solicitacao}</td>;
                                                case 'A4':
                                                    return (
                                                        <td key={col.key} className="px-4 py-4">
                                                            <div className="flex flex-wrap gap-1">
                                                                {(() => {
                                                                    const a4 = parseInt(p.A4 || 0);
                                                                    const a3 = parseInt(p.A3 || 0);
                                                                    const bk = parseInt(p.TonerPreto || 0);
                                                                    const cy = parseInt(p.TonerCiano || 0);
                                                                    const mg = parseInt(p.TonerMagenta || 0);
                                                                    const yw = parseInt(p.TonerAmarelo || 0);
                                                                    const badges = [];
                                                                    if (a4 > 0) badges.push(<span key="a4" className="px-1.5 py-0.5 rounded text-[9px] font-bold bg-primary/10 text-primary border border-primary/20">A4×{a4}</span>);
                                                                    if (a3 > 0) badges.push(<span key="a3" className="px-1.5 py-0.5 rounded text-[9px] font-bold bg-primary/10 text-primary border border-primary/20">A3×{a3}</span>);
                                                                    if (bk > 0) badges.push(<span key="bk" className="px-1.5 py-0.5 rounded text-[9px] font-bold bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 border border-slate-200 dark:border-slate-700">BK×{bk}</span>);
                                                                    if (cy > 0) badges.push(<span key="cy" className="px-1.5 py-0.5 rounded text-[9px] font-bold bg-cyan-50 dark:bg-cyan-900/20 text-cyan-700 dark:text-cyan-400 border border-cyan-200 dark:border-cyan-800">CY×{cy}</span>);
                                                                    if (mg > 0) badges.push(<span key="mg" className="px-1.5 py-0.5 rounded text-[9px] font-bold bg-pink-50 dark:bg-pink-900/20 text-pink-700 dark:text-pink-400 border border-pink-200 dark:border-pink-800">MG×{mg}</span>);
                                                                    if (yw > 0) badges.push(<span key="yw" className="px-1.5 py-0.5 rounded text-[9px] font-bold bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-400 border border-amber-200 dark:border-amber-800">YW×{yw}</span>);
                                                                    return badges.length > 0 ? badges : <span className="text-slate-300 dark:text-slate-600">—</span>;
                                                                })()}
                                                            </div>
                                                        </td>
                                                    );
                                                case 'DataEntrega':
                                                    return <td key={col.key} className="px-4 py-4 text-slate-900 dark:text-white font-bold truncate max-w-[130px]" title={p.DataEntrega}>{p.DataEntrega || '-'}</td>;
                                                default:
                                                    return <td key={col.key} className="px-4 py-4 text-slate-600 dark:text-slate-400">{p[col.key]}</td>;
                                            }
                                        })}
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
            
            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 rounded-xl shadow-sm shrink-0 transition-colors">
                <Pagination {...paginationProps} />
            </div>

            {/* Detail Modal */}
            {selectedProtocol && (
                <HistoryDetailModal
                    protocol={selectedProtocol}
                    onClose={() => setSelectedProtocol(null)}
                />
            )}
        </div>
    );
}

import { useRef, useState } from 'react';
import { useToast } from '../../context/ToastContext';
import { useReactToPrint } from 'react-to-print';
import { X, Printer, MapPin, User, FileText, CheckCircle, PackageCheck } from 'lucide-react';
import ProtocolPrint from '../Protocol/ProtocolPrint';
import DeliveryModal from '../Protocol/ProtocolDelivery';

const ReadOnlyField = ({ label, value, icon: Icon, className = "" }) => (
    <div className={`flex flex-col ${className}`}>
        <label className="text-[10px] uppercase font-bold text-slate-500 mb-1 flex items-center gap-1">
            {Icon && <Icon size={10} />} {label}
        </label>
        <div className="text-sm font-medium text-slate-800 bg-slate-50 border border-slate-200 rounded px-2 py-1.5 min-h-[32px] flex items-center">
            {value || '-'}
        </div>
    </div>
);

export default function HistoryDetailModal({ protocol, onClose }) {
    const { addToast } = useToast();
    const printRef = useRef(null);
    const [showDelivery, setShowDelivery] = useState(false);

    const handlePrint = useReactToPrint({
        contentRef: printRef,
        documentTitle: `Protocolo_${protocol?.Protocolo}`,
        onAfterPrint: () => {},
        onPrintError: (_error) => {
            addToast("Erro ao imprimir: Verifique as configurações da impressora.", "error");
        }
    });

    if (!protocol) return null;

    return (
            <div className="bg-white dark:bg-slate-800 w-full max-w-4xl rounded-2xl shadow-2xl p-0 overflow-hidden flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className="bg-white dark:bg-slate-800 p-4 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center shrink-0">
                    <div className="flex items-center gap-3">
                        <div className="bg-purple-100 dark:bg-purple-900/30 p-2 rounded-lg">
                            <FileText className="text-purple-600 dark:text-purple-400" size={24} />
                        </div>
                        <div>
                            <h2 className="text-lg font-bold text-slate-900 dark:text-white">Protocolo #{protocol.Protocolo}</h2>
                            <p className="text-xs text-slate-500">{protocol.DataEntrega ? `Entregue em: ${protocol.DataEntrega}` : 'Pendente de Entrega'}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        {!protocol.DataEntrega && (
                            <button
                                onClick={() => setShowDelivery(true)}
                                className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg transition-colors font-medium text-sm"
                            >
                                <PackageCheck size={16} /> Dar Baixa
                            </button>
                        )}
                        <button
                            onClick={() => {
                                handlePrint();
                            }}
                            className="flex items-center gap-2 px-4 py-2 bg-primary hover:bg-primary/90 text-white rounded-lg transition-colors font-medium text-sm"
                        >
                            <Printer size={16} /> Imprimir Comprovante
                        </button>
                        <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors text-slate-500">
                            <X size={20} />
                        </button>
                    </div>
                </div>

                {/* Content - Scrollable */}
                <div className="overflow-y-auto p-6 space-y-6 bg-slate-50/50 dark:bg-slate-900/50">

                    {/* Equipment Section */}
                    <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                        <h3 className="text-sm font-bold text-slate-900 dark:text-white uppercase tracking-wider mb-4 border-b border-slate-100 dark:border-slate-700 pb-2">
                            Equipamento
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                            <ReadOnlyField label="Série" value={protocol.Serie} icon={Printer} />
                            <ReadOnlyField label="Modelo" value={protocol.Modelo} />
                            <ReadOnlyField label="Fila" value={protocol.Fila} icon={CheckCircle} />
                            <ReadOnlyField label="Status Atual" value={protocol.StatusEmprestimo} />
                            <ReadOnlyField label="Contador Inicial" value={protocol.ContadorInicial} />
                            <ReadOnlyField label="Contador Final" value={protocol.ContadorFinal} />
                            <ReadOnlyField label="Produção" value={protocol.Producao} />
                            <ReadOnlyField label="% Toner" value={protocol.PorcentagemToner} />
                        </div>
                    </div>

                    {/* Location Section */}
                    <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                        <h3 className="text-sm font-bold text-slate-900 dark:text-white uppercase tracking-wider mb-4 border-b border-slate-100 dark:border-slate-700 pb-2">
                            Localização & Contato
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <ReadOnlyField label="Empresa" value={protocol.Empresa} icon={MapPin} />
                            <ReadOnlyField label="Solicitante" value={protocol.Solicitante} icon={User} />
                            <ReadOnlyField label="Ramal" value={protocol.Ramal} />
                            <ReadOnlyField label="Local de Entrega" value={protocol.LocalEntrega} className="md:col-span-3" />
                        </div>
                    </div>

                    {/* Supplies Table */}
                    <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                        <h3 className="text-sm font-bold text-slate-900 dark:text-white uppercase tracking-wider mb-4 border-b border-slate-100 dark:border-slate-700 pb-2">
                            Suprimentos Entregues
                        </h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            {[
                                { name: 'Papel A4', key: 'A4' },
                                { name: 'Papel A3', key: 'A3' },
                                { name: 'Toner Preto', key: 'TonerPreto' },
                                { name: 'Toner Ciano', key: 'TonerCiano' },
                                { name: 'Toner Magenta', key: 'TonerMagenta' },
                                { name: 'Toner Amarelo', key: 'TonerAmarelo' },
                                { name: 'Outros', key: 'Outros' }
                            ].map(item => (
                                <div key={item.key} className={`flex justify-between items-center p-2 rounded-lg border ${protocol[item.key] > 0 ? 'bg-primary/10 border-primary/20 text-primary' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                                    <span className="text-xs font-bold">{item.name}</span>
                                    <span className="text-sm font-black">{protocol[item.key] > 0 ? protocol[item.key] : '-'}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Observations */}
                    {protocol.Obs && (
                        <div className="bg-amber-50 dark:bg-amber-900/10 p-4 rounded-xl border border-amber-100 dark:border-amber-900/30">
                            <h3 className="text-xs font-bold text-amber-800 dark:text-amber-400 uppercase tracking-wider mb-2">
                                Observações
                            </h3>
                            <p className="text-sm text-amber-900 dark:text-amber-200">{protocol.Obs}</p>
                        </div>
                    )}

                </div>
            </div>

            {/* Hidden Print Component - Kept in DOM but hidden */}
            <div style={{ position: 'absolute', top: -9999, left: -9999, width: 0, height: 0, overflow: 'hidden' }}>
                <ProtocolPrint ref={printRef} data={protocol} />
            </div>

            {/* DeliveryModal */}
            <DeliveryModal
                protocolId={protocol.Protocolo}
                isOpen={showDelivery}
                onClose={() => setShowDelivery(false)}
                onSuccess={() => { setShowDelivery(false); onClose(); }}
            />
        </div>
    );

}

import React, { useState } from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { LayoutDashboard, PlusCircle, Package, Truck, Settings, Menu } from 'lucide-react';
import { cn } from '../lib/utils';
import UserProfileModal from './Settings/UserProfileModal';
import { useAuth } from '../context/AuthProvider';

export default function Layout() {
    const location = useLocation();
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const { user } = useAuth();

    const navItems = [
        { name: 'Pendências', icon: LayoutDashboard, path: '/' },
        { name: 'Novo Protocolo', icon: PlusCircle, path: '/wizard' },
        { name: 'Entregas', icon: Truck, path: '/deliveries' }, 
        { name: 'Estoque', icon: Package, path: '/inventory' },
    ];

    const currentTitle = navItems.find(item => item.path === location.pathname)?.name || 'Supply 2026';
    const activeContractId = user?.activeContract?.contract_id || user?.activeContract || '00000000';

    return (
        <div className="flex h-screen bg-[#020617] text-slate-100 font-sans selection:bg-[#D18BFF]/30 selection:text-white">
            {/* Sidebar v12 Glassmorphism */}
            <aside className="w-72 bg-black/40 backdrop-blur-3xl border-r border-white/5 hidden md:flex flex-col relative z-[50]">
                <div className="absolute top-0 right-0 w-1 h-full bg-gradient-to-b from-transparent via-[#D18BFF]/20 to-transparent" />
                
                <div className="h-24 flex items-center px-8 border-b border-white/5">
                    <div className="flex items-center gap-4 group cursor-pointer">
                        <div className="p-2 bg-[#D18BFF] rounded-lg shadow-[0_0_15px_rgba(209,139,255,0.4)] group-hover:scale-110 transition-transform">
                            <Package className="h-6 w-6 text-black" />
                        </div>
                        <div>
                            <span className="text-xl font-bold text-white font-display tracking-tight block">SUPPLY 2026</span>
                            <span className="text-[9px] font-bold text-[#D18BFF] uppercase tracking-[0.3em] block -mt-1 opacity-70">Logistics Control</span>
                        </div>
                    </div>
                </div>

                <nav className="flex-1 py-10 px-6 space-y-3">
                    <div className="text-[10px] font-bold text-slate-600 uppercase tracking-[0.4em] mb-6 ml-2">Menu Principal</div>
                    {navItems.map((item) => {
                        const isActive = location.pathname === item.path;
                        const Icon = item.icon;
                        return (
                            <Link
                                key={item.path}
                                to={item.path}
                                className={cn(
                                    "flex items-center gap-4 px-4 py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all duration-300 relative group overflow-hidden",
                                    isActive
                                        ? "bg-white text-black shadow-[0_10px_30px_rgba(255,255,255,0.1)] scale-[1.02]"
                                        : "text-slate-500 hover:text-white hover:bg-white/5"
                                )}
                            >
                                <Icon className={cn("h-4 w-4 transition-transform group-hover:scale-110", isActive ? "text-black" : "text-[#D18BFF]/60")} />
                                {item.name}
                                {isActive && <div className="absolute left-0 w-1.5 h-full bg-[#D18BFF]" />}
                            </Link>
                        );
                    })}
                </nav>

                <div className="p-8 border-t border-white/5">
                    <button 
                        onClick={() => window.location.href = '/settings'}
                        className="flex items-center gap-4 px-4 py-4 text-[10px] font-bold uppercase tracking-widest text-[#D18BFF] bg-[#D18BFF]/5 border border-[#D18BFF]/20 w-full rounded-xl hover:bg-[#D18BFF] hover:text-black transition-all group"
                    >
                        <Settings className="h-4 w-4 group-hover:rotate-90 transition-transform duration-500" />
                        Gestão de Dados
                    </button>
                </div>
            </aside>

            {/* Main Content Area */}
            <div className="flex-1 flex flex-col overflow-hidden relative">
                {/* Background Blobs for Atmosphere */}
                <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-[#D18BFF]/5 blur-[120px] rounded-full pointer-events-none" />
                <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-[#4D91FF]/5 blur-[100px] rounded-full pointer-events-none" />

                {/* Header v12 Fluid Interface */}
                <header className="h-24 bg-black/20 backdrop-blur-md border-b border-white/5 flex items-center px-10 justify-between relative z-40">
                    <div className="flex items-center gap-6">
                        <button className="md:hidden p-3 bg-white/5 rounded-xl border border-white/10 text-white">
                            <Menu className="h-6 w-6" />
                        </button>
                        <div className="hidden md:block">
                            <h2 className="text-sm font-bold text-white font-display flex items-center gap-3">
                                <div className="w-2 h-2 rounded-full bg-[#4DFF88] shadow-[0_0_8px_#4DFF88]" />
                                {currentTitle}
                            </h2>
                        </div>
                    </div>

                    <div className="flex items-center gap-8">
                        {/* Monitoramento de Status */}
                        <div className="hidden lg:flex items-center gap-6 pr-6 border-r border-white/5">
                            <div className="flex flex-col items-end">
                                <span className="text-[9px] uppercase font-bold text-slate-500 tracking-[0.2em] mb-1">Contrato Ativo</span>
                                <span className="text-xs font-mono font-bold text-[#D18BFF] bg-[#D18BFF]/10 px-2 py-0.5 rounded border border-[#D18BFF]/20">#{activeContractId}</span>
                            </div>
                            <div className="flex flex-col items-end">
                                <span className="text-[9px] uppercase font-bold text-slate-500 tracking-[0.2em] mb-1">Estado de Rede</span>
                                <span className="text-[10px] font-bold text-[#4DFF88] flex items-center gap-1.5">
                                    <div className="w-1.5 h-1.5 rounded-full bg-[#4DFF88] animate-pulse" /> SÍNCRONO
                                </span>
                            </div>
                        </div>

                        {/* User Identity Chip */}
                        <button
                            onClick={() => setIsProfileOpen(true)}
                            className="flex items-center gap-4 bg-white/5 border border-white/10 hover:border-[#D18BFF]/40 p-2 pr-6 rounded-full transition-all group scale-100 hover:scale-[1.02]"
                        >
                            <div className="h-10 w-10 rounded-full bg-gradient-to-tr from-[#D18BFF] to-[#4D91FF] p-[2px] shadow-lg group-hover:shadow-[#D18BFF]/20 transition-all">
                                <div className="w-full h-full rounded-full bg-[#020617] flex items-center justify-center font-bold text-xs text-white overflow-hidden border border-black/20">
                                    {user?.avatar ? (
                                        <img src={user.avatar} alt="Avatar" className="w-full h-full object-cover" />
                                    ) : (
                                        <span>{user?.username?.substring(0, 2).toUpperCase()}</span>
                                    )}
                                </div>
                            </div>
                            <div className="text-left hidden sm:block">
                                <span className="text-xs font-bold text-white block leading-tight">{user?.username}</span>
                                <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">{user?.role || 'Agente'}</span>
                            </div>
                        </button>
                    </div>
                </header>

                <UserProfileModal
                    isOpen={isProfileOpen}
                    onClose={() => setIsProfileOpen(false)}
                    user={user}
                />

                {/* Main Dynamic Stage */}
                <main className="flex-1 overflow-auto p-12 custom-scrollbar relative z-10 transition-all duration-500">
                    <Outlet />
                </main>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { useAuth } from '../context/AuthProvider';
import { useNavigate, Link } from 'react-router-dom';
import { Lock, User, Sun, Moon } from 'lucide-react';
import { useTheme } from '../context/ThemeContext';

export default function Login() {
    const { login } = useAuth();
    const { isDarkMode, toggleTheme } = useTheme();
    const navigate = useNavigate();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        const res = await login(username, password);
        setLoading(false);

        if (res.success) {
            navigate(res.route || '/');
        } else {
            setError(res.msg || 'Falha no login');
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-950 bg-gradient-to-br from-slate-100 via-primary/5 to-slate-200 dark:from-slate-950 dark:via-slate-900 dark:to-slate-950 flex items-center justify-center p-6 relative overflow-hidden animate-in fade-in duration-700 transition-colors">
            {/* Subtle background decoration */}
            <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-primary/10 blur-[120px] rounded-full" />
            <div className="absolute bottom-[-20%] left-[-10%] w-[400px] h-[400px] bg-primary/5 blur-[100px] rounded-full" />

            <div className="w-full max-w-md relative z-10">
                <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl shadow-slate-200/50 dark:shadow-none p-10 border border-slate-200/80 dark:border-slate-800 relative overflow-hidden transition-colors">
                    {/* Decorative top accent */}
                    <div className="absolute top-0 left-0 right-0 h-1 bg-primary" />

                    <div className="text-center mb-8 relative">
                        <button 
                            type="button"
                            onClick={toggleTheme}
                            className="absolute right-0 top-0 p-2 rounded-xl bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-primary dark:hover:text-white transition-all shadow-sm border border-slate-100 dark:border-slate-700"
                            title="Alternar Tema"
                        >
                            {isDarkMode ? <Sun size={16} /> : <Moon size={16} />}
                        </button>
                        <div className="inline-flex items-center justify-center w-16 h-16 bg-primary/10 rounded-2xl mb-5 shadow-sm">
                            <Lock className="w-7 h-7 text-primary" />
                        </div>
                        <h1 className="text-3xl font-bold text-slate-800 dark:text-white tracking-tight mb-1">Supply <span className="text-primary">2026</span></h1>
                        <p className="text-[11px] font-bold text-slate-600 dark:text-slate-400 uppercase tracking-[0.3em]">Acesso Restrito</p>
                    </div>

                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-2">
                            <label className="block text-xs font-bold text-slate-600 dark:text-slate-400 uppercase tracking-widest ml-1">Usuário</label>
                            <div className="relative">
                                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                                    <User size={18} />
                                </span>
                                <input
                                    type="text"
                                    value={username}
                                    onChange={(e) => setUsername(e.target.value)}
                                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl pl-12 pr-4 py-3.5 text-sm text-slate-800 dark:text-white focus:bg-white dark:focus:bg-slate-700 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all placeholder:text-slate-400 dark:placeholder:text-slate-600 font-medium"
                                    placeholder="ex: admin"
                                    required
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="block text-xs font-bold text-slate-600 dark:text-slate-400 uppercase tracking-widest ml-1">Senha</label>
                            <div className="relative">
                                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                                    <Lock size={18} />
                                </span>
                                <input
                                    type="password"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl pl-12 pr-4 py-3.5 text-sm text-slate-800 dark:text-white focus:bg-white dark:focus:bg-slate-700 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all placeholder:text-slate-400 dark:placeholder:text-slate-600 font-mono tracking-widest"
                                    placeholder="••••••••"
                                    required
                                />
                            </div>
                        </div>

                        {error && (
                            <div className="bg-red-50 text-red-600 text-xs font-bold p-3.5 rounded-xl border border-red-200">
                                {error}
                            </div>
                        )}

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full flex justify-center items-center py-4 px-6 bg-primary hover:bg-primary/90 text-white rounded-xl text-xs font-bold uppercase tracking-widest overflow-hidden transition-all disabled:opacity-50 shadow-lg shadow-primary/20 active:scale-[0.98]"
                        >
                            {loading ? 'Entrando...' : 'Acessar Sistema'}
                        </button>

                        <div className="text-center pt-2">
                            <Link to="/forgot-password" title="Recuperar Senha" className="text-[11px] font-bold text-slate-600 dark:text-slate-400 hover:text-primary dark:hover:text-white uppercase tracking-widest transition-colors">
                                Esqueci minha senha
                            </Link>
                        </div>
                    </form>
                </div>

                {/* Footer */}
                <div className="mt-6 text-center">
                    <p className="text-[10px] font-bold text-slate-600 dark:text-slate-500 uppercase tracking-[0.3em]">Gerenciamento de Suprimentos</p>
                </div>
            </div>
        </div>
    );
}

