import { useState, useEffect } from 'react';
import { Wrench, AlertTriangle, CheckCircle, Clock, Copy, Plus, Filter, Search, ChevronRight } from 'lucide-react';
import api from '../../lib/api';
import { cn } from '../../lib/utils';
import OSWizard from './OSWizard';
import NFManager from './NFManager';

const MaintenanceDashboard = () => {
    const [equipments, setEquipments] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [filterStatus, setFilterStatus] = useState('ALL');
    const [isOSModalOpen, setIsOSModalOpen] = useState(false);
    const [activeTab, setActiveTab] = useState('preventive');

    const fetchStatus = async () => {
        try {
            const response = await api.get('/maintenance/status');
            setEquipments(response.data);
            setLoading(false);
        } catch (_error) {
            console.error("Failed to fetch maintenance status", _error);
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchStatus();
    }, []);

    const getStatusColor = (status) => {
        switch (status) {
            case 'CRITICAL': return 'text-red-500 bg-red-500/10 border-red-500/20';
            case 'WARNING': return 'text-amber-500 bg-amber-500/10 border-amber-500/20';
            default: return 'text-emerald-500 bg-emerald-500/10 border-emerald-500/20';
        }
    };

    const filteredEquipments = equipments.filter(eq => {
        const matchesSearch = eq.Serie.toLowerCase().includes(searchTerm.toLowerCase()) || 
                             (eq.Local || '').toLowerCase().includes(searchTerm.toLowerCase());

        const hasWarning = eq.Componentes.some(c => c.Status === 'WARNING' || c.Status === 'CRITICAL');
        const hasCritical = eq.Componentes.some(c => c.Status === 'CRITICAL');

        if (filterStatus === 'CRITICAL') return matchesSearch && hasCritical;
        if (filterStatus === 'WARNING') return matchesSearch && hasWarning;
        return matchesSearch;
    });

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Tab Navigation */}
            <div className="flex gap-4 border-b border-slate-200 dark:border-slate-800">
                <button 
                    onClick={() => setActiveTab('preventive')}
                    className={cn(
                        "pb-4 px-2 text-sm font-bold transition-all relative",
                        activeTab === 'preventive' ? "text-primary" : "text-slate-400 hover:text-slate-600"
                    )}
                >
                    Monitoramento Preventivo
                    {activeTab === 'preventive' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-primary rounded-full" />}
                </button>
                <button 
                    onClick={() => setActiveTab('finance')}
                    className={cn(
                        "pb-4 px-2 text-sm font-bold transition-all relative",
                        activeTab === 'finance' ? "text-primary" : "text-slate-400 hover:text-slate-600"
                    )}
                >
                    Notas Fiscais (Financeiro)
                    {activeTab === 'finance' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-primary rounded-full" />}
                </button>
            </div>

            {activeTab === 'preventive' ? (
                <>
            {/* Stats Overview */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                {[
                    { label: 'Total Monitorado', value: equipments.length, icon: Wrench, color: 'text-blue-500' },
                    { label: 'Críticos (>90%)', value: equipments.filter(e => e.Componentes.some(c => c.Status === 'CRITICAL')).length, icon: AlertTriangle, color: 'text-red-500' },
                    { label: 'Atenção (>80%)', value: equipments.filter(e => e.Componentes.some(c => c.Status === 'WARNING')).length, icon: Clock, color: 'text-amber-500' },
                    { label: 'Operacionais', value: equipments.filter(e => e.Componentes.every(c => c.Status === 'OK')).length, icon: CheckCircle, color: 'text-emerald-500' },
                ].map((stat, idx) => (
                    <div key={idx} className="bg-white/80 dark:bg-slate-900/50 backdrop-blur-xl p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm transition-all hover:scale-[1.02]">
                        <div className="flex items-center justify-between mb-4">
                            <div className={cn("p-3 rounded-2xl bg-slate-50 dark:bg-slate-800", stat.color)}>
                                <stat.icon size={24} />
                            </div>
                        </div>
                        <p className="text-3xl font-black text-slate-800 dark:text-white">{stat.value}</p>
                        <p className="text-xs font-bold uppercase tracking-widest text-slate-400 mt-1">{stat.label}</p>
                    </div>
                ))}
            </div>

            {/* Main Controls */}
            <div className="flex flex-col md:flex-row gap-4 items-center justify-between bg-white/50 dark:bg-slate-900/30 backdrop-blur-md p-4 rounded-3xl border border-slate-200 dark:border-slate-800">
                <div className="relative w-full md:w-96">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                        type="text" 
                        placeholder="Buscar por Série ou Local..."
                        className="w-full bg-white dark:bg-slate-800 border-none rounded-2xl py-3 pl-12 pr-4 text-sm focus:ring-2 focus:ring-primary transition-all outline-none"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
                <div className="flex items-center gap-2">
                    {['ALL', 'WARNING', 'CRITICAL'].map((status) => (
                        <button
                            key={status}
                            onClick={() => setFilterStatus(status)}
                            className={cn(
                                "px-6 py-2.5 rounded-2xl text-xs font-bold transition-all border",
                                filterStatus === status 
                                    ? "bg-primary text-white border-primary shadow-lg shadow-primary/20" 
                                    : "bg-white dark:bg-slate-800 text-slate-500 border-slate-200 dark:border-slate-700 hover:border-primary"
                            )}
                        >
                            {status === 'ALL' ? 'Todos' : status === 'WARNING' ? 'Atenção' : 'Crítico'}
                        </button>
                    ))}
                    <button 
                        onClick={() => setIsOSModalOpen(true)}
                        className="ml-4 bg-primary text-white px-6 py-2.5 rounded-2xl text-xs font-bold flex items-center gap-2 hover:bg-primary/90 transition-all shadow-lg shadow-primary/20"
                    >
                        <Plus size={16} /> Nova O.S.
                    </button>
                </div>
            </div>

            {/* Preventive Maintenance Table */}
            <div className="bg-white/80 dark:bg-slate-900/50 backdrop-blur-xl rounded-3xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-slate-50/50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                            <th className="p-6 text-xs font-bold uppercase tracking-widest text-slate-400">Equipamento</th>
                            <th className="p-6 text-xs font-bold uppercase tracking-widest text-slate-400">Localização</th>
                            <th className="p-6 text-xs font-bold uppercase tracking-widest text-slate-400 text-center">Desgaste por Componente</th>
                            <th className="p-6 text-xs font-bold uppercase tracking-widest text-slate-400 text-right">Ação</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                        {loading ? (
                            <tr><td colSpan="4" className="p-20 text-center text-slate-400 font-medium italic">Sincronizando dados de manutenção...</td></tr>
                        ) : filteredEquipments.length === 0 ? (
                            <tr><td colSpan="4" className="p-20 text-center text-slate-400 font-medium italic">Nenhum alerta de manutenção encontrado.</td></tr>
                        ) : filteredEquipments.map((eq) => (
                            <tr key={eq.Serie} className="group hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors">
                                <td className="p-6">
                                    <p className="font-bold text-slate-800 dark:text-white">{eq.Serie}</p>
                                    <p className="text-[10px] font-bold text-primary uppercase tracking-wider mt-0.5">{eq.Modelo}</p>
                                </td>
                                <td className="p-6">
                                    <p className="text-sm text-slate-600 dark:text-slate-400">{eq.Local || 'Sem Localização'}</p>
                                    <p className="text-[10px] text-slate-400 mt-0.5">Contador: {eq.ContadorAtual.toLocaleString()}</p>
                                </td>
                                <td className="p-6">
                                    <div className="flex items-center justify-center gap-4">
                                        {eq.Componentes.map((comp) => (
                                            <div key={comp.Tipo} className="flex flex-col items-center gap-2">
                                                <div className={cn(
                                                    "w-12 h-12 rounded-xl flex items-center justify-center border transition-all group-hover:scale-110",
                                                    getStatusColor(comp.Status)
                                                )}>
                                                    <span className="text-[10px] font-black">{comp.Uso}%</span>
                                                </div>
                                                <span className="text-[8px] font-bold uppercase tracking-tighter text-slate-400">{comp.Tipo}</span>
                                            </div>
                                        ))}
                                    </div>
                                </td>
                                <td className="p-6 text-right">
                                    <button className="p-2 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-400 hover:text-primary hover:bg-primary/10 transition-all">
                                        <ChevronRight size={20} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            </>
            ) : (
                <NFManager />
            )}

            <OSWizard 
                isOpen={isOSModalOpen} 
                onClose={() => setIsOSModalOpen(false)} 
                onSuccess={() => {
                    setIsOSModalOpen(false);
                    fetchStatus();
                }}
            />
        </div>
    );
};

export default MaintenanceDashboard;

import React, { useState, useEffect } from 'react';
import { FileText, Plus, Search, Trash2, Download, Calendar, Tag, DollarSign, X, Upload } from 'lucide-react';
import api from '../../lib/api';
import { cn } from '../../lib/utils';
import { useToast } from '../../context/ToastContext';

const NFManager = () => {
    const { addToast } = useToast();
    const [nfs, setNfs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [uploading, setUploading] = useState(false);
    const [formData, setFormData] = useState({
        numero: '',
        data: '',
        fornecedor: '',
        valor: '',
        serie: ''
    });
    const [selectedFile, setSelectedFile] = useState(null);

    useEffect(() => {
        fetchNFs();
    }, []);

    const fetchNFs = async () => {
        try {
            setLoading(true);
            const response = await api.get('/maintenance/nf');
            setNfs(Array.isArray(response.data) ? response.data : []);
        } catch (error) {
            console.error("Failed to fetch NFs", error);
        } finally {
            setLoading(false);
        }
    };

    const handleUpload = async (e) => {
        e.preventDefault();
        if (!selectedFile) return alert("Selecione um arquivo (PDF/Imagem)");

        const form = new FormData();
        form.append('file', selectedFile);
        form.append('numero', formData.numero);
        form.append('data', formData.data);
        form.append('fornecedor', formData.fornecedor);
        form.append('valor', formData.valor);
        form.append('serie', formData.serie);

        try {
            setUploading(true);
            await api.post('/maintenance/nf', form, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            addToast("Nota Fiscal registrada!", "success");
            setIsModalOpen(false);
            fetchNFs();
            setFormData({ numero: '', data: '', fornecedor: '', valor: '', serie: '' });
            setSelectedFile(null);
        } catch (error) {
            addToast("Erro ao registrar NF.", "error");
        } finally {
            setUploading(false);
        }
    };

    const handleDelete = async (filename) => {
        if (!window.confirm("Excluir esta Nota Fiscal permanentemente?")) return;
        try {
            await api.delete(`/maintenance/nf/${filename}`);
            addToast("NF excluída.", "info");
            fetchNFs();
        } catch (error) {
            addToast("Erro ao excluir.", "error");
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h3 className="text-xl font-bold text-slate-800 dark:text-white">Registro de Notas Fiscais</h3>
                    <p className="text-xs text-slate-400">Controle simples de faturamento de peças e serviços.</p>
                </div>
                <button 
                    onClick={() => setIsModalOpen(true)}
                    className="bg-primary text-white px-6 py-2.5 rounded-2xl text-xs font-bold flex items-center gap-2 hover:bg-primary/90 transition-all shadow-lg shadow-primary/20"
                >
                    <Plus size={16} /> Registrar NF
                </button>
            </div>

            {loading ? (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {[1,2,3].map(i => <div key={i} className="h-32 bg-slate-100 dark:bg-slate-800 animate-pulse rounded-2xl" />)}
                </div>
            ) : nfs.length === 0 ? (
                <div className="text-center py-20 bg-slate-50 dark:bg-slate-800/50 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-700">
                    <FileText size={48} className="mx-auto text-slate-300 mb-4" />
                    <p className="text-slate-400 font-medium">Nenhuma NF registrada para este contrato.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {nfs.map((nf, idx) => (
                        <div key={idx} className="group bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm hover:shadow-xl transition-all relative overflow-hidden">
                            <div className="absolute top-0 right-0 w-24 h-24 bg-primary/5 blur-2xl rounded-full -mr-12 -mt-12" />

                            <div className="flex items-start justify-between mb-4 relative">
                                <div className="p-3 bg-primary/10 rounded-xl text-primary">
                                    <FileText size={20} />
                                </div>
                                <button 
                                    onClick={() => handleDelete(nf.Filename)}
                                    className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>

                            <div className="space-y-3 relative">
                                <div>
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">NF #{nf.Numero}</p>
                                    <p className="font-bold text-slate-800 dark:text-white truncate">{nf.Fornecedor}</p>
                                </div>

                                <div className="grid grid-cols-2 gap-2 text-[11px]">
                                    <div className="flex items-center gap-1.5 text-slate-500">
                                        <Calendar size={12} />
                                        <span>{nf.Data}</span>
                                    </div>
                                    <div className="flex items-center gap-1.5 text-emerald-600 font-bold">
                                        <DollarSign size={12} />
                                        <span>R$ {parseFloat(nf.Valor).toLocaleString()}</span>
                                    </div>
                                </div>

                                {nf.Serie && (
                                    <div className="flex items-center gap-1.5 text-[10px] bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded-lg w-fit text-slate-500">
                                        <Tag size={10} />
                                        <span>Série: {nf.Serie}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* Upload Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 z-[80] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm">
                    <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl border border-slate-200 dark:border-slate-800 overflow-hidden">
                        <div className="p-6 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between">
                            <h3 className="text-lg font-bold text-slate-800 dark:text-white">Novo Registro de NF</h3>
                            <button onClick={() => setIsModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                                <X size={20} className="text-slate-400" />
                            </button>
                        </div>

                        <form onSubmit={handleUpload} className="p-6 space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Número NF</label>
                                    <input 
                                        type="text" required
                                        className="w-full bg-slate-50 dark:bg-slate-800 rounded-xl p-3 text-sm border-none outline-none focus:ring-2 focus:ring-primary"
                                        value={formData.numero}
                                        onChange={e => setFormData({...formData, numero: e.target.value})}
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Data Emissão</label>
                                    <input 
                                        type="date" required
                                        className="w-full bg-slate-50 dark:bg-slate-800 rounded-xl p-3 text-sm border-none outline-none focus:ring-2 focus:ring-primary"
                                        value={formData.data}
                                        onChange={e => setFormData({...formData, data: e.target.value})}
                                    />
                                </div>
                            </div>

                            <div className="space-y-1">
                                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Fornecedor</label>
                                <input 
                                    type="text" required
                                    className="w-full bg-slate-50 dark:bg-slate-800 rounded-xl p-3 text-sm border-none outline-none focus:ring-2 focus:ring-primary"
                                    value={formData.fornecedor}
                                    onChange={e => setFormData({...formData, fornecedor: e.target.value})}
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1">
