            {value || '—'}
        </div>
    </div>
);

// ─── DeliveryModal ────────────────────────────────────────────────────────────

export default function DeliveryModal({ protocolId, isOpen, onClose, onSuccess }) {
    const { addToast } = useToast();
    const { user } = useAuth();

    const [loading, setLoading] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [data, setData] = useState(null);
    const [deleteModal, setDeleteModal] = useState(null);

    const [form, setForm] = useState({
        RecebidoPor: '',
        DataEntrega: new Date().toISOString().split('T')[0],
        ContadorFinal: '',
        Obs: '',
        IncidenteRds: '',
        Almoxarifado: '',
        Items: { A4: 0, A3: 0, TonerPreto: 0, TonerCiano: 0, TonerAmarelo: 0, TonerMagenta: 0 }
    });

    // Fechar com Escape
    useEffect(() => {
        if (!isOpen) return;
        const handler = (e) => { if (e.key === 'Escape') onClose(); };
        document.addEventListener('keydown', handler);
        return () => document.removeEventListener('keydown', handler);
    }, [isOpen, onClose]);

    // Carregar protocolo quando abre
    useEffect(() => {
        if (!isOpen || !protocolId) return;
        setData(null);
        loadProtocol();
    }, [isOpen, protocolId]);

    const loadProtocol = async () => {
        try {
            setLoading(true);
            const res = await api.get(`/data/entregas/${protocolId}`);
            const p = res.data;
            setData(p);
            setForm({
                RecebidoPor: p.RecebidoPor || '',
                DataEntrega: new Date().toISOString().split('T')[0],
                ContadorFinal: '',
                Obs: '',
                IncidenteRds: p.IncidenteRds || '',
                Almoxarifado: p.Almoxarifado || '',
                Items: {
                    A4:           Number(p.A4)           || 0,
                    A3:           Number(p.A3)           || 0,
                    TonerPreto:   Number(p.TonerPreto)   || 0,
                    TonerCiano:   Number(p.TonerCiano)   || 0,
                    TonerAmarelo: Number(p.TonerAmarelo) || 0,
                    TonerMagenta: Number(p.TonerMagenta) || 0,
                }
            });
        } catch {
            addToast('Erro ao carregar protocolo.', 'error');
        } finally {
            setLoading(false);
        }
    };

    const handleItemChange = (key, value) => {
        setForm(prev => ({ ...prev, Items: { ...prev.Items, [key]: Number(value) || 0 } }));
    };

    const handleSubmit = async () => {
        await performDelivery();
    };

    const performDelivery = async () => {
        try {
            setSubmitting(true);
            await api.post(`/data/entregas/${protocolId}/deliver`, {
                ...form,
                user: user?.username || 'User',
                empresa: data.Empresa
            });
            addToast('Baixa realizada com sucesso!', 'success');
            onSuccess?.();
            onClose();
        } catch (err) {
            addToast(err.response?.data?.detail || 'Erro ao realizar baixa.', 'error');
        } finally {
            setSubmitting(false);
        }
    };

    const handleCancel = () => {
        setDeleteModal({
            title: 'Cancelar Pedido',
            message: `Tem certeza que deseja CANCELAR o pedido #${data.Protocolo}? Esta ação é irreversível.`,
            targetId: String(data.Protocolo),
            icon: AlertTriangle,
            variant: 'danger',
            requireTyping: false,
            confirmLabel: 'Confirmar Cancelamento',
            onConfirm: async () => { setDeleteModal(null); await performCancel(); }
        });
    };

    const performCancel = async () => {
        try {
            setSubmitting(true);
            await api.post(`/data/entregas/${protocolId}/cancel`, { reason: form.Obs });
            addToast('Pedido cancelado com sucesso.', 'success');
            onSuccess?.();
            onClose();
        } catch (err) {
            addToast(err.response?.data?.detail || 'Erro ao cancelar pedido.', 'error');
        } finally {
            setSubmitting(false);
        }
    };

    if (!isOpen) return null;

    const canConfirm = true;
    const pedidoOriginal = INSUMOS.filter(i => Number(data?.[i.key]) > 0);

    return (
        <>
            {/* Overlay */}
            <div
                className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200"
                onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
            >
                <div className="bg-white dark:bg-slate-900 w-full max-w-4xl max-h-[90vh] rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-800 flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">

                    {/* Header */}
                    <div className="flex items-center justify-between px-6 py-4 border-b border-slate-200 dark:border-slate-700 shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-primary/10 rounded-xl">
                                <PackageCheck className="w-5 h-5 text-primary" />
                            </div>
                            <div>
                                <h2 className="text-lg font-bold text-slate-800 dark:text-white">Baixa de Entrega</h2>
                                {data && (
                                    <p className="text-xs text-slate-500 dark:text-slate-400">
                                        Protocolo <span className="font-bold text-primary">#{data.Protocolo}</span>
                                        {data.Empresa && <span className="ml-2">— {data.Empresa}</span>}
                                    </p>
                                )}
                            </div>
                        </div>
                        <button
                            onClick={onClose}
                            className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors text-slate-400 dark:text-slate-500"
                        >
                            <X size={20} />
                        </button>
                    </div>

                    {/* Body */}
                    <div className="flex-1 overflow-y-auto">
                        {loading ? (
                            <div className="flex items-center justify-center py-20">
                                <Loader2 className="animate-spin w-8 h-8 text-primary" />
                            </div>
                        ) : !data ? (
                            <div className="flex flex-col items-center justify-center py-20 gap-4">
                                <p className="text-slate-500 dark:text-slate-400">Protocolo não encontrado.</p>
                                <button onClick={onClose} className="text-sm text-primary hover:underline">Fechar</button>
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-200 dark:divide-slate-700">

                                {/* ── Coluna Esquerda: Informações (read-only) ── */}
                                <div className="p-6 space-y-4 bg-slate-50/50 dark:bg-slate-900/50">
                                    <h3 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Informações do Protocolo</h3>

                                    <div className="grid grid-cols-2 gap-3">
                                        <ReadOnlyField label="Série" value={data.Serie} />
                                        <ReadOnlyField label="Modelo" value={data.Modelo} />
                                        <ReadOnlyField label="Fila" value={data.Fila} />
                                        <ReadOnlyField label="Empresa" value={data.Empresa} />
                                    </div>

                                    <ReadOnlyField
                                        label="Local de Instalação"
                                        value={data.LocalInstalacao || data.M_EndCompleto}
                                        className="col-span-2"
                                    />

                                    <div className="grid grid-cols-2 gap-3">
                                        <ReadOnlyField label="Contato" value={data.ContatoSetor || data.Contato} />
                                        <ReadOnlyField label="Ramal" value={data.Ramal} />
                                        {data.Horario && <ReadOnlyField label="Horário" value={data.Horario} />}
                                        {data.Area && <ReadOnlyField label="Área" value={data.Area} />}
                                    </div>

                                    {/* Pedido Original */}
                                    {pedidoOriginal.length > 0 && (
                                        <div className="pt-2 border-t border-slate-200 dark:border-slate-700">
                                            <h4 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-3">Pedido Original</h4>
                                            <div className="grid grid-cols-3 gap-2">
                                                {pedidoOriginal.map(({ key, label, color }) => (
                                                    <div key={key} className="flex items-center justify-between bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2">
                                                        <span className={cn('text-[10px] font-bold uppercase', color)}>{label}</span>
                                                        <span className="text-sm font-black text-slate-800 dark:text-white">{data[key]}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    )}
                                </div>

                                {/* ── Coluna Direita: Confirmação (editável) ── */}
                                <div className="p-6 space-y-4">
                                    <h3 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Confirmação de Entrega</h3>

                                    {/* Recebido por + Data */}
                                    <div className="grid grid-cols-2 gap-3">
                                        <div className="space-y-1">
                                            <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                                                Recebido por
                                            </label>
                                            <input
                                                type="text"
                                                value={form.RecebidoPor}
                                                onChange={e => setForm(p => ({ ...p, RecebidoPor: e.target.value }))}
                                                placeholder="Nome completo (opcional)"
                                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-sm text-slate-800 dark:text-white focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                                            />
                                        </div>
                                        <div className="space-y-1">
                                            <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Data de Entrega</label>
                                            <input
                                                type="date"
                                                value={form.DataEntrega}
                                                onChange={e => setForm(p => ({ ...p, DataEntrega: e.target.value }))}
                                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-sm text-slate-800 dark:text-white focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                                            />
                                        </div>
                                    </div>

                                    {/* Contador Final */}
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Contador Final</label>
                                        <input
                                            type="number"
                                            value={form.ContadorFinal}
                                            onChange={e => setForm(p => ({ ...p, ContadorFinal: e.target.value }))}
                                            placeholder="Leitura do contador no momento da entrega"
                                            className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-sm font-mono text-slate-800 dark:text-white focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                                        />
                                    </div>

                                    {/* Incidente / Requisição + Estoque no Local */}
                                    <div className="grid grid-cols-2 gap-3">
                                        <div className="space-y-1">
                                            <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                                                Nº Incidente / Requisição
                                            </label>
                                            <input
                                                type="text"
                                                value={form.IncidenteRds}
                                                onChange={e => setForm(p => ({ ...p, IncidenteRds: e.target.value }))}
                                                placeholder="Ex: INC0012345"
                                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-sm font-mono text-slate-800 dark:text-white focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                                            />
                                        </div>
                                        <div className="space-y-1">
                                            <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                                                Estoque no Local (resmas)
                                            </label>
                                            <input
                                                type="number"
                                                min="0"
                                                value={form.Almoxarifado}
                                                onChange={e => setForm(p => ({ ...p, Almoxarifado: e.target.value }))}
                                                placeholder="Qtd. resmas no local"
                                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-sm font-mono text-slate-800 dark:text-white focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                                            />
                                        </div>
                                    </div>

                                    {/* Insumos Entregues */}
                                    <div className="space-y-2">
                                        <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Insumos Entregues</label>
                                        <div className="grid grid-cols-3 gap-2">
                                            {INSUMOS.map(({ key, label, color }) => (
                                                <div key={key} className="space-y-1">
                                                    <label className={cn('text-[10px] font-bold uppercase tracking-widest block text-center', color)}>
                                                        {label}
                                                    </label>
                                                    <input
                                                        type="number"
                                                        min="0"
                                                        value={form.Items[key]}
                                                        onChange={e => handleItemChange(key, e.target.value)}
                                                        className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl py-2 text-center text-base font-bold text-slate-800 dark:text-white focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all font-mono"
                                                    />
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    {/* Observações */}
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Observações</label>
                                        <textarea
                                            value={form.Obs}
                                            onChange={e => setForm(p => ({ ...p, Obs: e.target.value }))}
                                            placeholder="Observações opcionais..."
                                            rows={2}
                                            className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-sm text-slate-800 dark:text-white focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all resize-none"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Footer */}
                    {data && !loading && (
                        <div className="flex items-center justify-between gap-3 px-6 py-4 border-t border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 shrink-0">
                            <button
                                onClick={handleCancel}
                                disabled={submitting}
                                className="flex items-center gap-2 px-5 py-2.5 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 border border-red-200 dark:border-red-800 rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-red-100 dark:hover:bg-red-900/30 transition-all disabled:opacity-50"
                            >
                                <AlertTriangle size={14} />
                                Cancelar Pedido
                            </button>

                            <button
                                onClick={handleSubmit}
                                disabled={submitting || !canConfirm}
                                className="flex items-center gap-2 px-6 py-2.5 bg-primary text-white rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-primary/90 transition-all shadow-lg shadow-primary/20 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {submitting
                                    ? <><Loader2 size={14} className="animate-spin" /> Processando...</>
                                    : <><CheckCircle size={14} /> Confirmar Entrega</>
                                }
                            </button>
                        </div>
                    )}
                </div>
            </div>

            {/* Modal de confirmação */}
            {deleteModal && (
                <GenericDeleteModal
                    title={deleteModal.title}
                    message={deleteModal.message}
                    targetId={deleteModal.targetId}
                    onClose={() => setDeleteModal(null)}
                    onConfirm={deleteModal.onConfirm}
                    icon={deleteModal.icon}
                    variant={deleteModal.variant}
                    confirmLabel={deleteModal.confirmLabel}
                />
            )}
        </>
    );
}

// ─── DeliveryPage — wrapper para rota /protocol/:id/deliver ───────────────────

export function DeliveryPage() {
    const { id } = useParams();
    const navigate = useNavigate();
    return (
        <DeliveryModal
            protocolId={id}
            isOpen={true}
            onClose={() => navigate('/')}
            onSuccess={() => navigate('/')}
        />
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { useToast } from '../../context/ToastContext';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../lib/api';
import { ArrowLeft, Printer, Save, Loader2, Eye, EyeOff } from 'lucide-react';
import ProtocolPrint from './ProtocolPrint';
import SolicitanteInput from '../Wizard/SolicitanteInput';
import { useReactToPrint } from 'react-to-print';

export default function ProtocolEditor() {
    const { addToast } = useToast();
    const { id } = useParams();
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [data, setData] = useState(null);
    const [showPreview, setShowPreview] = useState(false);
    const printRef = useRef();

    useEffect(() => { loadProtocol(); }, [id]);

    const loadProtocol = async () => {
        try {
            setLoading(true);
            const res = await api.get(`/data/entregas/${id}`);
            setData(res.data);
        } catch {
            addToast("Erro ao carregar protocolo.", "error");
        } finally {
            setLoading(false);
        }
    };

    const handlePrint = useReactToPrint({
        contentRef: printRef,
        documentTitle: `Protocolo_${id}`,
    });

    const handleSave = async () => {
        try {
            setSaving(true);
            await api.put(`/data/entregas/${id}`, {
                solicitante: data.Solicitante,
                ramal: data.Ramal,
                solicitacao: data.Solicitacao,
                incidente: data.IncidenteRds,
                analiseFV: data.AnaliseFV,
                counterInitial: data.ContadorInicial,
                counterFinal: data.ContadorFinal,
                production: data.Producao,
                productionReams: data.ProducaoResmas,
                comDefeito: data.ComDefeito,
                recolha: data.Recolha,
                funcionario: data.Funcionario,
                outros: data.Outros,
                tonerBk: data.TonerPreto,
                tonerCy: data.TonerCiano,
                tonerYw: data.TonerAmarelo,
                tonerMg: data.TonerMagenta,
                a4: data.A4,
                a3: data.A3,
                obs: data.Obs,
            });
            addToast("Protocolo salvo com sucesso!", "success");
        } catch {
            addToast("Erro ao salvar.", "error");
        } finally {
            setSaving(false);
        }
    };

    const set = (field, value) => {
        setData(prev => {
            const next = { ...prev, [field]: value };
            if (field === 'ContadorInicial' || field === 'ContadorFinal') {
                const ini = parseInt(next.ContadorInicial) || 0;
                const fin = parseInt(next.ContadorFinal) || 0;
                if (fin >= ini && fin > 0) {
                    next.Producao = fin - ini;
                    next.ProducaoResmas = ((fin - ini) / 500).toFixed(2);
                }
            }
            return next;
        });
    };

    if (loading) return (
        <div className="flex items-center justify-center py-32">
            <Loader2 className="animate-spin h-8 w-8 text-primary" />
        </div>
    );

    if (!data?.Protocolo) return (
        <div className="p-8 text-center text-slate-500 dark:text-slate-400">Protocolo não encontrado.</div>
    );

    const inp = "w-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2.5 text-sm text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 focus:border-primary focus:ring-2 focus:ring-primary/20 outline-none transition-all";
    const lbl = "block text-[11px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1.5";
    const card = "bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl p-5 shadow-sm space-y-4";

    return (
        <div className="space-y-5 animate-in fade-in duration-300">

            {/* ── Header ── */}
            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl p-4 flex items-center justify-between shadow-sm">
                <div className="flex items-center gap-3">
                    <button onClick={() => navigate('/')}
                        className="p-2 rounded-lg bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 transition-all">
                        <ArrowLeft className="w-4 h-4" />
                    </button>
                    <div>
                        <div className="flex items-center gap-2">
                            <span className="font-bold text-slate-900 dark:text-white">Protocolo</span>
                            <span className="text-xs font-mono font-bold text-primary bg-primary/10 px-2 py-0.5 rounded-full border border-primary/20">#{data.Protocolo}</span>
                            <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border ${
                                data.Status === 'Entregue' ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800' :
                                data.Status === 'Cancelado' ? 'bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400 border-red-200 dark:border-red-800' :
                                'bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-400 border-amber-200 dark:border-amber-800'
                            }`}>{data.Status || 'Pendente'}</span>
                        </div>
                        <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">{data.Empresa} · {data.Fila} · {data.Serie}</p>
                    </div>
                </div>
                <div className="flex gap-2">
                    <button onClick={() => setShowPreview(v => !v)}
                        className="flex items-center gap-2 px-3 py-2 text-xs font-bold text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-all">
                        {showPreview ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                        {showPreview ? 'Ocultar' : 'Preview'}
                    </button>
                    <button onClick={() => handlePrint()}
                        className="flex items-center gap-2 px-3 py-2 text-xs font-bold text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-all">
                        <Printer className="w-4 h-4" /> Imprimir
                    </button>
                    <button onClick={handleSave} disabled={saving}
                        className="flex items-center gap-2 px-5 py-2 text-xs font-bold text-white bg-primary hover:bg-primary/90 rounded-lg transition-all shadow-md disabled:opacity-50 active:scale-95">
                        {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                        Salvar
                    </button>
                </div>
            </div>

            <div className={`grid gap-5 ${showPreview ? 'grid-cols-1 xl:grid-cols-2' : 'grid-cols-1 max-w-2xl'}`}>

                {/* ── Form ── */}
                <div className="space-y-4">

                    {/* Solicitante */}
                    <div className={card}>
                        <h3 className={lbl + " !mb-0"}>Solicitante</h3>
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className={lbl}>Tipo de Pedido</label>
                                <select className={inp} value={data.Solicitacao || 'Telefone'} onChange={e => set('Solicitacao', e.target.value)}>
                                    <option value="Telefone">Telefone</option>
                                    <option value="E-mail">E-mail</option>
                                    <option value="Sistema">Sistema</option>
                                    <option value="Proativo">Proativo</option>
                                </select>
                            </div>
                            <div>
                                <label className={lbl}>Ramal</label>
                                <input className={inp} value={data.Ramal || ''} onChange={e => set('Ramal', e.target.value)} placeholder="Ex: 3210" />
                            </div>
                        </div>
                        <div>
                            <label className={lbl}>Nome do Solicitante</label>
                            <SolicitanteInput
                                name="Solicitante"
                                value={data.Solicitante || ''}
                                onChange={e => set('Solicitante', e.target.value)}
                                onSelect={s => {
                                    if (typeof s === 'string') s = { Nome: s, Ramal: '' };
                                    setData(p => ({ ...p, Solicitante: s.Nome, Ramal: s.Ramal || p.Ramal }));
                                }}
                            />
                        </div>
                        <div>
                            <label className={lbl}>Incidente RDS</label>
                            <input className={inp} value={data.IncidenteRds || ''} onChange={e => set('IncidenteRds', e.target.value)} placeholder="Número do incidente" />
                        </div>
                    </div>

                    {/* Contadores */}
                    <div className={card}>
                        <h3 className={lbl + " !mb-0"}>Contadores & Produção</h3>
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className={lbl}>Contador Inicial</label>
                                <input type="number" className={inp + " font-mono"} value={data.ContadorInicial || ''} onChange={e => set('ContadorInicial', e.target.value)} />
                            </div>
                            <div>
                                <label className={lbl}>Contador Final</label>
                                <input type="number" className={inp + " font-mono"} value={data.ContadorFinal || ''} onChange={e => set('ContadorFinal', e.target.value)} />
                            </div>
                        </div>
                        <div className="grid grid-cols-3 gap-3">
                            <div className="bg-slate-50 dark:bg-slate-800 rounded-lg p-3 text-center border border-slate-200 dark:border-slate-700">
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Produção</p>
                                <p className="text-xl font-bold text-slate-900 dark:text-white font-mono mt-1">{(data.Producao || 0).toLocaleString()}</p>
                            </div>
                            <div className="bg-slate-50 dark:bg-slate-800 rounded-lg p-3 text-center border border-slate-200 dark:border-slate-700">
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Resmas</p>
                                <p className="text-xl font-bold text-primary font-mono mt-1">{data.ProducaoResmas || '0.00'}</p>
                            </div>
                            <div>
                                <label className={lbl}>Análise F/V</label>
                                <input className={inp + " text-center font-bold uppercase"} value={data.AnaliseFV || ''} onChange={e => set('AnaliseFV', e.target.value)} placeholder="OK" />
                            </div>
                        </div>
                    </div>

                    {/* Insumos */}
                    <div className={card}>
                        <h3 className={lbl + " !mb-0"}>Insumos Entregues</h3>
                        <div className="grid grid-cols-4 gap-3">
                            {[
                                { key: 'TonerPreto', label: 'Toner BK', accent: 'text-slate-700 dark:text-slate-200' },
                                { key: 'TonerCiano', label: 'Toner CY', accent: 'text-cyan-600 dark:text-cyan-400' },
                                { key: 'TonerAmarelo', label: 'Toner YW', accent: 'text-yellow-600 dark:text-yellow-500' },
                                { key: 'TonerMagenta', label: 'Toner MG', accent: 'text-pink-600 dark:text-pink-400' },
                            ].map(({ key, label, accent }) => (
                                <div key={key}>
                                    <label className={`block text-[10px] font-bold uppercase tracking-wider mb-1.5 ${accent}`}>{label}</label>
                                    <input type="number" className={inp + " text-center font-bold"} value={data[key] || 0} onChange={e => set(key, e.target.value)} />
                                </div>
                            ))}
                        </div>
                        <div className="grid grid-cols-3 gap-3 pt-3 border-t border-slate-100 dark:border-slate-800">
                            {[
                                { key: 'A4', label: 'Papel A4 (Resmas)' },
                                { key: 'A3', label: 'Papel A3 (Resmas)' },
                                { key: 'Outros', label: 'Outros' },
                            ].map(({ key, label }) => (
                                <div key={key}>
                                    <label className={lbl}>{label}</label>
                                    <input type="number" className={inp + " text-center"} value={data[key] || 0} onChange={e => set(key, e.target.value)} />
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Observações & Validação */}
                    <div className={card}>
                        <h3 className={lbl + " !mb-0"}>Observações & Validação</h3>
                        <div>
                            <label className={lbl}>Observações</label>
                            <textarea rows={3} className={inp + " resize-none"} value={data.Obs || ''} onChange={e => set('Obs', e.target.value)} placeholder="Notas técnicas ou anomalias..." />
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className={lbl}>Funcionário</label>
                                <input className={inp} value={data.Funcionario || ''} onChange={e => set('Funcionario', e.target.value)} placeholder="Nome do técnico" />
                            </div>
                            <div>
                                <label className={lbl}>Competência</label>
                                <input className={inp} value={data.Competencia || ''} onChange={e => set('Competencia', e.target.value)} placeholder="MM/AAAA" />
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className={lbl}>Com Defeito?</label>
                                <select className={inp} value={data.ComDefeito || ''} onChange={e => set('ComDefeito', e.target.value)}>
                                    <option value="">Não</option>
                                    <option value="Sim">Sim</option>
                                </select>
                            </div>
                            <div>
                                <label className={lbl}>Recolha?</label>
                                <select className={inp} value={data.Recolha || ''} onChange={e => set('Recolha', e.target.value)}>
                                    <option value="">Não</option>
                                    <option value="Sim">Sim</option>
                                </select>
                            </div>
                        </div>
                    </div>
                </div>

                {/* ── Preview ── */}
                {showPreview && (
                    <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl p-5 shadow-sm overflow-auto">
                        <p className={lbl}>Pré-visualização do Protocolo</p>
                        <div className="bg-white rounded-lg overflow-hidden shadow border border-slate-200"
                            style={{ transform: 'scale(0.72)', transformOrigin: 'top left', width: '139%' }}>
                            <ProtocolPrint ref={printRef} data={data} />
                        </div>
                    </div>
                )}
            </div>

            {/* Hidden print target when preview is off */}
            {!showPreview && (
                <div className="hidden">
                    <ProtocolPrint ref={printRef} data={data} />
                </div>
            )}
        </div>
    );
}

import React, { forwardRef } from 'react';

// === HELPERS ===

// Standard Box Field (como os do topo do modelo)
const BoxField = ({ label, value, className = "", labelClass = "", valueClass = "", highlight = false }) => (
    <div className={`flex flex-col border-slate-400 p-1 px-2 ${className}`}>
        <span className={`text-[10px] text-slate-500 font-medium mb-1 ${labelClass}`}>{label}</span>
        <span className={`text-[14px] font-bold ${highlight ? 'text-[18px] uppercase font-black' : ''} text-slate-900 leading-tight ${valueClass}`}>
            {value || '-'}
        </span>
    </div>
);

// Indented List Field (como os de Local de Entrega)
const ListItem = ({ label, value, className = "" }) => (
    <div className={`flex items-center gap-1 py-0.5 ${className}`}>
        <span className="text-[10px] font-bold uppercase text-slate-500 min-w-[65px]">{label}:</span>
        <span className="text-[12px] font-bold text-slate-900 border-b border-dotted border-slate-300 flex-1">{value || ''}</span>
    </div>
);

// === LOGO HELPER ===
const SiteLogo = () => {
    const logoUrl = localStorage.getItem('proto_logo_url') || '';
    const logoMode = localStorage.getItem('proto_logo_mode') || 'text';
    const siteTitle = localStorage.getItem('proto_logo_title') || localStorage.getItem('site_title') || 'SUPPLY2026';

    const showLogo = (logoMode === 'logo' || logoMode === 'both_side' || logoMode === 'both_below' || logoMode === 'both') && logoUrl;
    const showText = logoMode === 'text' || logoMode === 'both_side' || logoMode === 'both_below' || logoMode === 'both' || !logoUrl;
    const isBelow = logoMode === 'both_below';

    return (
        <div className={`flex ${isBelow ? 'flex-col items-center gap-0.5' : 'items-center gap-2'}`}>
            {showLogo && (
                <img src={logoUrl} alt="Logo" className="h-9 w-auto object-contain" />
            )}
            {showText && (
                <h1 className={`font-black text-slate-700 tracking-tighter ${isBelow ? 'text-[11px] text-center' : 'text-[28px]'}`}>{siteTitle}</h1>
            )}
        </div>
    );
};

