import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Save, AlertTriangle, ArrowRight, CheckCircle2, XCircle, Eye, X, RefreshCcw } from 'lucide-react';

const FIELD_LABELS = {
    SERIE: 'Número de Série', TOTAL: 'Contador Total', DATA: 'Data de Leitura',
    '%BK': 'Toner Preto (%)', '%CY': 'Toner Ciano (%)', '%Mg': 'Toner Magenta (%)', '%Yw': 'Toner Amarelo (%)',
    A4RESMA: 'Meta de Papel (Resmas)', MEDIA: 'Média Mensal (Folhas)',
    FILA: 'Fila / Hostname', MODELOSIMPRESS: 'Modelo do Equipamento', STATUS: 'Status',
    LOCALINSTALACAO: 'Local de Instalação', RUAREF: 'Rua / Referência', CIDADE: 'Cidade',
    EMPRESA: 'Empresa / Unidade', PLANTAINSTALADA: 'Planta Instalada', AREA: 'Área / Setor',
    CONTRATO: 'Contrato', HORARIO: 'Horário', CONTATOSETOR: 'Contato do Setor',
    RAMAL: 'Ramal / Telefone', ALMOXARIFADO: 'Almoxarifado',
};
function fieldLabel(col) { return FIELD_LABELS[col] || FIELD_LABELS[col?.toUpperCase()] || col; }

export default function ColumnMappingModal({ isOpen, onClose, checkResult, onConfirm, isLoading }) {
    const [mapping, setMapping] = useState({});
    const [saveForFuture, setSaveForFuture] = useState(true);
    const [showPreview, setShowPreview] = useState(false);
    const [showNonEssential, setShowNonEssential] = useState(false);

    useEffect(() => {
        if (!checkResult) return;
        const { detected_columns = [], required_columns = [], optional_columns = [], current_mapping = {} } = checkResult;
        const initial = {};
        [...required_columns, ...optional_columns].forEach(sysCol => {
            const mappingKey = Object.keys(current_mapping).find(k => k.toUpperCase() === sysCol.toUpperCase());
            const fromMap = mappingKey ? current_mapping[mappingKey] : undefined;
            if (fromMap && detected_columns.includes(fromMap)) {
                initial[sysCol] = fromMap;
            } else {
                const direct = detected_columns.find(c => c.toUpperCase() === sysCol.toUpperCase());
                if (direct) initial[sysCol] = direct;
            }
        });
        setMapping(initial);
    }, [checkResult]);

    if (!isOpen || !checkResult) return null;

    const {
        detected_columns = [], required_columns = [], optional_columns = [],
        missing_essential_optional = [], temp_token, file_key, preview_data = []
    } = checkResult;

    const handleMapChange = (col, val) => setMapping(p => ({ ...p, [col]: val }));
    const handleIgnore = (col) => setMapping(p => ({ ...p, [col]: '' }));
    const handleUnignore = (col) => setMapping(p => { const n = { ...p }; delete n[col]; return n; });

    const isRequiredComplete = required_columns.every(col => !!mapping[col]);
    const undecidedEssential = missing_essential_optional.filter(col => mapping[col] === undefined);
    // canConfirm: only requires that REQUIRED fields are mapped.
    // Essential optional fields (FILA, MODELOSIMPRESS, etc.) are suggestions — user can ignore them.
    // The "Confirmar" button is enabled as soon as all required fields are mapped.
    const canConfirm = isRequiredComplete;

    const essentialOptionalToShow = optional_columns.filter(col =>
        missing_essential_optional.some(m => m.toUpperCase() === col.toUpperCase())
    );
    const nonEssentialOptional = optional_columns.filter(col => !essentialOptionalToShow.includes(col));

    const handleConfirm = () => onConfirm({ temp_token, file_key, mapping, save_for_future: saveForFuture });

    return createPortal(
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-end sm:items-center justify-center z-[9999] p-0 sm:p-4">
            {/* Modal container — flex column with fixed header/footer and scrollable body */}
            <div
                className="bg-white dark:bg-slate-900 rounded-t-2xl sm:rounded-xl shadow-2xl w-full max-w-4xl flex flex-col border border-slate-200 dark:border-slate-700"
                style={{ maxHeight: '92vh' }}
            >
                {/* ── HEADER (fixed) ── */}
                <div className="shrink-0 p-5 bg-slate-50 dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 flex justify-between items-start rounded-t-2xl sm:rounded-t-xl">
                    <div className="flex gap-3">
                        <div className="p-2.5 bg-amber-100 dark:bg-amber-900/20 text-amber-600 rounded-xl h-10 w-10 flex items-center justify-center shrink-0">
                            <AlertTriangle className="h-5 w-5" />
                        </div>
                        <div>
                            <h2 className="text-lg font-bold text-slate-900 dark:text-white">Mapeamento de Colunas</h2>
                            <p className="text-slate-500 dark:text-slate-400 text-xs mt-0.5">
                                Arquivo <span className="font-mono font-bold text-primary">{file_key}</span> — associe as colunas do CSV aos campos do sistema.
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 shrink-0 ml-2">
                        {preview_data.length > 0 && (
                            <button onClick={() => setShowPreview(true)}
                                className="flex items-center gap-1.5 px-2.5 py-1.5 text-xs font-bold text-slate-600 dark:text-slate-300 bg-white dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-lg hover:bg-slate-50 transition-colors">
                                <Eye className="h-3.5 w-3.5" /> Ver CSV
                            </button>
                        )}
                        {canConfirm
                            ? <span className="text-green-600 font-bold flex items-center gap-1 text-xs whitespace-nowrap"><CheckCircle2 size={14} /> Pronto</span>
                            : <span className="text-amber-600 font-bold flex items-center gap-1 text-xs whitespace-nowrap"><XCircle size={14} /> Pendente</span>
                        }
                    </div>
                </div>

                {/* ── BODY (scrollable) ── */}
                <div className="flex-1 overflow-y-auto min-h-0 p-5 space-y-5 bg-slate-50/50 dark:bg-slate-900">

                    {required_columns.length > 0 && (
                        <Section title="Campos Obrigatórios" dotColor="bg-red-500"
                            description="O arquivo não pode ser importado sem estes campos.">
                            {required_columns.map(col => (
                                <MappingRow key={col} sysCol={col} value={mapping[col]}
                                    detected_columns={detected_columns} variant="required" onChange={handleMapChange} />
                            ))}
                        </Section>
                    )}

                    {essentialOptionalToShow.length > 0 && (
                        <Section title="Campos do Protocolo" dotColor="bg-amber-400"
                            description="Estes campos preenchem o protocolo de entrega. Mapeie ou escolha Ignorar."
                            badge={undecidedEssential.length > 0 ? `${undecidedEssential.length} pendente${undecidedEssential.length > 1 ? 's' : ''}` : null}>
                            {essentialOptionalToShow.map(col => {
                                const isIgnored = mapping[col] === '';
                                const isUndecided = mapping[col] === undefined;
                                return (
                                    <MappingRow key={col} sysCol={col} value={mapping[col]}
                                        detected_columns={detected_columns}
                                        variant={isIgnored ? 'ignored' : isUndecided ? 'undecided' : 'recommended'}
                                        onChange={handleMapChange} onIgnore={handleIgnore}
                                        onUnignore={handleUnignore} isIgnored={isIgnored} />
                                );
                            })}
                        </Section>
                    )}

                    {nonEssentialOptional.length > 0 && (
                        <div>
                            <button onClick={() => setShowNonEssential(v => !v)}
                                className="text-xs font-bold text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 uppercase tracking-widest flex items-center gap-2 transition-colors">
                                <span>{showNonEssential ? '▾' : '▸'}</span>
                                Campos Adicionais ({nonEssentialOptional.length})
                            </button>
                            {showNonEssential && (
                                <div className="mt-3 space-y-2">
                                    {nonEssentialOptional.map(col => (
                                        <MappingRow key={col} sysCol={col} value={mapping[col]}
                                            detected_columns={detected_columns} variant="optional" onChange={handleMapChange} />
                                    ))}
                                </div>
                            )}
                        </div>
                    )}

                    <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700">
                        <h4 className="text-xs font-bold uppercase text-slate-400 mb-2">Colunas detectadas no CSV ({detected_columns.length})</h4>
                        <div className="flex flex-wrap gap-1.5">
                            {detected_columns.map(col => (
                                <span key={col} className="text-[11px] px-2 py-0.5 bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded border border-slate-200 dark:border-slate-600">{col}</span>
                            ))}
                        </div>
                    </div>
                </div>

                {/* ── FOOTER (fixed, always visible) ── */}
                <div className="shrink-0 p-4 bg-white dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700 flex justify-between items-center rounded-b-xl">
                    <label className="flex items-center gap-2 cursor-pointer select-none">
                        <input type="checkbox" checked={saveForFuture} onChange={e => setSaveForFuture(e.target.checked)}
                            className="h-4 w-4 rounded border-slate-300 accent-primary" />
                        <span className="text-xs text-slate-600 dark:text-slate-300">Lembrar para futuros uploads</span>
                    </label>
                    <div className="flex gap-3">
                        <button onClick={onClose}
                            className="px-4 py-2 text-sm font-medium text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-lg transition-colors">
                            Cancelar
                        </button>
                        <button onClick={handleConfirm} disabled={!canConfirm || isLoading}
                            className={`flex items-center gap-2 px-6 py-2.5 text-sm font-bold text-white rounded-lg transition-all shadow-md
                                ${canConfirm && !isLoading ? 'bg-primary hover:bg-primary/90 active:scale-95' : 'bg-slate-300 dark:bg-slate-600 cursor-not-allowed opacity-60'}`}>
                            {isLoading
                                ? <><RefreshCcw className="h-4 w-4 animate-spin" /> Processando...</>
                                : <><Save className="h-4 w-4" /> Confirmar Importação</>
                            }
                        </button>
                    </div>
                </div>
            </div>

            {/* Preview modal */}
            {showPreview && (
                <div className="fixed inset-0 z-[10000] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-white dark:bg-slate-900 w-full max-w-[95vw] h-[90vh] rounded-xl shadow-2xl flex flex-col overflow-hidden border border-slate-200 dark:border-slate-700">
                        <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 shrink-0">
                            <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
                                <Eye className="h-5 w-5 text-primary" /> Pré-visualização — {detected_columns.length} colunas
                            </h3>
                            <button onClick={() => setShowPreview(false)} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-colors">
                                <X className="h-5 w-5 text-slate-500" />
                            </button>
                        </div>
                        <div className="flex-1 overflow-auto p-4">
                            <table className="text-left text-sm text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-700 rounded-lg overflow-hidden min-w-max">
                                <thead className="bg-slate-100 dark:bg-slate-800 text-xs uppercase text-slate-500 font-bold sticky top-0">
                                    <tr>{detected_columns.map(col => <th key={col} className="px-4 py-3 border-b border-r border-slate-200 dark:border-slate-700 whitespace-nowrap last:border-r-0">{col}</th>)}</tr>
                                </thead>
                                <tbody className="divide-y divide-slate-200 dark:divide-slate-700 bg-white dark:bg-slate-900">
                                    {preview_data.map((row, i) => (
                                        <tr key={i} className="hover:bg-slate-50 dark:hover:bg-slate-800/50">
                                            {detected_columns.map(col => <td key={col} className="px-4 py-2 whitespace-nowrap border-r border-slate-100 dark:border-slate-800/50 last:border-r-0">{row[col]}</td>)}
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            )}
        </div>,
        document.body
    );
}

function Section({ title, dotColor, description, badge, children }) {
    return (
        <div className="space-y-2">
            <div className="flex items-center gap-2">
                <span className={`w-2 h-2 rounded-full shrink-0 ${dotColor}`} />
                <h3 className="text-xs font-bold uppercase tracking-wider text-slate-600 dark:text-slate-300">{title}</h3>
                {badge && <span className="text-[10px] font-bold bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 px-2 py-0.5 rounded-full border border-amber-200 dark:border-amber-800 animate-pulse">{badge}</span>}
            </div>
            {description && <p className="text-xs text-slate-400 dark:text-slate-500 ml-4">{description}</p>}
            <div className="space-y-2">{children}</div>
        </div>
    );
}

function MappingRow({ sysCol, value, detected_columns, variant, onChange, onIgnore, onUnignore, isIgnored }) {
    const label = fieldLabel(sysCol);
    const isMapped = !!value;

    const containerClass = {
        required: isMapped ? 'border-green-200 dark:border-green-900/50 bg-white dark:bg-slate-800' : 'border-red-200 dark:border-red-900/50 bg-red-50/30',
        recommended: isMapped ? 'border-green-200 dark:border-green-900/50 bg-white dark:bg-slate-800' : 'border-amber-200 dark:border-amber-900/50 bg-amber-50/30',
        undecided: 'border-amber-300 dark:border-amber-700 bg-amber-50/50 dark:bg-amber-950/20 ring-1 ring-amber-200 dark:ring-amber-800',
        ignored: 'border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50 opacity-60',
        optional: isMapped ? 'border-green-200 dark:border-green-900/50 bg-white dark:bg-slate-800' : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800',
    }[variant] || 'border-slate-200 bg-white dark:bg-slate-800';

    const badgeEl = {
        required: <span className="text-[9px] bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 px-1.5 py-0.5 rounded font-bold">Obrigatório</span>,
        recommended: <span className="text-[9px] bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 px-1.5 py-0.5 rounded font-bold">Protocolo</span>,
        undecided: <span className="text-[9px] bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 px-1.5 py-0.5 rounded font-bold animate-pulse">Decidir</span>,
        ignored: <span className="text-[9px] bg-slate-200 dark:bg-slate-700 text-slate-500 px-1.5 py-0.5 rounded">Ignorado</span>,
        optional: <span className="text-[9px] bg-slate-100 dark:bg-slate-700 text-slate-400 px-1.5 py-0.5 rounded">Opcional</span>,
    }[variant];

    return (
        <div className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${containerClass}`}>
            <div className="w-44 shrink-0">
                <div className="flex items-center gap-1.5 flex-wrap">
                    <span className="text-sm font-bold text-slate-800 dark:text-white">{label}</span>
                    {badgeEl}
                </div>
                <div className="text-[10px] text-slate-400 font-mono mt-0.5">{sysCol}</div>
            </div>
            <ArrowRight className="h-4 w-4 text-slate-300 dark:text-slate-600 shrink-0" />
            <div className="flex-1 min-w-0">
                {isIgnored ? (
                    <div className="flex items-center gap-2">
                        <span className="text-xs text-slate-400 italic flex-1">Campo ignorado</span>
                        <button onClick={() => onUnignore(sysCol)} className="text-xs text-primary hover:underline font-bold shrink-0">Desfazer</button>
                    </div>
                ) : (
                    <select value={value || ''} onChange={e => onChange(sysCol, e.target.value)}
                        className={`w-full p-2 rounded-md border text-sm outline-none transition-all appearance-none cursor-pointer
                            ${isMapped ? 'border-green-300 dark:border-green-700 bg-green-50 dark:bg-green-900/10 text-green-800 dark:text-green-300 font-medium'
                                : variant === 'required' ? 'border-red-300 dark:border-red-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-white'
                                : variant === 'undecided' ? 'border-amber-300 dark:border-amber-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-white'
                                : 'border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-200'}`}>
                        <option value="">— Selecione a coluna —</option>
                        {detected_columns.map(col => <option key={col} value={col}>{col}</option>)}
                    </select>
                )}
            </div>
            {(variant === 'recommended' || variant === 'undecided') && !isIgnored && onIgnore && (
                <button onClick={() => onIgnore(sysCol)}
                    className="shrink-0 text-xs text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 font-bold px-2 py-1 rounded hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors whitespace-nowrap">
                    Ignorar
                </button>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useToast } from '../../context/ToastContext';
import { useParams, useNavigate } from 'react-router-dom';
import { Upload, CheckCircle, AlertCircle, ArrowRight, Loader } from 'lucide-react';
import { useAuth } from '../../context/AuthProvider';
import api from '../../lib/api';

export default function ContractSetupWizard() {
    const { addToast } = useToast();
    const { contractId } = useParams();
    const navigate = useNavigate();
    const [status, setStatus] = useState(null);
    const [loading, setLoading] = useState(true);
    const [activeStep, setActiveStep] = useState(0);
    const processedRef = React.useRef(false);

    // Steps configuration
    const steps = [
        { id: 'welcome', title: 'Boas Vindas' },
        { id: 'mapa', title: 'Mapa de Equipamentos', key: 'MAPA' },
        { id: 'contadores', title: 'Contadores', key: 'CONTADORES' },
        { id: 'papel', title: 'Meta de Papel', key: 'PAPEL' },
        { id: 'finish', title: 'Conclusão' }
    ];
    const { user, updateActiveContract, refreshUser } = useAuth();

    useEffect(() => {
        const syncAndLoad = async () => {
            if (contractId && user) {
                // If contract is not in user list, refresh first
                if (!user.contracts.includes(contractId)) {

                    const updated = await refreshUser();
                    if (updated && !updated.contracts.includes(contractId) && user.role !== 'superadmin') {

                        // Fallback or alert? The App.jsx redirect might still hit
                    }
                }
                
                if (user.activeContract !== contractId) {

                    updateActiveContract(contractId);
                }
            }
            loadStatus();
        };
        
        syncAndLoad();
    }, [contractId, user?.activeContract, user?.contracts?.length]); // Modified dependency array

    const loadStatus = async () => {
        try {
            setLoading(true);
            const res = await api.get(`/admin/contracts/${contractId}/status`);
            setStatus(res.data);

            // Only determine initial step ONCE
            if (!processedRef.current) {
                determineInitialStep(res.data);
                processedRef.current = true;
            }
        } catch (e) {

            addToast("Erro ao carregar status do contrato", "error");
        } finally {
            setLoading(false);
        }
    };

    const determineInitialStep = (s) => {
        // If entirely new (no files), Start at Welcome (0)
        if (!s.has_mapa && !s.has_contadores && !s.has_papel) {
            setActiveStep(0);
            return;
        }

        // Resume logic
        if (!s.has_mapa) setActiveStep(1);
        else if (!s.has_contadores) setActiveStep(2);
        else if (!s.has_papel) setActiveStep(3);
        else setActiveStep(4); // Finish
    };

    const handleNext = () => setActiveStep(prev => Math.min(prev + 1, steps.length - 1));
    const handlePrev = () => setActiveStep(prev => Math.max(prev - 1, 0));

    if (loading) return <div className="p-8 flex items-center justify-center text-slate-500 dark:text-slate-400">Carregando...</div>;

    // Guard: if status failed to load, show error state
    if (!status) return (
        <div className="p-8 flex flex-col items-center justify-center gap-4 text-slate-500 dark:text-slate-400">
            <AlertCircle size={32} className="text-amber-500" />
            <p className="text-sm font-bold">Não foi possível carregar o status do contrato <span className="text-primary font-mono">{contractId}</span>.</p>
            <button onClick={loadStatus} className="px-4 py-2 bg-primary text-white rounded-lg text-xs font-bold hover:bg-primary/90 transition-all">Tentar novamente</button>
        </div>
    );

    return (
        <div className="flex flex-col items-center py-6 animate-in fade-in slide-in-from-bottom-4 duration-500 transition-colors">
            <div className="w-full bg-white dark:bg-slate-900 glass-surface shadow-2xl overflow-hidden border border-slate-200 dark:border-white/10 transition-colors duration-300">
                {/* Minimalist Header */}
                <div className="p-8 border-b border-slate-100 dark:border-white/5 transition-colors">
                    <div className="flex justify-between items-start mb-4">
                        <div className="space-y-1">
                            <h1 className="text-3xl font-bold font-display text-slate-900 dark:text-white tracking-tight">Configuração do Contrato</h1>
                            <p className="text-[#9D4DFF] font-mono text-xs uppercase tracking-widest">Contrato ID: {contractId}</p>
                        </div>
                        <button 
                            onClick={() => navigate('/admin')} 
                            className="text-slate-400 dark:text-white/40 hover:text-slate-900 dark:hover:text-white transition-all text-xs font-medium px-4 py-1.5 rounded-full border border-slate-200 dark:border-white/10 hover:bg-slate-50 dark:hover:bg-white/5"
                        >
                            Voltar
                        </button>
                    </div>
                    {/* Progress Indicator */}
                    <div className="flex gap-2">
                        {steps.map((s, i) => (
                            <div 
                                key={s.id} 
                                className={`h-1 flex-1 rounded-full transition-all duration-500 ${i <= activeStep ? 'bg-[#D18BFF] shadow-[0_0_10px_rgba(209,139,255,0.3)]' : 'bg-slate-100 dark:bg-white/10'}`}
                            />
                        ))}
                    </div>
                </div>

                {/* Content */}
                <div className="p-8 min-h-[400px]">
                    {activeStep === 0 && <WelcomeStep onNext={handleNext} status={status} />}
                    {activeStep === 1 && <UploadStep
                        title="Importar Mapa de Equipamentos"
                        description="Arquivo com todos os equipamentos, locais e modelos do contrato."
                        fileKey="MAPA"
                        contractId={contractId}
                        onSuccess={() => { loadStatus(); handleNext(); }}
                        hasFile={status?.has_mapa}
                    />}
                    {activeStep === 2 && <UploadStep
                        title="Importar Contadores"
                        description="Arquivo com as leituras atuais dos contadores de cada equipamento."
                        fileKey="CONTADORES"
                        contractId={contractId}
                        onSuccess={() => { loadStatus(); handleNext(); }}
                        hasFile={status?.has_contadores}
                    />}
                    {activeStep === 3 && <UploadStep
                        title="Importar Meta de Papel (Opcional)"
                        description="Arquivo com a quantidade de papel prevista para cada equipamento."
                        fileKey="PAPEL"
                        contractId={contractId}
                        onSuccess={() => { loadStatus(); handleNext(); }}
                        hasFile={status?.has_papel}
                        isOptional={true}
                        onSkip={handleNext}
                    />}
                    {activeStep === 4 && <FinishStep navigate={navigate} contractId={contractId} />}
                </div>

                {/* Footer Navigation */}
                <div className="bg-slate-50 dark:bg-white/5 p-4 border-t border-slate-100 dark:border-white/5 flex justify-between items-center px-8 transition-colors">
                    <button
                        onClick={handlePrev}
                        disabled={activeStep === 0}
                        className="px-4 py-2 text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors disabled:opacity-20 text-sm font-medium"
                    >
                        Anterior
                    </button>
                    <span className="text-[10px] font-mono text-slate-400 dark:text-white/20 uppercase tracking-widest">Etapa {activeStep + 1} de {steps.length}</span>
                </div>
            </div>
        </div>
    );
}

function WelcomeStep({ onNext, status }) {
    return (
        <div className="text-center space-y-8 py-4">
            <div className="mx-auto w-20 h-20 bg-[#D18BFF]/10 text-[#D18BFF] rounded-full flex items-center justify-center animate-pulse">
                <AlertCircle size={40} />
            </div>
            <div className="space-y-2">
                <h2 className="text-2xl font-bold text-slate-800 dark:text-white font-display">Inicialização do Contrato</h2>
                <p className="text-slate-500 dark:text-slate-400 max-w-md mx-auto text-sm leading-relaxed">
                    Para ativar este contrato, precisamos importar os arquivos de dados.
                </p>
            </div>

            <div className="grid grid-cols-3 gap-4 max-w-md mx-auto">
                <StatusCard label="Mapa" done={status?.has_mapa} color="#4D91FF" />
                <StatusCard label="Contadores" done={status?.has_contadores} color="#D18BFF" />
                <StatusCard label="Papel" done={status?.has_papel} color="#4DFF88" />
            </div>

            <button onClick={onNext} className="bg-[#D18BFF] text-black px-8 py-3 rounded-full font-bold shadow-xl hover:bg-[#D18BFF]/90 transition-all flex items-center justify-center mx-auto hover:scale-105 active:scale-95">
                Começar <ArrowRight className="ml-2" size={18} />
            </button>
        </div>
    );
}

function StatusCard({ label, done, color }) {
    return (
        <div className={`p-4 rounded-xl border transition-all duration-500 ${done ? 'bg-slate-50 dark:bg-white/5 border-slate-200 dark:border-white/20' : 'bg-slate-50/50 dark:bg-white/2 border-slate-100 dark:border-white/5 opacity-40'}`}>
            <div className="font-bold text-xs uppercase tracking-tighter mb-1" style={{ color: done ? color : 'inherit' }}>{label}</div>
            <div className="text-[10px] font-mono text-slate-400 opacity-50">{done ? 'OK' : 'Pendente'}</div>
        </div>
    );
}

import ColumnMappingModal from './ColumnMappingModal';

function UploadStep({ title, description, fileKey, contractId, onSuccess, hasFile, isOptional, onSkip }) {
    const { addToast } = useToast();
    const [uploading, setUploading] = useState(false);
    const [mappingData, setMappingData] = useState(null); // { temp_token, detected_columns, ... }

    const handleFile = async (e) => {
        const file = e.target.files[0];
        if (!file) {
            return;
        }



        const formData = new FormData();
        formData.append('file', file);
        e.target.value = null; // Reset input

        try {
            setUploading(true);
            const res = await api.post(`/upload/csv/${fileKey}`, formData, {
                params: {
                    contract_id: contractId
                },
                headers: { 'Content-Type': 'multipart/form-data' }
            });

            if (res.data.status === 'success') {
                onSuccess();
            } else if (res.data.status === 'mapping_required') {
                setMappingData(res.data);
            } else {
                addToast("Resposta desconhecida do servidor: " + JSON.stringify(res.data), "info");
            }
        } catch (err) {

            addToast("Erro no upload: " + (err.response?.data?.detail || err.message), "error");
        } finally {
            setUploading(false);
        }
    };

    const handleMappingConfirm = async (payload) => {
        try {
            setUploading(true);
            const res = await api.post(`/upload/confirm-mapping`, payload, {
                params: { contract_id: contractId }
            });
            if (res.data.status === 'success') {
                setMappingData(null);
                onSuccess();
            } else {
                addToast("Erro ao aplicar mapeamento: resposta inesperada do servidor.", "error");
            }
        } catch (err) {
            addToast("Erro ao aplicar mapeamento: " + (err.response?.data?.detail || err.message), "error");
        } finally {
            setUploading(false);
        }
    };

    return (
        <div className="space-y-6 max-w-lg mx-auto">
            <h2 className="text-xl font-bold text-slate-800 dark:text-white">{title}</h2>
            <p className="text-slate-600 dark:text-slate-400">{description}</p>

            {hasFile && (
                <div className="bg-green-50 dark:bg-green-900/30 border border-green-200 dark:border-green-700 p-4 rounded-lg flex items-center gap-3 text-green-700 dark:text-green-400 mb-4">
                    <CheckCircle size={20} />
                    <div>
                        <span className="font-bold">Arquivo já importado.</span>
                        <div className="text-xs">Você pode importar novamente para atualizar.</div>
                    </div>
                </div>
            )}

            <div className={`border-2 border-dashed border-slate-300 dark:border-slate-600 rounded-xl p-8 text-center hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors relative ${uploading ? 'opacity-50 pointer-events-none' : ''}`}>
                <input
                    type="file"
                    onChange={handleFile}
                    className="absolute inset-0 opacity-0 cursor-pointer"
                    accept=".csv,.xlsx"
                    disabled={uploading}
                />
                <div className="flex flex-col items-center gap-3 text-slate-500 dark:text-slate-400">
                    {uploading ? <Loader className="animate-spin text-primary" size={32} /> : <Upload size={32} />}
                    <span className="font-medium">
                        {uploading ? 'Processando...' : 'Clique ou arraste o arquivo aqui'}
                    </span>
                    <span className="text-xs text-slate-400 dark:text-slate-500">Suporta .csv e .xlsx</span>
                </div>
            </div>

            <div className="flex justify-between items-center pt-4">
                {isOptional ? (
                    <button onClick={onSkip} className="text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 text-sm">
                        Pular esta etapa
                    </button>
                ) : <div />}

                {hasFile && (
                    <button onClick={onSuccess} className="bg-green-600 text-white px-6 py-2 rounded shadow-sm hover:bg-green-700 flex items-center gap-2">
                        Próximo <ArrowRight size={16} />
                    </button>
                )}
            </div>

            {/* Modal */}
            <ColumnMappingModal
                isOpen={!!mappingData}
                onClose={() => setMappingData(null)}
                checkResult={mappingData}
                onConfirm={handleMappingConfirm}
            />
        </div>
    );
}

function FinishStep({ navigate, contractId }) {
    const { addToast } = useToast();
    return (
        <div className="text-center space-y-6">
            <div className="mx-auto w-16 h-16 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-full flex items-center justify-center">
                <CheckCircle size={32} />
            </div>
            <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Tudo Pronto!</h2>
            <p className="text-slate-600 dark:text-slate-400 max-w-lg mx-auto">
                O contrato {contractId} está pronto para uso. Você já pode criar pedidos e gerenciar rotas.
            </p>
            <button onClick={() => navigate('/')} className="bg-primary text-white px-8 py-3 rounded-xl font-bold shadow-lg hover:bg-primary/90 transition-all hover:scale-105 active:scale-95 mt-8">
                Ir para o Início
            </button>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useToast } from '../../context/ToastContext';
import { useNavigate } from 'react-router-dom';
import { Save, Loader, AlertTriangle, History, X, UserPlus } from 'lucide-react';
import api from '../../lib/api';
import { cn } from '../../lib/utils';
import SolicitanteInput from './SolicitanteInput';
import SolicitanteFormModal from '../Solicitantes/SolicitanteFormModal';

// ─── Estilos responsivos ──────────────────────────────────────────────────────
// Contraste melhorado: slate-700 no light, slate-200 no dark
const inp = "w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded px-3 py-2 text-sm text-slate-900 dark:text-white placeholder-slate-400 focus:border-primary focus:ring-1 focus:ring-primary/20 outline-none transition-all";
const lbl = "block text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-1 leading-none";
const sec = "bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg p-3 shadow-sm";

export default function FormStep({ data, type, activeContract }) {
    const { addToast } = useToast();
    const navigate = useNavigate();
    const [saving, setSaving] = useState(false);
    const [showHistory, setShowHistory] = useState(false);
    const [showAddSolicitante, setShowAddSolicitante] = useState(false);

    const suggestion = data.suggestion || {};
    const warnings = suggestion.warnings || [];
    const [isColorOverride, setIsColorOverride] = useState(data.is_color || false);

    const [form, setForm] = useState({
        protocol: '(Novo)',
        date: new Date().toLocaleDateString('pt-BR'),
        status: data.equipment.Status || data.equipment.STATUS || '',
        serie: data.equipment.Serie || '',
        fila: data.equipment.Fila || '',
        modelo: data.equipment.ModeloSimpress || '',
        empresa: data.equipment.Empresa || '',
        plantaInstalada: data.equipment.PlantaInstalada || '',
        localInstalacao: data.equipment.LocalInstalacao || '',
        ruaRef: data.equipment.RuaRef || '',
        cidade: data.equipment.Cidade || '',
        area: data.equipment.Area || '',
        horario: data.equipment.Horario || '',
        contrato: data.equipment.Contrato || '',
        contatoSetor: data.equipment.ContatoSetor || data.equipment.Contato || '',
        ramalEquip: data.equipment.Ramal || '',
        comDefeito: '',
        analiseFV: '',
        recolha: '',
        solicitante: '',
        telefone: '',
        resmas: suggestion.resmas || 1,
        tonerBk: suggestion.toner_bk || 0,
        tonerCy: suggestion.toner_cy || 0,
        tonerMg: suggestion.toner_mg || 0,
        tonerYw: suggestion.toner_yw || 0,
        counterInitial: data.last_delivery?.counter || 0,
        counterFinal: data.counters?.counter_total || '',
        incidente: '',
        emprestimo: 'Nenhum',
        origem: '',
        obs: '',
    });

    const [extraMappings, setExtraMappings] = useState([]);
    const [extraValues, setExtraValues] = useState({});
    const [production, setProduction] = useState(0);

    useEffect(() => {
        const loadMappings = async () => {
            try {
                const res = await api.get('/data/mappings');
                const mapaExtras = res.data.MAPA?.EXTRAS || [];
                setExtraMappings(mapaExtras);
                const initialExtras = {};
                mapaExtras.forEach(ex => {
                    initialExtras[ex.key] = data.equipment[ex.header] || data.equipment[ex.key] || '';
                });
                setExtraValues(initialExtras);
            } catch { /* silent */ }
        };
        loadMappings();
    }, [data.equipment]);

    useEffect(() => {
        const ini = parseInt(form.counterInitial || 0) || 0;
        const fin = parseInt(form.counterFinal || 0) || 0;
        setProduction(Math.max(0, fin - ini));
    }, [form.counterInitial, form.counterFinal]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setForm(prev => ({ ...prev, [name]: value }));
    };

    const handleSave = async () => {
        setSaving(true);
        try {
            const payload = {
                ...form,
                ...extraValues,
                production,
                solicitacao: type,
                extras_meta: extraMappings,
                endereco: form.localInstalacao,
                rua: form.ruaRef,
                contato: form.contatoSetor,
                ramal: form.ramalEquip || form.telefone,
            };
            await api.post(`/data/entregas?contract_id=${activeContract}`, payload);
            addToast('Protocolo gerado com sucesso!', 'success');
            navigate('/');
        } catch {
            addToast('Erro ao salvar protocolo.', 'error');
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="flex flex-col gap-2 h-full overflow-hidden">

            {/* ── Alerta ── */}
            {warnings.length > 0 && (
                <div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-xl px-4 py-2.5 flex items-center gap-3 shrink-0">
                    <AlertTriangle className="h-4 w-4 text-amber-600 dark:text-amber-400 shrink-0" />
                    <p className="text-xs font-bold text-amber-700 dark:text-amber-400 uppercase tracking-tight">
                        {warnings.join(' · ')}
                    </p>
                </div>
            )}

            {/* ── Informações do Equipamento (read-only) — cresce em telas grandes ── */}
            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg px-4 py-3 shadow-sm shrink-0">
                <div className="grid grid-cols-6 gap-x-4 gap-y-2">
                    {/* Linha 1 */}
                    <div>
                        <span className={lbl}>Série</span>
                        <span className="text-sm font-bold text-primary font-mono block">{form.serie}</span>
                    </div>
                    <div>
                        <span className={lbl}>Modelo</span>
                        <span className="text-sm font-bold text-slate-800 dark:text-white block">{form.modelo}</span>
                    </div>
                    <div>
                        <span className={lbl}>Fila</span>
                        <span className="text-sm font-bold text-slate-800 dark:text-white font-mono block">{form.fila}</span>
                    </div>
                    <div>
                        <span className={lbl}>Cidade</span>
                        <span className="text-sm text-slate-800 dark:text-slate-100 block">{form.cidade}</span>
                    </div>
                    <div>
                        <span className={lbl}>Horário</span>
                        <span className="text-sm text-slate-800 dark:text-slate-100 block">{form.horario || '—'}</span>
                    </div>
                    <div>
                        <span className={lbl}>Contrato</span>
                        <span className="text-sm text-slate-800 dark:text-slate-100 block">{form.contrato || '—'}</span>
                    </div>
                    {/* Linha 2 */}
                    <div className="col-span-2">
                        <span className={lbl}>Empresa</span>
                        <span className="text-sm font-bold text-slate-900 dark:text-white uppercase block">{form.empresa}</span>
                    </div>
                    <div className="col-span-2">
                        <span className={lbl}>Local de Instalação</span>
                        <span className="text-sm text-slate-800 dark:text-slate-100 block">{form.localInstalacao || '—'}</span>
                    </div>
                    <div>
                        <span className={lbl}>Rua / Ref</span>
                        <span className="text-sm text-slate-800 dark:text-slate-100 block">{form.ruaRef || '—'}</span>
                    </div>
                    <div>
                        <span className={lbl}>Área</span>
                        <span className="text-sm text-slate-800 dark:text-slate-100 block">{form.area || '—'}</span>
                    </div>
                    {/* Linha 3 */}
                    <div className="col-span-2">
                        <span className={lbl}>Contato do Setor</span>
                        <span className="text-sm font-semibold text-slate-800 dark:text-slate-100 block">{form.contatoSetor || '—'}</span>
                    </div>
                    <div>
                        <span className={lbl}>Ramal</span>
                        <span className="text-sm font-mono text-slate-800 dark:text-slate-100 block">{form.ramalEquip || '—'}</span>
                    </div>
                    <div className="col-span-2">
                        <span className={lbl}>Planta Instalada</span>
                        <span className="text-sm text-slate-800 dark:text-slate-100 block">{form.plantaInstalada || '—'}</span>
                    </div>
                </div>
            </div>

            {/* ── Formulário principal: 3 colunas ── */}
            <div className="grid grid-cols-3 gap-2 flex-1 min-h-0">

                {/* Coluna 1: Solicitante (flex-1) + Contadores (fixo) */}
                <div className="flex flex-col gap-1.5 min-h-0">
                    {/* Solicitante cresce para preencher */}
                    <div className={sec + " flex-1 min-h-0 flex flex-col"}>
                        <h3 className={lbl + " mb-1 shrink-0"}>Solicitante</h3>
                        <div className="flex flex-col gap-1.5 overflow-y-auto custom-scrollbar">
                            <div className="space-y-1.5">
                                <div className="grid grid-cols-2 gap-1">
                                    <div>
                                        <label className={lbl}>Canal de Solicitação</label>
                                        <select className={inp} name="solicitacao" value={form.solicitacao || type || 'Telefone'} onChange={handleChange}>
                                            <option value="Telefone">Telefone</option>
                                            <option value="E-mail">E-mail</option>
                                            <option value="Sistema">Sistema</option>
                                            <option value="Proativo">Proativo</option>
                                        </select>
                                    </div>
                                    <div>
                                        <label className={lbl}>Ramal</label>
                                        <input className={inp} name="telefone" value={form.telefone} onChange={handleChange} placeholder="Ex: 3210" />
                                    </div>
                                </div>
                                <div>
                                    <div className="flex items-center justify-between mb-1">
                                        <label className={lbl + " !mb-0"}>Nome do Solicitante</label>
                                        <button
                                            type="button"
                                            onClick={() => setShowAddSolicitante(true)}
                                            className="flex items-center gap-1 text-[9px] font-bold text-primary hover:text-primary/80 transition-colors"
                                            title="Adicionar novo solicitante"
                                        >
                                            <UserPlus size={12} /> Novo
                                        </button>
                                    </div>
                                    <SolicitanteInput
                                        name="solicitante"
                                        value={form.solicitante}
                                        onChange={handleChange}
                                        onSelect={s => {
                                            if (typeof s === 'string') s = { Nome: s, Ramal: '' };
                                            setForm(p => ({
                                                ...p,
                                                solicitante: s.Nome || s.Solicitante || '',
                                                telefone: s.Ramal || p.telefone,
                                                ramalEquip: p.ramalEquip || s.Ramal || '',
                                            }));
                                        }}
                                    />
                                </div>
                                <div>
                                    <label className={lbl}>Nº do Chamado</label>
                                    <input className={inp} name="incidente" value={form.incidente} onChange={handleChange} placeholder="Número do incidente" />
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Contadores — fixo no fundo */}
                    <div className={sec + " shrink-0"}>
                        <h3 className={lbl + " mb-1"}>Contadores</h3>
                        <div className="grid grid-cols-3 gap-1">
                            <div>
                                <label className={lbl}>Inicial</label>
                                <div className="bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded px-2 py-1.5 text-xs font-mono font-bold text-slate-500 dark:text-slate-400 truncate">
                                    {parseInt(form.counterInitial || 0).toLocaleString()}
                                </div>
                            </div>
                            <div>
                                <label className={lbl}>Final</label>
                                <input type="number" className={inp + " font-mono"} name="counterFinal" value={form.counterFinal} onChange={handleChange} placeholder="0" />
                            </div>
                            <div>
                                <label className={lbl}>Produção</label>
                                <div className="bg-primary/10 border border-primary/20 rounded px-2 py-1.5 text-xs font-mono font-bold text-primary text-center">
                                    {production.toLocaleString()}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Coluna 2: Insumos — distribui conteúdo verticalmente */}
                <div className={sec + " flex flex-col min-h-0"}>
                    <h3 className={lbl + " mb-1.5 shrink-0"}>Insumos</h3>

                    <div className="flex flex-col gap-2 flex-1 min-h-0 justify-between">
                        {/* Papel A4 */}
                        <div>
                            <label className={lbl}>Papel A4 (Resmas)</label>
                            <div className="flex items-center gap-1">
                                <button type="button" onClick={() => setForm(p => ({ ...p, resmas: Math.max(0, (parseInt(p.resmas) || 0) - 1) }))}
                                    className="w-8 h-8 flex items-center justify-center bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-white font-bold transition-all text-base shrink-0">−</button>
                                <input type="number" name="resmas" value={form.resmas || 0} onChange={handleChange}
                                    className={inp + " text-center text-xl font-black text-slate-900 dark:text-white py-1.5"} />
                                <button type="button" onClick={() => setForm(p => ({ ...p, resmas: (parseInt(p.resmas) || 0) + 1 }))}
                                    className="w-8 h-8 flex items-center justify-center bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-white font-bold transition-all text-base shrink-0">+</button>
                            </div>
                            <p className="text-[9px] text-slate-500 dark:text-slate-400 mt-0.5 font-medium">Média: {data.papel_stats?.media || 0} resmas</p>
                        </div>

                        {/* Papel A3 */}
                        <div>
                            <label className={lbl}>Papel A3 (Resmas)</label>
                            <input type="number" className={inp + " text-center text-lg font-black text-slate-900 dark:text-white"} name="a3" value={form.a3 || 0} onChange={handleChange} />
                        </div>

                        {/* Toners */}
                        <div className="border-t border-slate-100 dark:border-slate-800 pt-1.5">
                            <div className="flex items-center justify-between mb-1">
                                <label className={lbl + " !mb-0"}>Toners</label>
                                <label className="flex items-center gap-1.5 cursor-pointer">
                                    <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Colorido</span>
                                    <div className="relative">
                                        <input type="checkbox" checked={isColorOverride} onChange={e => setIsColorOverride(e.target.checked)} className="sr-only peer" />
                                        <div className="w-7 h-4 bg-slate-200 dark:bg-slate-700 rounded-full peer peer-checked:bg-primary transition-all after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:after:translate-x-3"></div>
                                    </div>
                                </label>
                            </div>
                            <div className="grid grid-cols-2 gap-1">
                                <div>
                                    <label className="block text-[9px] font-bold text-slate-700 dark:text-slate-200 uppercase tracking-widest mb-0.5">BK</label>
                                    <input type="number" className={inp + " text-center text-lg font-black text-slate-900 dark:text-white"} name="tonerBk" value={form.tonerBk || 0} onChange={handleChange} />
                                </div>
                                {isColorOverride && (<>
                                    <div>
                                        <label className="block text-[9px] font-bold text-cyan-600 dark:text-cyan-400 uppercase tracking-widest mb-0.5">CY</label>
                                        <input type="number" className={inp + " text-center text-lg font-black text-slate-900 dark:text-white"} name="tonerCy" value={form.tonerCy || 0} onChange={handleChange} />
                                    </div>
                                    <div>
                                        <label className="block text-[9px] font-bold text-pink-600 dark:text-pink-400 uppercase tracking-widest mb-0.5">MG</label>
                                        <input type="number" className={inp + " text-center text-lg font-black text-slate-900 dark:text-white"} name="tonerMg" value={form.tonerMg || 0} onChange={handleChange} />
                                    </div>
                                    <div>
                                        <label className="block text-[9px] font-bold text-yellow-600 dark:text-yellow-400 uppercase tracking-widest mb-0.5">YW</label>
                                        <input type="number" className={inp + " text-center text-lg font-black text-slate-900 dark:text-white"} name="tonerYw" value={form.tonerYw || 0} onChange={handleChange} />
                                    </div>
                                </>)}
                            </div>
                        </div>

                        {/* Outros */}
                        <div>
                            <label className={lbl}>Outros</label>
                            <input type="number" className={inp + " text-center text-lg font-black text-slate-900 dark:text-white"} name="outros" value={form.outros || 0} onChange={handleChange} />
                        </div>
                    </div>
                </div>

                {/* Coluna 3: Validação — distribui verticalmente */}
                <div className={sec + " flex flex-col min-h-0"}>
                    <h3 className={lbl + " mb-1.5 shrink-0"}>Validação</h3>

                    <div className="flex flex-col gap-2 flex-1 min-h-0 justify-between">
                        <div className="grid grid-cols-2 gap-1.5">
                            <div>
                                <label className={lbl}>Análise Física/Visual</label>
                                <input className={inp + " text-center font-bold uppercase"} name="analiseFV" value={form.analiseFV} onChange={handleChange} placeholder="OK" />
                            </div>
                            <div>
                                <label className={lbl}>Com Defeito?</label>
                                <select className={inp} name="comDefeito" value={form.comDefeito} onChange={handleChange}>
                                    <option value="">Não</option>
                                    <option value="Sim">Sim</option>
                                </select>
                            </div>
                            <div>
                                <label className={lbl}>Recolher Equipamento?</label>
                                <select className={inp} name="recolha" value={form.recolha} onChange={handleChange}>
                                    <option value="">Não</option>
                                    <option value="Sim">Sim</option>
                                </select>
                            </div>
                            <div>
                                <label className={lbl}>Empréstimo de Equipamento</label>
                                <select className={inp} name="emprestimo" value={form.emprestimo} onChange={handleChange}>
                                    <option value="Nenhum">Nenhum</option>
                                    <option value="Emprestado">Emprestado</option>
                                    <option value="Recebido">Recebido</option>
                                </select>
                            </div>
                        </div>

                        {form.emprestimo !== 'Nenhum' && (
                            <div>
                                <label className={lbl}>Origem / Destino</label>
                                <input className={inp} name="origem" value={form.origem} onChange={handleChange} placeholder="Emprestado de/para..." />
                            </div>
                        )}

                        {/* Observações ocupa o espaço restante */}
                        <div className="flex-1 flex flex-col min-h-0">
                            <label className={lbl}>Observações</label>
                            <textarea
                                className={inp + " resize-none flex-1 min-h-[60px]"}
                                name="obs"
                                value={form.obs}
                                onChange={handleChange}
                                placeholder="Notas técnicas..."
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* ── Barra de ações ── */}
            <div className="flex items-center justify-between pt-2 border-t border-slate-200 dark:border-slate-800 shrink-0">
                <button
                    type="button"
                    onClick={() => setShowHistory(true)}
                    className="flex items-center gap-2 px-4 py-2 text-xs font-bold text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-all"
                >
                    <History className="h-4 w-4" /> Ver Histórico
                </button>
                <div className="flex gap-2">
                    <button
                        type="button"
                        onClick={() => navigate('/')}
                        className="px-4 py-2 text-xs font-bold text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-white transition-colors"
                    >
                        Cancelar
                    </button>
                    <button
                        type="button"
                        onClick={handleSave}
                        disabled={saving}
                        style={{ backgroundColor: 'rgb(var(--color-primary))', color: 'white' }}
                        className="flex items-center gap-2 px-6 py-2 text-xs font-bold rounded-lg hover:opacity-90 transition-all shadow-md active:scale-95 disabled:opacity-50"
                    >
                        {saving ? <Loader className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                        {saving ? 'Gerando...' : 'Gerar Protocolo'}
                    </button>
                </div>
            </div>

            {/* ── Modal de Histórico ── */}
            {showHistory && (
                <HistoryModal
                    history={data.history || []}
                    onClose={() => setShowHistory(false)}
                    serie={form.serie}
                />
            )}

            {/* ── Modal de Novo Solicitante ── */}
            {showAddSolicitante && (
                <SolicitanteFormModal
                    mode="create"
                    onSave={async ({ nome, ramal, obs }) => {
                        await api.post('/data/solicitantes', { nome, ramal, obs }, { params: { contract_id: activeContract } });
                        setForm(p => ({ ...p, solicitante: nome, telefone: ramal || p.telefone }));
                    }}
                    onClose={() => setShowAddSolicitante(false)}
                />
            )}
        </div>
    );
}

function HistoryModal({ history, onClose, serie }) {
    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-white dark:bg-slate-900 w-full max-w-4xl max-h-[85vh] flex flex-col rounded-2xl border border-slate-200 dark:border-slate-800 shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
                <div className="flex items-center justify-between px-6 py-4 border-b border-slate-200 dark:border-slate-700">
                    <div>
                        <h2 className="text-lg font-bold text-slate-800 dark:text-white">Histórico de Entregas</h2>
                        <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">Série: <span className="font-bold text-primary">{serie}</span></p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors text-slate-400">
                        <X className="h-5 w-5" />
                    </button>
                </div>

                <div className="flex-1 overflow-auto custom-scrollbar">
                    {history.length === 0 ? (
                        <div className="flex items-center justify-center py-20 text-slate-400 text-sm">
                            Nenhuma entrega anterior encontrada.
                        </div>
                    ) : (
                        <table className="w-full text-left text-xs min-w-[800px]">
                            <thead className="bg-slate-50 dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 sticky top-0">
                                <tr>
                                    {['Protocolo', 'Data', 'Contador Final', 'Produção', 'A4', 'Toners', 'Solicitante'].map(h => (
                                        <th key={h} className="px-4 py-3 font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest text-[9px]">{h}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                {history.map((item, idx) => (
                                    <tr key={idx} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                                        <td className="px-4 py-3 font-bold text-primary">#{item.Protocolo}</td>
                                        <td className="px-4 py-3 text-slate-500 dark:text-slate-400">{item.DataEntrega || item.Data}</td>
                                        <td className="px-4 py-3 font-mono text-slate-800 dark:text-white">{item.ContadorFinal || item.ContFinal || '—'}</td>
                                        <td className="px-4 py-3">
                                            <span className="bg-emerald-50 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 px-2 py-0.5 rounded-full text-[10px] font-bold border border-emerald-100 dark:border-emerald-800">
                                                {item.Producao || '—'}
                                            </span>
                                        </td>
                                        <td className="px-4 py-3">
                                            <span className="bg-primary/10 text-primary px-2 py-0.5 rounded-full text-[10px] font-bold border border-primary/20">
                                                {item.A4 || 0}
                                            </span>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex gap-1">
                                                {[
                                                    { val: item.TonerPreto || item.TonerBk, cls: 'bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300' },
                                                    { val: item.TonerCiano || item.TonerCy, cls: 'bg-cyan-50 dark:bg-cyan-900/30 text-cyan-600 dark:text-cyan-400' },
                                                    { val: item.TonerMagenta || item.TonerMg, cls: 'bg-pink-50 dark:bg-pink-900/30 text-pink-600 dark:text-pink-400' },
                                                    { val: item.TonerAmarelo || item.TonerYw, cls: 'bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400' },
                                                ].map((t, i) => (
                                                    <span key={i} className={cn('w-6 h-6 flex items-center justify-center rounded text-[10px] font-bold border border-slate-200 dark:border-slate-700', t.cls)}>
                                                        {t.val || 0}
                                                    </span>
                                                ))}
                                            </div>
                                        </td>
                                        <td className="px-4 py-3 text-slate-700 dark:text-slate-300 font-medium">{item.Solicitante || '—'}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>

                <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-700 flex justify-end bg-slate-50 dark:bg-slate-900/50">
                    <button onClick={onClose} className="px-5 py-2 bg-primary text-white rounded-lg font-bold text-xs hover:bg-primary/90 transition-all">
                        Fechar
                    </button>
                </div>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { FileText, ArrowRight, Loader, AlertCircle } from 'lucide-react';
import { useAuth } from '../../context/AuthProvider';
import api from '../../lib/api';

export default function FullPageWizard() {
    const navigate = useNavigate();
    const { updateActiveContract } = useAuth();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);

    const [formData, setFormData] = useState({
        id: '',
        name: '',
        description: ''
    });

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError(null);
        setLoading(true);

        try {
            // 1. Create Contract
            // Endpoint matches backend/routers/admin.py: @router.post("/contracts") expect {id, name, description}
            await api.post('admin/contracts', formData);

            // 2. Redirect to Setup Wizard -> setup-contract (Base Configuration)
            navigate(`/setup-contract/${formData.id}`);

        } catch (err) {

            setError(err.response?.data?.detail || "Erro ao criar contrato. Verifique se o ID já existe.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="flex flex-col items-center justify-center py-10 px-4 animate-in fade-in duration-700">
            <div className="w-full max-w-md bg-white dark:bg-slate-900 glass-surface shadow-2xl overflow-hidden border border-slate-200 dark:border-white/10 p-1 transition-colors">
                {/* Header */}
                <div className="p-8 text-center border-b border-slate-100 dark:border-white/5 space-y-4 transition-colors">
                    <div className="mx-auto w-16 h-16 bg-[#D18BFF]/20 rounded-full flex items-center justify-center border border-[#D18BFF]/30">
                        <FileText size={28} className="text-[#D18BFF]" />
                    </div>
                    <div>
                        <h1 className="text-3xl font-bold text-slate-900 dark:text-white font-display tracking-tight">New Contract</h1>
                        <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">Configuração inicial do Supply 2026.</p>
                    </div>
                </div>

                {/* Form */}
                <form onSubmit={handleSubmit} className="p-8 space-y-6">
                    {error && (
                        <div className="bg-red-500/10 border border-red-500/20 text-[#FF4D4D] p-3 rounded-xl text-xs flex items-start gap-2 animate-pulse">
                            <AlertCircle size={16} className="shrink-0 mt-0.5" />
                            <span>{error}</span>
                        </div>
                    )}

                    <div className="space-y-5">
                        <div className="space-y-1">
                            <label className="block text-[10px] font-mono uppercase tracking-[0.2em] text-[#9D4DFF]">
                                Node Identifier (ID)
                            </label>
                            <input
                                type="text"
                                required
                                value={formData.id}
                                onChange={e => setFormData({ ...formData, id: e.target.value.trim() })}
