                        >
                            {loading ? <Loader className="animate-spin" size={20} /> : <>Initialize Node <ArrowRight size={18} /></>}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthProvider';
import TypeSelection from './TypeSelection';
import SearchStep from './SearchStep';
import FormStep from './FormStep';
import { ArrowLeft } from 'lucide-react';

export default function ProtocolWizard() {
    const navigate = useNavigate();
    const { user } = useAuth();
    const activeContract = user?.activeContract;
    const [step, setStep] = useState(1);
    const [protocolType, setProtocolType] = useState(null);
    const [selectedData, setSelectedData] = useState(null);

    const handleTypeSelect = (type) => {
        setProtocolType(type);
        setStep(2);
    };

    const handleSearchSelect = (data) => {
        setSelectedData(data);
        setStep(3);
    };

    const handleBack = () => {
        if (step === 1) navigate('/');
        else if (step === 2) setStep(1);
        else if (step === 3) setStep(2);
    };

    return (
        <div className="h-full flex flex-col gap-3 animate-in fade-in duration-300">
            {/* Header compacto */}
            <div className="flex items-center gap-4 shrink-0">
                <button 
                    onClick={handleBack} 
                    className="p-2 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-all text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white"
                >
                    <ArrowLeft className="h-5 w-5" />
                </button>
                <div className="flex-1 flex items-center gap-4">
                    <h1 className="text-xl font-bold text-slate-900 dark:text-white tracking-tight">Novo Protocolo</h1>
                    <div className="flex items-center gap-3">
                        <div className="flex gap-1">
                            {[1, 2, 3].map(i => (
                                <div 
                                    key={i} 
                                    className={`h-1 w-6 rounded-full transition-all duration-500 ${step >= i ? 'bg-primary' : 'bg-slate-200 dark:bg-slate-700'}`} 
                                />
                            ))}
                        </div>
                        <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Estágio {step} de 3 — {
                            step === 1 ? 'Tipo' :
                            step === 2 ? 'Equipamento' :
                            'Detalhes'
                        }</p>
                    </div>
                </div>
            </div>

            {/* Conteúdo — ocupa todo o espaço restante */}
            <div className="flex-1 min-h-0 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-sm overflow-hidden">
                <div className={`h-full p-3 flex flex-col ${step !== 3 ? 'overflow-y-auto custom-scrollbar' : 'overflow-hidden'}`}>
                    {step === 1 && <TypeSelection onSelect={handleTypeSelect} />}
                    {step === 2 && <SearchStep onSelect={handleSearchSelect} activeContract={activeContract} />}
                    {step === 3 && <FormStep data={selectedData} type={protocolType} activeContract={activeContract} />}
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { useToast } from '../../context/ToastContext';
import { Search, Loader, AlertCircle, ArrowRight, CheckCircle, Clock } from 'lucide-react';
import Pagination from '../Shared/Pagination';
import { usePagination } from '../../hooks/usePagination';
import api from '../../lib/api';

// ─── Estilos reutilizáveis (mesmos do FormStep) ───────────────────────────────
const inp = "w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-900 dark:text-white placeholder-slate-400 focus:border-primary focus:ring-1 focus:ring-primary/20 outline-none transition-all";
const lbl = "block text-[9px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-0.5";

const STATUS_STYLES = {
    'Em Produção': 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-400 border-emerald-100 dark:border-emerald-800',
    'default':     'bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-slate-700',
};

export default function SearchStep({ onSelect, activeContract }) {
    const { addToast } = useToast();
    const [query, setQuery] = useState('');
    const [loading, setLoading] = useState(false);
    const [loadingDetails, setLoadingDetails] = useState(null);
    const [results, setResults] = useState([]);
    const [error, setError] = useState(null);
    const [hasSearched, setHasSearched] = useState(false);
    const inputRef = useRef(null);

    const { currentData: currentResults, paginationProps } = usePagination(results, 8);

    useEffect(() => {
        inputRef.current?.focus();
    }, []);

    const handleSearch = async (e) => {
        e?.preventDefault();
        if (query.trim().length < 4) {
            setError('Digite pelo menos 4 caracteres para buscar.');
            return;
        }
        setLoading(true);
        setError(null);
        setResults([]);
        setHasSearched(false);
        try {
            const res = await api.get(`/data/assist/search?q=${encodeURIComponent(query)}&contract_id=${activeContract}`);
            setResults(res.data?.results || []);
            setHasSearched(true);
        } catch {
            setError('Erro ao buscar. Tente novamente.');
        } finally {
            setLoading(false);
        }
    };

    const handleSelectMachine = async (serie) => {
        setLoadingDetails(serie);
        try {
            const res = await api.get(`/data/assist/equipment/${encodeURIComponent(serie)}?contract_id=${activeContract}`);
            if (res.data?.equipment) {
                onSelect(res.data);
            } else {
                addToast('Erro ao carregar detalhes do equipamento.', 'error');
            }
        } catch {
            addToast('Erro de conexão ao carregar detalhes.', 'error');
        } finally {
            setLoadingDetails(null);
        }
    };

    const canSearch = query.trim().length >= 4;

    return (
        <div className="h-full flex flex-col gap-3 animate-in fade-in duration-300">

            {/* ── Cabeçalho compacto ── */}
            <div className="shrink-0">
                <h2 className="text-base font-bold text-slate-800 dark:text-white tracking-tight">Buscar Equipamento</h2>
                <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">Digite a Fila (Hostname) ou Número de Série</p>
            </div>

            {/* ── Campo de busca ── */}
            <form onSubmit={handleSearch} className="flex gap-2 shrink-0">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none" />
                    <input
                        ref={inputRef}
                        type="text"
                        value={query}
                        onChange={(e) => { setQuery(e.target.value); if (error) setError(null); }}
                        onKeyDown={(e) => e.key === 'Enter' && canSearch && handleSearch(e)}
                        placeholder="Ex: URIPA0123 ou número de série..."
                        className={inp + " pl-9"}
                    />
                </div>
                <button
                    type="submit"
                    disabled={loading || !canSearch}
                    style={canSearch ? { backgroundColor: 'rgb(var(--color-primary))', color: 'white' } : {}}
                    className={`flex items-center gap-2 px-5 py-2 rounded-lg text-xs font-bold transition-all shrink-0 ${
                        canSearch
                            ? 'hover:opacity-90 active:scale-95 shadow-sm'
                            : 'bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-500 cursor-not-allowed'
                    }`}
                >
                    {loading ? <Loader className="h-4 w-4 animate-spin" /> : <Search className="h-4 w-4" />}
                    {loading ? 'Buscando...' : 'Buscar'}
                </button>
            </form>

            {/* ── Hint ── */}
            {!hasSearched && !error && (
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center shrink-0">
                    Mínimo de 4 caracteres para iniciar a busca.
                </p>
            )}

            {/* ── Erro ── */}
            {error && (
                <div className="flex items-center gap-2 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg px-3 py-2 shrink-0">
                    <AlertCircle className="h-4 w-4 text-red-500 shrink-0" />
                    <span className="text-xs font-bold text-red-600 dark:text-red-400">{error}</span>
                </div>
            )}

            {/* ── Sem resultados ── */}
            {hasSearched && results.length === 0 && !error && (
                <div className="flex-1 flex items-center justify-center">
                    <div className="text-center py-10 px-6 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-dashed border-slate-200 dark:border-slate-700 w-full max-w-md">
                        <Search className="h-8 w-8 text-slate-300 dark:text-slate-600 mx-auto mb-2" />
                        <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Nenhum equipamento encontrado.</p>
                        <p className="text-[10px] text-slate-400 mt-1">Tente outro termo de busca.</p>
                    </div>
                </div>
            )}

            {/* ── Resultados ── */}
            {results.length > 0 && (
                <div className="flex-1 min-h-0 flex flex-col bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-sm overflow-hidden">
                    {/* Header da tabela */}
                    <div className="flex items-center justify-between px-4 py-2 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700 shrink-0">
                        <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                            {results.length} resultado{results.length !== 1 ? 's' : ''} encontrado{results.length !== 1 ? 's' : ''}
                        </span>
                        {results.length > 8 && (
                            <span className="text-[10px] text-slate-400">Página {paginationProps.currentPage} de {paginationProps.totalPages}</span>
                        )}
                    </div>

                    {/* Tabela */}
                    <div className="flex-1 overflow-y-auto custom-scrollbar">
                        <table className="w-full text-left">
                            <thead className="sticky top-0 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 z-10">
                                <tr>
                                    {['Fila / Modelo', 'Série', 'Status', 'Ação'].map((h, i) => (
                                        <th key={h} className={`px-4 py-2 text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ${i === 3 ? 'text-right' : ''}`}>{h}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                                {currentResults.map((item, idx) => (
                                    <tr key={idx} className="hover:bg-slate-50 dark:hover:bg-slate-800/40 transition-colors group">
                                        <td className="px-4 py-3">
                                            <div className="font-bold text-sm text-slate-900 dark:text-white group-hover:text-primary transition-colors">{item.Fila}</div>
                                            <div className="text-[10px] text-slate-400 dark:text-slate-500 font-medium mt-0.5">{item.Modelo}</div>
                                        </td>
                                        <td className="px-4 py-3 font-mono text-xs text-slate-500 dark:text-slate-400 tracking-wider">{item.Serie}</td>
                                        <td className="px-4 py-3">
                                            <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-bold border ${STATUS_STYLES[item.Status] || STATUS_STYLES.default}`}>
                                                {item.Status === 'Em Produção'
                                                    ? <CheckCircle className="h-3 w-3" />
                                                    : <Clock className="h-3 w-3" />
                                                }
                                                {item.Status}
                                            </span>
                                        </td>
                                        <td className="px-4 py-3 text-right">
                                            <button
                                                onClick={() => handleSelectMachine(item.Serie)}
                                                disabled={!!loadingDetails}
                                                style={{ backgroundColor: 'rgb(var(--color-primary))', color: 'white' }}
                                                className="inline-flex items-center gap-1.5 px-4 py-1.5 rounded-lg text-xs font-bold transition-all hover:opacity-90 active:scale-95 disabled:opacity-50 shadow-sm"
                                            >
                                                {loadingDetails === item.Serie
                                                    ? <Loader className="h-3.5 w-3.5 animate-spin" />
                                                    : <>Selecionar <ArrowRight className="h-3.5 w-3.5" /></>
                                                }
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>

                    {/* Paginação — só aparece se necessário */}
                    {results.length > 8 && (
                        <div className="shrink-0 border-t border-slate-100 dark:border-slate-800 px-4 py-2">
                            <Pagination {...paginationProps} />
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import api from '../../lib/api';
import { Loader2, User } from 'lucide-react';

/**
 * SolicitanteInput — autocomplete input for requester names.
 * Fetches suggestions from /data/solicitantes?q=...
 * Calls onSelect({ Nome, Ramal }) when a suggestion is picked.
 */
export default function SolicitanteInput({ value, onChange, onSelect, name, className }) {
    const [suggestions, setSuggestions] = useState([]);
    const [showSuggestions, setShowSuggestions] = useState(false);
    const [loading, setLoading] = useState(false);
    const wrapperRef = useRef(null);
    const timeoutRef = useRef(null);

    // Close on outside click
    useEffect(() => {
        const handler = (e) => {
            if (wrapperRef.current && !wrapperRef.current.contains(e.target)) {
                setShowSuggestions(false);
            }
        };
        document.addEventListener('mousedown', handler);
        return () => document.removeEventListener('mousedown', handler);
    }, []);

    const fetchSuggestions = async (query) => {
        if (!query || query.length < 2) {
            setSuggestions([]);
            setShowSuggestions(false);
            return;
        }
        try {
            setLoading(true);
            // Correct endpoint: /data/solicitantes
            const res = await api.get(`/data/solicitantes?q=${encodeURIComponent(query)}`);
            const data = Array.isArray(res.data) ? res.data : [];
            setSuggestions(data);
            setShowSuggestions(data.length > 0);
        } catch {
            // Silent — autocomplete is non-critical
        } finally {
            setLoading(false);
        }
    };

    const handleInputChange = (e) => {
        onChange(e);
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
        timeoutRef.current = setTimeout(() => fetchSuggestions(e.target.value), 300);
    };

    const handleSelect = (item) => {
        const s = typeof item === 'string' ? { Nome: item, Ramal: '' } : item;
        if (onSelect) {
            onSelect(s);
        } else {
            onChange({ target: { name, value: s.Nome } });
        }
        setShowSuggestions(false);
        setSuggestions([]);
    };

    const defaultInputClass = "w-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2.5 text-sm text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 focus:border-primary focus:ring-2 focus:ring-primary/20 outline-none transition-all";

    return (
        <div className="relative" ref={wrapperRef}>
            <div className="relative">
                <input
                    name={name}
                    value={value}
                    onChange={handleInputChange}
                    onFocus={() => { if (value && value.length >= 2) fetchSuggestions(value); }}
                    autoComplete="off"
                    placeholder="Nome do solicitante..."
                    className={className || defaultInputClass}
                />
                {loading && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2">
                        <Loader2 className="h-4 w-4 animate-spin text-primary" />
                    </div>
                )}
            </div>

            {showSuggestions && suggestions.length > 0 && (
                <div className="absolute z-[200] w-full mt-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-xl overflow-hidden animate-in fade-in slide-in-from-top-1 duration-150">
                    <div className="px-3 py-2 bg-slate-50 dark:bg-slate-900 border-b border-slate-100 dark:border-slate-700">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Solicitantes cadastrados</span>
                    </div>
                    <div className="max-h-52 overflow-y-auto custom-scrollbar">
                        {suggestions.map((s, i) => (
                            <button
                                key={i}
                                type="button"
                                onClick={() => handleSelect(s)}
                                className="w-full text-left px-4 py-3 hover:bg-primary/5 dark:hover:bg-primary/10 transition-colors border-b border-slate-50 dark:border-slate-700/50 last:border-0 flex items-center justify-between gap-3"
                            >
                                <div className="flex items-center gap-2 min-w-0">
                                    <User className="w-3.5 h-3.5 text-slate-400 shrink-0" />
                                    <div className="min-w-0">
                                        <span className="text-sm font-medium text-slate-900 dark:text-white truncate block">
                                            {s.Solicitante || s.Nome}
                                        </span>
                                        {s.Area && (
                                            <span className="text-[10px] text-slate-400 truncate block">{s.Area}</span>
                                        )}
                                    </div>
                                </div>
                                {(s.Ramal) && (
                                    <span className="text-[10px] font-mono text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-700 px-2 py-0.5 rounded shrink-0">
                                        {s.Ramal}
                                    </span>
                                )}
                            </button>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

import React from 'react';
import { Phone, Route, AlertTriangle, FileText } from 'lucide-react';
import { cn } from '../../lib/utils';

export default function TypeSelection({ onSelect }) {
    const options = [
        { id: 'Telefone', label: 'Solicitação via Telefone', icon: Phone, color: 'text-[#4D91FF]', bg: 'bg-[#4D91FF]/10', border: 'border-[#4D91FF]/20', desc: 'Atendimento via ramal ou celular' },
        { id: 'Rota', label: 'Rota Proativa', icon: Route, color: 'text-[#4DFF88]', bg: 'bg-[#4DFF88]/10', border: 'border-[#4DFF88]/20', desc: 'Identificação por visita periódica' },
        { id: 'Incidente', label: 'Incidente', icon: AlertTriangle, color: 'text-[#FF4D4D]', bg: 'bg-[#FF4D4D]/10', border: 'border-[#FF4D4D]/20', desc: 'Correção de falha documentada' },
        { id: 'Requisicao', label: 'Requisição Interna', icon: FileText, color: 'text-[#D18BFF]', bg: 'bg-[#D18BFF]/10', border: 'border-[#D18BFF]/20', desc: 'Demanda de uso do próprio setor' },
    ];

    return (
        <div className="space-y-12 animate-in fade-in zoom-in duration-500">
            <div className="text-center space-y-4">
                <h2 className="text-3xl font-bold text-slate-900 dark:text-white font-display uppercase tracking-widest">Selecione o Tipo de Pedido</h2>
                <p className="text-slate-500 font-medium">Defina a origem da solicitação</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {options.map((opt) => {
                    const Icon = opt.icon;
                    return (
                        <button
                            key={opt.id}
                            onClick={() => onSelect(opt.id)}
                            className={cn(
                                "flex items-start gap-6 p-8 rounded-2xl border bg-slate-50/50 dark:bg-white/[0.02] border-slate-200 dark:border-white/10 transition-all text-left relative overflow-hidden group hover:bg-slate-100/50 dark:hover:bg-white/[0.05] hover:scale-[1.02] active:scale-[0.98]",
                                opt.border
                            )}
                        >
                             <div className="absolute top-0 right-0 w-32 h-32 bg-slate-900/[0.02] dark:bg-white/[0.02] blur-3xl -mr-16 -mt-16 rounded-full group-hover:bg-slate-900/[0.05] dark:group-hover:bg-white/[0.05] transition-all" />
                            <div className={cn("p-5 rounded-2xl transition-all border group-hover:shadow-[0_0_20px_rgba(255,255,255,0.1)]", opt.bg, opt.border)}>
                                <Icon className={cn("h-8 w-8", opt.color)} />
                            </div>
                            <div className="relative z-10 flex-1">
                                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2 font-display">{opt.label}</h3>
                                <p className="text-sm text-slate-500 font-medium leading-relaxed">{opt.desc}</p>
                            </div>
                        </button>
                    )
                })}
            </div>
        </div>
    );
}

